// Marker data extracted from AdminPortal.jsx
export const RISK_LEVELS = ["Low", "Medium", "High"];
export const makeMarker = (name, gene, risk, species, significance, description) => ({ name, gene, risk, species, significance, description });
export const MARKER_CATEGORIES = [
  { id: "behaviour", name: "Behaviour", color: "#F59E0B", markers: [
    makeMarker("Arginine Vasopressin Receptor 1A", "AVPR1A (VT3R)", "Medium", "Homo sapiens, Microtus ochrogaster, Canis lupus familiaris, Mus musculus, Gallus gallus, Danio rerio, Rattus norvegicus", "AVPR1A variants alter vasopressin V1a receptor expression, modifying pair-bonding strength, social attachment stability, and territorial aggression thresholds. Behavioral temperament assessment and considerate pairing selection are recommended in breeding programs to mitigate aggression or attachment disorders.", "Encodes the vasopressin V1a receptor, a GPCR mediating the central effects of vasopressin/vasotocin on social behavior, pair bonding, aggression, and stress responses."),
    makeMarker("Dopamine Receptor D1", "DRD1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "DRD1 polymorphisms affect dopamine D1 receptor density in the striatum and prefrontal cortex, influencing reward-driven motivation, trainability, and activity levels. Environmental enrichment and behavioral assessment are recommended for individuals with low-activity alleles; may affect response to dopaminergic medications.", "Encodes the dopamine D1 receptor, the most abundant dopamine receptor in the brain. A stimulatory GPCR that activates adenylyl cyclase and mediates reward, motivation, and motor behavior."),
    makeMarker("Dopamine Receptor D2", "DRD2", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Gallus gallus, Danio rerio", "DRD2 variants modify inhibitory dopaminergic autoreceptor function, predisposing to impulsive behaviors, compulsive repetitive actions, or reduced reward motivation. Structured behavioral management and veterinary behavioral consultation are advised; relevant to analgesic and antipsychotic drug selection.", "Encodes the dopamine D2 receptor, an inhibitory GPCR that reduces cAMP production. Exists as long (D2L) and short (D2S) splice variants with distinct functions in postsynaptic signaling and autorecept"),
    makeMarker("General Transcription Factor IIi", "GTF2I", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "GTF2I mutations in the Williams-Beuren syndrome critical region are linked to hypersociability, reduced fear responses, and impaired selective social discrimination. Behavioral profiling for sociability and fear responses is recommended; relevant to selective breeding programs targeting temperament traits in dogs.", "Encodes a multifunctional transcription factor involved in signal-induced gene expression. Located in the Williams-Beuren syndrome critical region."),
    makeMarker("GTF2I Repeat Domain Containing 1", "GTF2IRD1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "GTF2IRD1 variants in the Williams-Beuren critical region influence craniofacial morphology and behavioral regulation, contributing to altered social behavior and reduced wariness. Co-evaluate with other WBSCR loci; behavioral assessment for sociability, fear thresholds, and facial morphology is advised.", "Encodes a transcription factor in the Williams-Beuren syndrome critical region that regulates craniofacial and muscular development and behavioral traits."),
    makeMarker("5-Hydroxytryptamine Receptor 1A", "HTR1A", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "HTR1A variants reduce inhibitory serotonergic autoreceptor tone, increasing vulnerability to anxiety disorders, fearfulness, and stress-induced aggression. Behavioral stress assessment is recommended; affected animals may require serotonin-modulating management strategies and may show altered SSRI responsiveness.", "Encodes the serotonin 5-HT1A receptor, an inhibitory G protein-coupled receptor in the brain that modulates anxiety, mood, and behavioral responses."),
    makeMarker("5-Hydroxytryptamine Receptor 1B", "HTR1B", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "HTR1B variants affect presynaptic serotonin autoreceptor inhibition of serotonin release, predisposing to elevated impulsivity and interspecific or intraspecific aggression. Carrier animals may require structured socialization protocols, behavioral monitoring, and careful drug selection when serotonergic agents are used.", "Encodes the serotonin 5-HT1B receptor, a presynaptic autoreceptor that inhibits serotonin release and modulates aggression and impulsivity."),
    makeMarker("5-Hydroxytryptamine Receptor 2A", "HTR2A", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "HTR2A variants alter excitatory serotonin Gq-coupled signaling, linked to heightened sensory sensitivity, aggression, and altered mood states. Behavioral assessment and careful environmental management are recommended; relevant to atypical drug responses when 5-HT2A-active compounds are prescribed.", "Encodes the serotonin 5-HT2A receptor, a Gq-coupled receptor mediating excitatory serotonergic signaling involved in mood, cognition, and perception."),
    makeMarker("Monoamine Oxidase B", "MAOB", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "MAOB variants affect oxidative metabolism of dopamine and phenylethylamine, influencing dopaminergic tone in the basal ganglia. Neurological and behavioral phenotypes should be assessed; monitoring during aging is advisable as MAOB activity increases with age, affecting monoaminergic balance.", "Encodes monoamine oxidase B, a mitochondrial enzyme that catalyzes the oxidative deamination of biogenic and xenobiotic amines including dopamine and phenylethylamine."),
    makeMarker("Neuropeptide Y", "NPY", "Medium", "Homo sapiens, Mus musculus, Gallus gallus, Sus scrofa, Bos taurus, Danio rerio, Rattus norvegicus", "NPY variants alter orexigenic neuropeptide Y signaling, affecting stress resilience, anxiety thresholds, appetite regulation, and cardiovascular tone. Nutritional management and behavioral monitoring are recommended; affected animals may show exaggerated or attenuated stress-related feeding responses.", "A 36-amino acid neuropeptide widely distributed in the central and peripheral nervous system, regulating appetite, stress response, and anxiety. It is one of the most potent orexigenic factors in the "),
    makeMarker("Oxytocin/Neurophysin I Prepropeptide", "OXT", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Bos taurus, Ovis aries, Danio rerio, Rattus norvegicus", "OXT variants affect oxytocin neuropeptide levels, influencing maternal behavior quality, social bonding strength, parturition signaling, and lactation. Breeding animals should be monitored for dystocia risk and maternal behavior deficits; neonatal bonding evaluation is recommended in affected dams.", "Encodes the precursor of oxytocin, a neuropeptide hormone critical for social bonding, parturition, lactation, and maternal behavior. Also functions as a neurotransmitter modulating trust and social c"),
    makeMarker("Oxytocin Receptor (Mesotocin Receptor in Birds)", "OXTR (Mesotocin receptor)", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Gallus gallus, Taeniopygia guttata, Danio rerio, Rattus norvegicus", "OXTR variants reduce oxytocin receptor-mediated social signaling, impairing pair-bond formation, neonatal attachment, and social recognition. Maternal-offspring bonding and parturition should be closely monitored in carrier breeding pairs; behavioral enrichment supporting social bonding is advisable.", "Encodes the receptor for oxytocin (or mesotocin in birds), a G protein-coupled receptor mediating the behavioral and physiological effects of oxytocin signaling including pair bonding and social recog"),
    makeMarker("Serotonin Transporter (Solute Carrier Family 6 Member 4)", "SERT (SLC6A4)", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Macaca mulatta, Danio rerio, Rattus norvegicus", "SERT variants alter serotonin reuptake efficiency and synaptic serotonergic tone, underpinning anxiety, aggression, and stress responsiveness phenotypes. Behavioral temperament evaluation is advised; genotype may predict response to SSRIs — carriers with reduced-function alleles often show altered SSRI efficacy.", "Encodes the serotonin transporter that mediates reuptake of serotonin from the synaptic cleft into presynaptic neurons. Primary target of SSRI antidepressants and central to serotonergic neurotransmis"),
    makeMarker("Solute Carrier Family 6 Member 3 (Dopamine Transporter, DAT)", "SLC6A3", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "SLC6A3 variants alter dopamine transporter function and striatal dopamine clearance rate, affecting attention, hyperactivity, and impulse control phenotypes. Behavioral assessment for ADHD-like traits is recommended; genotype is relevant to managing psychostimulant responses in working and sport animals.", "Encodes the dopamine transporter responsible for reuptake of dopamine from the synaptic cleft. Key regulator of dopaminergic neurotransmission and target of psychostimulants."),
    makeMarker("Tryptophan Hydroxylase 2", "TPH2", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "TPH2 variants reduce central serotonin biosynthesis capacity in the brain, predisposing to anxiety, depression-like states, and reactive aggression. Behavioral monitoring and serotonin-supporting nutritional strategies (tryptophan enrichment) are recommended; relevant to pharmacological management plans.", "Encodes the brain-specific isoform of tryptophan hydroxylase, the rate-limiting enzyme in serotonin biosynthesis in the central nervous system. Distinct from TPH1 which functions in peripheral tissues"),
    makeMarker("Williams-Beuren Syndrome Chromosome Region 17 (GALNT17)", "WBSCR17", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "WBSCR17 variants in the Williams-Beuren critical region affect O-linked glycosylation of proteins, with pleiotropic effects on neurological development and social cognition. Co-evaluate with other WBSCR loci; behavioral assessment for sociability, fear responses, and hypersociability traits is advised.", "Encodes a polypeptide N-acetylgalactosaminyltransferase (GALNT17) located in the Williams-Beuren syndrome critical region. Involved in O-linked glycosylation of proteins."),
    makeMarker("Forkhead Box Protein P2", "FOXP2", "Medium", "Homo sapiens, Taeniopygia guttata (Zebra Finch), Mus musculus, Rattus norvegicus, Xenopus laevis, Xenopus tropicalis, Caenorhabditis elegans, Danio rerio, Drosophila melanogaster", "FOXP2 variants impair synaptic plasticity in vocal learning and motor learning circuits, affecting communication, vocalization patterns, and procedural learning capacity. Vocalization quality and social communication behaviors should be assessed; most relevant for songbirds, parrots, and speech-producing species.", "Transcription factor critical for speech and language development; regulates synaptic plasticity and motor learning circuits"),
    makeMarker("Monoamine Oxidase A", "MAOA", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Saccharomyces cerevisiae, Xenopus laevis, Xenopus tropicalis, Caenorhabditis elegans, Danio rerio, Drosophila melanogaster", "MAOA variants alter oxidative catabolism of serotonin, norepinephrine, and dopamine, directly influencing aggression thresholds and reactivity to social stressors. Behavioral evaluation in competitive or high-stress environments is recommended; MAOA genotype may predict response to MAO inhibitor medications.", "Mitochondrial enzyme that degrades serotonin, norepinephrine, and dopamine; key regulator of monoaminergic neurotransmission"),
    makeMarker("Solute Carrier Family 6 Member 4 (Serotonin Transporter)", "SLC6A4", "Medium", "Homo sapiens, Macaca mulatta (Rhesus Macaque), Mus musculus, Rattus norvegicus, Xenopus laevis, Danio rerio, Xenopus tropicalis, Caenorhabditis elegans, Drosophila melanogaster", "SLC6A4 promoter region variation affects serotonin transporter expression levels, contributing to anxiety-related traits, social behavior differences, and vulnerability to environmental stressors. Behavioral profiling under standard and novel environments is recommended; relevant to SSRI pharmacogenomics.", "Serotonin reuptake transporter (5-HTT/SERT); primary mechanism for clearing serotonin from the synaptic cleft"),
    makeMarker("Dopamine Receptor D4", "DRD4", "Medium", "Homo sapiens, Parus major (Great Tit), Mus musculus, Rattus norvegicus, Xenopus tropicalis, Danio rerio, Xenopus laevis, Caenorhabditis elegans, Drosophila melanogaster", "DRD4 repeat variants modulate dopamine receptor sensitivity in attention and novelty-seeking circuits. Animals with high-repeat alleles may show elevated exploratory behavior, reduced fear habituation, or reduced inhibition; targeted environmental enrichment and structured habituation training are recommended.", "G protein-coupled receptor for dopamine; modulates attention, reward processing, and exploratory behaviour"),
    makeMarker("5-Hydroxytryptamine Receptor 2C", "HTR2C", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio, Xenopus tropicalis, Xenopus laevis, Caenorhabditis elegans, Drosophila melanogaster", "HTR2C variants affect serotonin-mediated appetite inhibition and impulse control pathways, predisposing to overeating, compulsive behaviors, or elevated anxiety. Dietary management, behavioral enrichment, and body condition monitoring are recommended for carrier animals.", "Serotonin receptor subtype involved in appetite regulation, anxiety, and impulsive behaviour"),
    makeMarker("Early Growth Response 1", "ZENK/EGR1", "Medium", "Taeniopygia guttata (Zebra Finch), Serinus canaria (Canary), Mus musculus, Rattus norvegicus, Xenopus tropicalis, Xenopus laevis, Drosophila melanogaster, Homo sapiens, Caenorhabditis elegans, Danio rerio", "EGR1 (ZENK) variants affect activity-dependent transcriptional responses in auditory and song-learning circuits. In songbirds, monitoring song learning progression and neural activity markers is recommended; in mammals, assess for cognitive and stress-related behavioral anomalies in carrier offspring.", "Immediate early gene (transcription factor) rapidly induced by neural activity; marker of song-driven neuronal activation in songbirds"),
    makeMarker("Adenylate Cyclase Activating Polypeptide 1 (PACAP)", "ADCYAP1", "Medium", "Sylvia atricapilla (Eurasian Blackcap), Junco hyemalis (Dark-eyed Junco), Danio rerio, Xenopus laevis, Homo sapiens, Mus musculus, Rattus norvegicus, Xenopus tropicalis, Caenorhabditis elegans", "ADCYAP1 variants alter PACAP neuropeptide signaling in stress response and migratory behavior regulation. In migratory avian species, phenotypic variation in migratory restlessness (Zugunruhe) may be linked to ADCYAP1 alleles; monitor for stress response dysregulation in managed populations.", "Neuropeptide involved in stress response, neural development, and migratory restlessness (Zugunruhe) in birds"),
    makeMarker("Vestigial Like Family Member 3", "VGLL3", "Medium", "Salmo salar (Atlantic Salmon), Xenopus laevis, Danio rerio, Drosophila melanogaster, Homo sapiens, Mus musculus, Rattus norvegicus, Xenopus tropicalis", "VGLL3 acts as a large-effect locus controlling age at sexual maturity in Atlantic salmon. In salmon breeding programs, VGLL3 genotyping is recommended to select for optimal maturation timing, balancing early ocean returns with growth and survival; relevant to aquaculture production planning.", "Transcription co-factor influencing age at maturity in Atlantic salmon; large-effect locus for life history strategy (early vs. late maturity)"),
    makeMarker("Tyrosinase Related Protein 1", "TYRP1", "Medium", "Columba livia (Rock Pigeon), Ovis aries (Sheep), Mus musculus, Rattus norvegicus, Xenopus tropicalis, Caenorhabditis elegans, Danio rerio, Xenopus laevis, Homo sapiens", "TYRP1 pleiotropic variants affect both melanin biosynthesis and behavioral traits in birds and other species. Co-evaluation of plumage/coat phenotype and behavioral temperament is recommended, particularly in species where pigmentation correlates with social dominance or stress reactivity.", "Melanin biosynthesis enzyme also functioning as a pleiotropic gene affecting plumage color and behavioral traits in birds"),
  ]},
  { id: "cancer", name: "Cancer / Cell Cycle", color: "#EF4444", markers: [
    makeMarker("B-Raf Proto-Oncogene, Serine/Threonine Kinase", "BRAF", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Felis catus, Danio rerio, Rattus norvegicus", "BRAF gain-of-function variants constitutively activate the RAS-MAPK proliferative signaling cascade, conferring elevated risk of histiocytic sarcoma, mast cell tumors, and melanoma. Annual oncology screening including full blood count, lymph node palpation, and abdominal imaging is strongly recommended from middle age; targeted BRAF inhibitor therapy is available for confirmed mutations.", "Encodes a serine/threonine kinase in the RAS-MAPK signaling pathway that transduces growth signals from cell surface receptors to the nucleus. A key oncogene in multiple cancer types."),
    makeMarker("BRCA2 DNA Repair Associated", "BRCA2", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Felis catus, Gallus gallus, Danio rerio, Rattus norvegicus", "Pathogenic BRCA2 variants severely compromise homologous recombination DNA repair, conferring markedly elevated lifetime risk of mammary, ovarian, and prostate neoplasia. Annual mammary and reproductive organ examination, including ultrasound imaging, is indicated from 4–5 years of age; reproductive organ removal (ovariohysterectomy, orchiectomy) may be recommended.", "Encodes a key protein in homologous recombination DNA repair that interacts with RAD51 to facilitate repair of double-strand breaks. A critical tumor suppressor whose loss leads to genomic instability"),
    makeMarker("F-Box And WD Repeat Domain Containing 7", "FBXW7", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Caenorhabditis elegans, Danio rerio, Drosophila melanogaster, Rattus norvegicus", "FBXW7 loss-of-function variants impair ubiquitin-mediated degradation of oncoproteins cyclin E, c-Myc, Notch, and mTOR, predisposing to lymphoma and carcinoma development. Annual lymph node assessment and complete blood count monitoring are recommended; notify oncologist if progressive lymphadenopathy is detected.", "Encodes a substrate recognition component of the SCF ubiquitin ligase complex that targets oncoproteins like cyclin E, c-Myc, Notch, and mTOR for proteasomal degradation."),
    makeMarker("MutY DNA Glycosylase", "MUTYH", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "Biallelic MUTYH variants cause MUTYH-Associated Polyposis through accumulation of oxidative G:C→T:A transversion mutations, significantly elevating colorectal and intestinal tumor risk. Regular gastrointestinal surveillance is recommended; heterozygous carriers have modestly elevated risk and should undergo periodic intestinal examination.", "Encodes a base excision repair enzyme that removes adenine mispaired with 8-oxoguanine, preventing G:C to T:A transversion mutations caused by oxidative DNA damage."),
    makeMarker("Platelet Derived Growth Factor Receptor Alpha", "PDGFRA", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Felis catus, Danio rerio, Rattus norvegicus", "Activating PDGFRA mutations drive gastrointestinal stromal tumors (GISTs) and mast cell neoplasias. Annual gastrointestinal examination and abdominal ultrasound are recommended; PDGFRA genotype directly informs tyrosine kinase inhibitor therapy selection (imatinib vs. other agents).", "Encodes a receptor tyrosine kinase that binds PDGF ligands and activates signaling cascades controlling cell proliferation, differentiation, and survival. Important in mesenchymal cell development."),
    makeMarker("Phosphatase and Tensin Homolog", "PTEN", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "PTEN loss-of-function variants deregulate PI3K/AKT survival signaling, conferring elevated risk of mammary tumors, thyroid carcinoma, and Cowden-equivalent syndromes. Annual reproductive organ, mammary, and thyroid assessment are recommended from 4 years of age; PI3K pathway-targeted therapies are increasingly available.", "Encodes a dual-specificity phosphatase that antagonizes PI3K/AKT signaling, functioning as a major tumor suppressor. Regulates cell growth, survival, and genomic stability."),
    makeMarker("Ribosomal Protein S15a", "RPS15A", "High", "Homo sapiens, Mus musculus, Caenorhabditis elegans, Danio rerio, Drosophila melanogaster, Rattus norvegicus, Saccharomyces cerevisiae", "RPS15A overexpression promotes ribosome biogenesis and cell proliferative capacity, with links to tumor progression across tissue types. Annual hematological screening (CBC, differential) and lymph node palpation are recommended; relevant in individuals with familial cancer history.", "Encodes a component of the 40S ribosomal subunit involved in translation initiation. Overexpression has been linked to cell proliferation and tumor progression."),
    makeMarker("THO Complex 1", "THOC1", "High", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "THOC1 variants compromise mRNA nuclear export efficiency and genome stability, disrupting tumor suppressor gene expression. Annual oncology assessment including complete blood count and abdominal imaging is recommended; early detection of evolving cytopenias or masses is important.", "Encodes a component of the THO/TREX complex involved in mRNA export from the nucleus to the cytoplasm. Also functions in transcription elongation and genome stability."),
    makeMarker("Tumor Protein P53", "TP53", "High", "Homo sapiens, Xenopus laevis, Xenopus tropicalis, Rattus norvegicus, Mus musculus, Danio rerio, Drosophila melanogaster, Caenorhabditis elegans, Saccharomyces cerevisiae", "TP53 mutations remove the master checkpoint controlling DNA damage responses, cell cycle arrest, and apoptosis, markedly increasing risk of diverse tumor types. Comprehensive annual oncology screening — CBC, biochemistry panel, thoracic and abdominal imaging — is strongly recommended; TP53 status critically informs chemotherapy protocol selection.", "Transcription factor and tumor suppressor ('guardian of the genome'); regulates cell cycle arrest, apoptosis, and DNA repair in response to genotoxic stress"),
    makeMarker("BRCA1 DNA Repair Associated", "BRCA1", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Xenopus laevis, Xenopus tropicalis, Danio rerio, Caenorhabditis elegans, Saccharomyces cerevisiae", "Pathogenic BRCA1 variants disable homologous recombination repair, producing high lifetime risk of mammary and ovarian neoplasias. Annual mammary palpation, abdominal ultrasound, and reproductive organ examination are recommended from 4 years of age; prophylactic ovariohysterectomy is considered in high-risk breeding animals.", "E3 ubiquitin ligase involved in homologous recombination DNA repair; maintains genomic stability and functions as a tumor suppressor"),
    makeMarker("MYC Proto-Oncogene, bHLH Transcription Factor", "MYC", "High", "Homo sapiens, Gallus gallus (Chicken, viral origin), Mus musculus, Rattus norvegicus, Danio rerio, Drosophila melanogaster, Xenopus tropicalis, Xenopus laevis, Caenorhabditis elegans", "MYC amplification or translocation events drive highly aggressive lymphomas and solid tumors through global transcriptional dysregulation of proliferative and metabolic programs. Prompt lymph node evaluation, complete blood count, and thoracic imaging are recommended at any sign of lymphadenopathy or unexplained weight loss.", "Transcription factor regulating cell proliferation, growth, apoptosis, and metabolism; one of the most frequently deregulated oncogenes"),
    makeMarker("RB Transcriptional Corepressor 1", "RB1", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Xenopus tropicalis, Drosophila melanogaster, Xenopus laevis, Caenorhabditis elegans, Danio rerio", "RB1 loss-of-function variants remove the G1/S cell cycle checkpoint, predisposing to osteosarcoma, retinoblastoma, and soft tissue sarcomas. Annual ophthalmic examination and musculoskeletal assessment are recommended; early detection substantially improves prognosis for RB1-associated tumors.", "Tumor suppressor protein regulating G1/S cell cycle transition; binds and inhibits E2F transcription factors controlling S-phase gene expression"),
    makeMarker("KRAS Proto-Oncogene, GTPase", "KRAS", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Xenopus laevis, Danio rerio, Drosophila melanogaster, Xenopus tropicalis, Caenorhabditis elegans", "Oncogenic KRAS mutations lock the RAS GTPase in a constitutively active state, driving carcinogenesis in lung, intestine, pancreas, and other tissues. Annual thoracic imaging and gastrointestinal examination are recommended; KRAS mutant status determines eligibility for targeted therapies and anti-EGFR agents.", "Small GTPase acting as a molecular switch in RAS/MAPK signaling cascade; regulates cell growth, differentiation, and survival"),
  ]},
  { id: "cardiovascular", name: "Cardiovascular", color: "#DC2626", markers: [
    makeMarker("Apolipoprotein B", "APOB", "High", "Homo sapiens, Equus caballus, Mus musculus, Canis lupus familiaris, Danio rerio, Rattus norvegicus", "APOB variants disrupt LDL lipoprotein assembly and cholesterol clearance, predisposing to familial hypercholesterolemia, atherosclerosis, and premature cardiovascular disease. Annual fasting lipid panel and cardiovascular examination are strongly recommended; dietary fat restriction and lipid-lowering management are essential.", "Encodes the primary structural protein of LDL and VLDL particles, essential for lipoprotein assembly, cholesterol transport, and receptor-mediated lipid uptake. Exists as two isoforms: apoB-100 (liver"),
    makeMarker("ATPase Plasma Membrane Ca2+ Transporting 1", "ATP2B1 (PMCA1)", "High", "Homo sapiens, Mus musculus, Gallus gallus, Rattus norvegicus, Caenorhabditis elegans, Danio rerio, Drosophila melanogaster, Saccharomyces cerevisiae", "ATP2B1 variants impair plasma membrane calcium ATPase function, destabilizing intracellular calcium homeostasis and predisposing to hypertension and cardiomyopathy. Annual blood pressure monitoring and cardiac auscultation with echocardiography are recommended; calcium channel management may require pharmacogenomic consideration.", "Encodes a ubiquitous plasma membrane calcium ATPase pump responsible for maintaining low intracellular calcium concentration. Essential for calcium homeostasis in all cell types including cardiomyocyt"),
    makeMarker("Calcium Voltage-Gated Channel Subunit Alpha1 C", "CACNA1C", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Canis lupus familiaris, Danio rerio", "CACNA1C variants alter L-type calcium channel kinetics in cardiomyocytes, predisposing to QT prolongation and ventricular arrhythmias equivalent to Timothy syndrome. Annual cardiac ECG and echocardiography are recommended; avoid drugs that prolong the QT interval in CACNA1C variant carriers.", "Encodes the pore-forming alpha-1C subunit of L-type voltage-gated calcium channels (Cav1.2). Critical for cardiac excitation-contraction coupling, vascular smooth muscle tone, and neuronal calcium sig"),
    makeMarker("Potassium Inwardly Rectifying Channel Subfamily J Member 2", "KCNJ2", "High", "Homo sapiens, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "KCNJ2 variants disrupt inward rectifier potassium channel function, predisposing to Andersen-Tawil syndrome — periodic paralysis, cardiac arrhythmias, and skeletal muscle weakness. Annual ECG with Holter monitoring and serum electrolyte panel are recommended; avoid hypokalemic triggers.", "Encodes the Kir2.1 inward rectifier potassium channel, essential for maintaining resting membrane potential in cardiac, skeletal muscle, and neural cells."),
    makeMarker("Myosin Binding Protein C3, Cardiac", "MYBPC3", "High", "Homo sapiens, Felis catus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "MYBPC3 is the most common cause of hypertrophic cardiomyopathy (HCM) in cats and dogs. Annual echocardiographic screening is strongly recommended from 2 years of age; carrier identification before breeding is essential in affected breeds (Maine Coon, Ragdoll, Bengal cats; Cavalier King Charles Spaniels).", "Encodes cardiac myosin-binding protein C, a thick filament protein essential for cardiac sarcomere structure and contractile regulation."),
    makeMarker("Myosin Heavy Chain 7", "MYH7", "High", "Homo sapiens, Equus caballus, Mus musculus, Sus scrofa, Danio rerio, Rattus norvegicus", "MYH7 variants are a major cause of hypertrophic and dilated cardiomyopathy in horses, dogs, and humans, impairing beta-myosin thick filament function and sarcomeric integrity. Annual echocardiography and clinical cardiac evaluation are essential from 3 years of age; cardiac biomarkers (NT-proBNP, troponin) should be monitored.", "Encodes beta-myosin heavy chain, the predominant myosin in cardiac ventricles and slow-twitch skeletal muscle fibers, essential for cardiac contraction."),
    makeMarker("Sodium Voltage-Gated Channel Alpha Subunit 5", "SCN5A", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "SCN5A variants alter cardiac Nav1.5 sodium channel kinetics, predisposing to Brugada syndrome, sick sinus syndrome, and dilated cardiomyopathy. Annual Holter monitoring and ECG are recommended; sodium channel-blocking drugs (flecainide, procainamide) must be avoided in SCN5A variant carriers.", "Encodes the alpha subunit of the cardiac voltage-gated sodium channel Nav1.5, responsible for the rapid upstroke of the cardiac action potential. Essential for normal cardiac conduction."),
    makeMarker("Striatin", "STRN", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "STRN variants are a significant cause of arrhythmogenic right ventricular cardiomyopathy (ARVC) in Boxer dogs and related breeds. Annual 24-hour Holter monitoring and echocardiography are strongly recommended in carrier animals; ventricular ectopy count on Holter guides antiarrhythmic therapy initiation.", "Encodes striatin, a calmodulin-binding scaffolding protein involved in cell signaling, endocytosis, and cell adhesion at the intercalated discs of cardiomyocytes."),
    makeMarker("Titin", "TTN", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Equus caballus, Danio rerio, Rattus norvegicus", "TTN truncating variants are the most common cause of dilated cardiomyopathy (DCM) in humans and dogs, impairing sarcomeric elasticity and structural integrity. Annual echocardiography and cardiac biomarker monitoring (troponin I, NT-proBNP) are recommended; early ACE inhibitor or pimobendan therapy may be indicated before clinical signs appear.", "Encodes titin, the largest known protein, spanning half the sarcomere from Z-disc to M-band in striated muscle. Functions as a molecular spring providing passive elasticity and serves as a scaffold fo"),
  ]},
  { id: "circadian", name: "Circadian Rhythm", color: "#8B5CF6", markers: [
    makeMarker("Aralkylamine N-Acetyltransferase", "AANAT", "Low", "Homo sapiens, Mus musculus, Ovis aries, Gallus gallus, Danio rerio, Rattus norvegicus", "AANAT variants alter the rate-limiting step of melatonin biosynthesis, influencing seasonal reproductive cycles, sleep-wake timing, and photoperiod adaptation. Monitoring of breeding seasonality and sleep-activity patterns is advisable; relevant to welfare management of species under artificial lighting schedules.", "Encodes the penultimate enzyme in melatonin biosynthesis, catalyzing the N-acetylation of serotonin to N-acetylserotonin. Critical for circadian regulation of melatonin production in the pineal gland."),
    makeMarker("Opsin 4 (Melanopsin)", "OPN4 (Melanopsin)", "Low", "Homo sapiens, Mus musculus, Gallus gallus, Columba livia, Danio rerio, Rattus norvegicus", "OPN4 variants affect melanopsin-mediated circadian photoentrainment efficiency in retinal ganglion cells, influencing adaptation to novel lighting environments. Relevant for welfare management under artificial lighting; affected animals may require gradual light-cycle transitions to avoid circadian misalignment.", "Encodes melanopsin, a photopigment expressed in intrinsically photosensitive retinal ganglion cells (ipRGCs) that mediates non-visual light responses including circadian photoentrainment and the pupil"),
    makeMarker("Clock Circadian Regulator", "CLOCK", "Low", "Homo sapiens, Mus musculus, Drosophila melanogaster (dClock), Rattus norvegicus, Rattus norvegicus, Xenopus tropicalis, Xenopus laevis, Danio rerio, Caenorhabditis elegans", "CLOCK variants alter the core molecular circadian oscillator, potentially causing circadian misalignment, disrupted sleep-wake cycles, and metabolic dysregulation associated with circadian disruption. Monitoring of activity-rest patterns and metabolic health under controlled lighting conditions is advisable.", "bHLH-PAS transcription factor; core component of the molecular circadian clock; heterodimerizes with BMAL1 to drive circadian gene expression"),
    makeMarker("Period Circadian Regulator 2", "PER2", "Low", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus, Xenopus tropicalis, Xenopus laevis, Caenorhabditis elegans, Drosophila melanogaster", "PER2 variants destabilize the circadian negative feedback loop, associated with advanced sleep phase syndrome and metabolic clock dysregulation. Monitoring of activity-rest patterns and feeding rhythms is advisable; relevant to managing reproductive performance and metabolic health in managed populations.", "Core circadian clock protein; negative regulator of CLOCK/BMAL1-mediated transcription; essential for ~24h oscillation of circadian rhythms"),
    makeMarker("Aryl Hydrocarbon Receptor Nuclear Translocator Like (Brain and Muscle ARNT-Like 1)", "ARNTL/BMAL1", "Low", "Homo sapiens, Mus musculus, Rattus norvegicus, Xenopus tropicalis, Xenopus laevis, Danio rerio, Drosophila melanogaster, Caenorhabditis elegans", "BMAL1 variants impair the positive arm of the molecular clock, predisposing to metabolic disorders, reduced fertility, and accelerated aging phenotypes. Routine metabolic health monitoring and reproductive performance assessment are recommended; environmental lighting management is important for affected individuals.", "Core circadian clock transcription factor; heterodimerizes with CLOCK to drive expression of Period and Cryptochrome genes"),
  ]},
  { id: "dermatology", name: "Dermatology", color: "#EC4899", markers: [
    makeMarker("Fermitin Family Member 1", "FERMT1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "FERMT1 (kindlin-1) loss-of-function variants cause Kindler syndrome — skin fragility with blistering at minimal mechanical trauma, progressive photosensitivity, and mucosal involvement. Protective management against mechanical trauma and UV exposure is essential; refer to dermatology for early intervention and wound care protocols.", "Encodes kindlin-1, a focal adhesion protein essential for integrin activation and keratinocyte adhesion to the basement membrane of the skin."),
    makeMarker("Keratin 71", "KRT71", "Medium", "Homo sapiens, Felis catus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "KRT71 variants alter inner root sheath keratin structure, producing wavy or curled coat phenotypes (rex trait). While primarily a morphological trait, confirm absence of associated follicular dystrophy or sebaceous gland dysfunction; skin barrier function monitoring and regular coat assessment are recommended.", "Encodes keratin type II cytoskeletal 71, expressed in the inner root sheath of hair follicles and controlling hair texture and curl pattern."),
    makeMarker("Laminin Subunit Alpha 3", "LAMA3", "Medium", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "LAMA3 loss-of-function variants cause junctional epidermolysis bullosa — severe mucocutaneous blistering at the dermal-epidermal junction with significant morbidity and mortality. Carrier identification before breeding is essential; offspring of carrier parents require immediate diagnostic confirmation and specialized supportive care.", "Encodes the alpha-3 chain of laminin-332 (formerly laminin-5), a major component of the basement membrane anchoring filaments in skin and mucous membranes."),
    makeMarker("Laminin Subunit Gamma 2", "LAMC2", "Medium", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "LAMC2 variants disrupt laminin-332 hemidesmosomal anchoring filament assembly, causing junctional epidermolysis bullosa with severe mucosal involvement. Genetic carrier testing before breeding is strongly advised; affected neonates require immediate specialized veterinary wound care and nutritional support.", "Encodes the gamma-2 chain of laminin-332, essential for epithelial cell adhesion to the basement membrane through hemidesmosomal anchoring."),
  ]},
  { id: "development", name: "Development", color: "#10B981", markers: [
    makeMarker("Cadherin 2 (N-Cadherin)", "CDH2", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Gallus gallus, Rattus norvegicus", "CDH2 variants impair N-cadherin-mediated neural crest migration and cardiac development, potentially contributing to congenital heart defects and skeletal dysplasias. Cardiac auscultation with echocardiography and developmental morphological assessment are recommended in affected offspring.", "Encodes N-cadherin, a calcium-dependent cell adhesion molecule critical for neural crest migration, cardiac development, and synaptic structure. Essential for embryonic development and tissue morphoge"),
    makeMarker("Indian Hedgehog Signaling Molecule", "IHH", "Medium", "Homo sapiens, Equus caballus, Gallus gallus, Mus musculus, Danio rerio, Rattus norvegicus", "IHH variants disrupt endochondral ossification signaling, causing brachydactyly and short stature syndromes from impaired chondrocyte differentiation. Limb length, skeletal proportions, and growth plate assessment are recommended in affected individuals; relevant for breeders selecting against skeletal dysplasias.", "Encodes Indian hedgehog, a signaling molecule critical for chondrocyte differentiation, bone formation, and endochondral ossification during skeletal development."),
    makeMarker("Limb And CNS Expressed 1", "LIX1", "Medium", "Homo sapiens, Gallus gallus, Mus musculus, Danio rerio, Rattus norvegicus", "LIX1 variants affect gastrointestinal mesenchymal progenitor cell maintenance, with potential consequences for smooth muscle development and GI motility. Gastrointestinal function assessment is recommended in animals presenting with unexplained digestive anomalies or motility disorders.", "Encodes a protein expressed during limb and central nervous system development, involved in gastrointestinal mesenchymal progenitor cell maintenance."),
    makeMarker("LLP Homolog, Long-Term Synaptic Facilitation Factor", "LLPH", "Medium", "Homo sapiens, Bos taurus, Mus musculus, Danio rerio, Rattus norvegicus", "LLPH variants influence synaptic facilitation and chromatin remodeling; specific clinical phenotypes in domestic animals require further characterization. Monitor for developmental or neurological anomalies in carrier offspring; neurological developmental milestones should be assessed.", "Encodes a protein implicated in long-term synaptic facilitation and chromatin remodeling, with roles in development and neuroplasticity."),
    makeMarker("Regulatory Factor X8", "RFX8", "Medium", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "RFX8 variants may impair ciliogenesis-related transcriptional programs; specific clinical phenotype in domestic species requires further characterization. Assess for ciliopathy-related signs including hydrocephalus, reproductive abnormalities, situs inversus, and respiratory mucociliary clearance defects.", "Encodes a member of the RFX transcription factor family involved in ciliogenesis and developmental gene regulation. RFX8 is less characterized than other RFX family members."),
    makeMarker("Semaphorin 3D", "SEMA3D", "Medium", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "SEMA3D variants affect axon guidance and cardiovascular neural crest cell patterning, potentially contributing to cardiac outflow tract malformations and olfactory development anomalies. Cardiac screening of offspring from carrier parents and assessment for anosmia-related Kallmann syndrome equivalents is advisable.", "Encodes a secreted semaphorin that functions as a guidance cue for axons and migrating cells during development. Also involved in cardiovascular development and neural crest cell migration."),
    makeMarker("SPARC Like 1 (Hevin)", "SPARCL1", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "SPARCL1 variants affect synaptogenesis and anti-adhesive extracellular matrix signaling in the nervous system. Monitor for developmental neurological symptoms including learning difficulties or behavioral abnormalities; relevant to breeding programs selecting for neurological soundness.", "Encodes hevin, a matricellular glycoprotein that modulates cell adhesion and is involved in synaptogenesis. An anti-adhesive protein structurally related to SPARC/osteonectin."),
    makeMarker("Sonic Hedgehog Signaling Molecule", "SHH", "Medium", "Homo sapiens, Mus musculus, Gallus gallus (Chicken), Caenorhabditis elegans, Danio rerio, Drosophila melanogaster, Rattus norvegicus, Xenopus tropicalis, Saccharomyces cerevisiae, Xenopus laevis", "SHH variants disrupt ventral neural tube and limb patterning, causing holoprosencephaly or polydactyly depending on allele type and dosage. Prenatal and neonatal developmental assessment is essential; carrier-to-carrier crosses should be avoided given the risk of severely affected homozygous offspring.", "Morphogen essential for embryonic patterning including neural tube, limb, and digit formation; ventral midline signaling"),
    makeMarker("Paired Box 6", "PAX6", "Medium", "Homo sapiens, Mus musculus, Drosophila melanogaster, Xenopus laevis, Danio rerio, Xenopus tropicalis, Caenorhabditis elegans, Rattus norvegicus", "PAX6 variants are a major cause of aniridia, ocular coloboma, and anterior segment dysgenesis. Ophthalmic examination with slit-lamp biomicroscopy is essential in offspring of carrier parents; ophthalmologist referral for definitive diagnosis and intraocular pressure monitoring are recommended.", "Master control gene for eye development; transcription factor regulating lens, cornea, retina, and brain patterning"),
    makeMarker("Bone Morphogenetic Protein 4", "BMP4", "Medium", "Geospiza fortis (Medium Ground Finch), Geospiza magnirostris (Large Ground Finch), Homo sapiens, Mus musculus, Rattus norvegicus, Xenopus tropicalis, Xenopus laevis, Caenorhabditis elegans, Danio rerio, Drosophila melanogaster", "BMP4 variants affect craniofacial and beak morphology, particularly in avian species where BMP4 expression level determines beak depth and width. Craniofacial conformation assessment in offspring is recommended; relevant for managed breeding programs selecting for beak shape or craniofacial structure.", "TGF-beta superfamily signaling molecule regulating bone, cartilage, and craniofacial morphogenesis"),
    makeMarker("Homeobox A13", "HOXA13", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Xenopus tropicalis, Danio rerio, Xenopus laevis", "HOXA13 variants cause hand-foot-genital syndrome with digit hypoplasia and urogenital tract anomalies. Evaluate digit morphology and urinary tract anatomy (ultrasound) in offspring of carrier parents; reproductive tract assessment is advisable for female carriers before inclusion in breeding programs.", "Transcription factor specifying distal limb and digit identity; regulates appendage patterning in vertebrates"),
    makeMarker("Wnt Family Member 3A", "WNT3A", "Medium", "Homo sapiens, Mus musculus, Xenopus laevis, Caenorhabditis elegans, Danio rerio, Mus musculus, Rattus norvegicus, Xenopus tropicalis", "WNT3A variants impair posterior body axis formation and somitogenesis signaling, predisposing to vertebral segmentation defects and sacral agenesis. Spinal radiographic assessment is recommended in offspring from carrier parents; relevant to assessing spinal malformation risk in breeding programs.", "Secreted signaling molecule in the canonical Wnt pathway; essential for posterior body axis formation and somitogenesis"),
    makeMarker("Fibroblast Growth Factor 8", "FGF8", "Medium", "Homo sapiens, Mus musculus, Gallus gallus (Chicken), Rattus norvegicus, Xenopus tropicalis, Danio rerio, Xenopus laevis, Caenorhabditis elegans", "FGF8 variants disrupt midbrain-hindbrain boundary formation, limb bud outgrowth, and olfactory development, causing Kallmann syndrome equivalents with anosmia and hypogonadotropic hypogonadism. Neurological, olfactory, and reproductive system assessment is recommended in affected animals.", "Signaling molecule critical for limb bud outgrowth, brain patterning (midbrain-hindbrain boundary), and craniofacial development"),
    makeMarker("Notch Receptor 1", "NOTCH1", "Medium", "Drosophila melanogaster, Homo sapiens, Mus musculus, Danio rerio, Caenorhabditis elegans, Xenopus laevis, Rattus norvegicus, Xenopus tropicalis", "NOTCH1 variants affect cardiac valve development and arterial wall formation, predisposing to bicuspid aortic valve and arterial calcification. Cardiac echocardiography and vascular assessment are recommended in offspring of carrier parents; relevant to managing inherited cardiac developmental anomalies.", "Transmembrane receptor mediating lateral inhibition during cell fate decisions; Notch signaling is fundamental to neurogenesis, somitogenesis, and angiogenesis"),
    makeMarker("Delta Like Canonical Notch Ligand 3", "DLL3", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Python molurus (Burmese Python), Xenopus laevis, Danio rerio, Xenopus tropicalis, Caenorhabditis elegans", "DLL3 variants cause spondylocostal dysostosis — severe vertebral and rib segmentation defects from impaired Notch-mediated somitogenesis. Thoracic and spinal radiographic examination is recommended in offspring; carrier testing is advised before breeding to reduce risk of severely affected offspring.", "Notch pathway ligand involved in somite segmentation; essential for proper vertebral column patterning"),
    makeMarker("Paired Like Homeodomain 2", "PITX2", "Medium", "Homo sapiens, Mus musculus, Lottia gigantea (Owl Limpet), Lymnaea stagnalis (Pond Snail), Xenopus laevis, Caenorhabditis elegans, Danio rerio, Drosophila melanogaster, Rattus norvegicus, Saccharomyces cerevisiae, Xenopus tropicalis", "PITX2 variants disrupt left-right cardiac and visceral organ siting, causing situs inversus or complex cardiac heterotaxy defects. Thoracic imaging including cardiac position and great vessel assessment is recommended in offspring; echocardiography is essential to characterize cardiac defects in affected individuals.", "Transcription factor essential for left-right body asymmetry; specifies left-sided organ identity during embryogenesis"),
  ]},
  { id: "endocrine", name: "Endocrine", color: "#F97316", markers: [
    makeMarker("Calcium Sensing Receptor", "CASR", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Bos taurus, Danio rerio, Rattus norvegicus", "CASR variants alter parathyroid calcium sensing, predisposing to familial hypocalciuric hypercalcemia or neonatal severe hyperparathyroidism depending on allele type. Annual serum calcium, phosphorus, and PTH monitoring are recommended; calcium-rich supplementation requires careful management to avoid hypercalcemic crises.", "Encodes the calcium-sensing receptor, a GPCR on parathyroid and renal cells that detects extracellular calcium levels and regulates PTH secretion and renal calcium reabsorption. Master regulator of ca"),
    makeMarker("Cytochrome P450 Family 27 Subfamily B Member 1", "CYP27B1", "Medium", "Homo sapiens, Mus musculus, Sus scrofa, Gallus gallus, Danio rerio, Rattus norvegicus", "CYP27B1 loss-of-function variants block active vitamin D3 synthesis, causing vitamin D-dependent rickets type IA with hypocalcemia, hypophosphatemia, and bone deformities. Regular serum 1,25(OH)2D3, calcium, and phosphorus monitoring are essential; calcitriol supplementation is required and must be carefully dosed.", "Encodes 25-hydroxyvitamin D 1-alpha-hydroxylase, the mitochondrial enzyme that produces the active hormone 1,25-dihydroxyvitamin D3 (calcitriol) in the kidney. The rate-limiting step in vitamin D acti"),
    makeMarker("Cytochrome P450 Family 2 Subfamily R Member 1", "CYP2R1", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "CYP2R1 variants reduce hepatic 25-hydroxylation of vitamin D, causing vitamin D-dependent rickets type IB. Regular serum 25-hydroxyvitamin D monitoring and adjusted dietary vitamin D supplementation are recommended; standard vitamin D doses may be insufficient and require upward adjustment.", "Encodes vitamin D 25-hydroxylase, the major hepatic enzyme that converts vitamin D3 (cholecalciferol) to 25-hydroxyvitamin D3, the main circulating form of vitamin D used for clinical assessment."),
    makeMarker("Iodothyronine Deiodinase 2", "DIO2", "Medium", "Homo sapiens, Gallus gallus, Coturnix japonica, Mus musculus, Canis lupus familiaris, Danio rerio, Rattus norvegicus", "DIO2 variants reduce peripheral T4-to-T3 conversion efficiency, potentially causing subclinical hypothyroidism despite normal T4 levels. Include total T3 measurement in thyroid panels; consider T3/T4 combination therapy or T3-containing thyroid supplements when clinical signs persist with normal T4.", "Encodes type 2 deiodinase, a selenoenzyme that converts the prohormone T4 (thyroxine) to the active thyroid hormone T3 (triiodothyronine) by outer ring deiodination. Critical for local thyroid hormone"),
    makeMarker("Fibroblast Growth Factor 23", "FGF23", "Medium", "Homo sapiens, Felis catus, Canis lupus familiaris, Mus musculus, Caenorhabditis elegans, Danio rerio, Drosophila melanogaster, Rattus norvegicus", "FGF23 variants cause hypophosphatemic rickets or familial tumoral calcinosis through dysregulated renal phosphate handling. Regular serum phosphate, FGF23, and calcium monitoring are recommended; dietary phosphate management and phosphate supplementation are important; relevant to chronic kidney disease management.", "Encodes a bone-derived phosphaturic hormone that regulates phosphate homeostasis and vitamin D metabolism by acting on the kidney."),
    makeMarker("Growth Hormone 1", "GH", "Medium", "Homo sapiens, Bos taurus, Sus scrofa, Gallus gallus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "GH variants affect growth hormone production, predisposing to growth retardation (dwarfism) or pituitary gigantism depending on variant type. Annual height/weight growth curve monitoring and serum IGF-1 measurement are recommended; endocrine consultation is advisable for individuals with significant growth deviation.", "Encodes growth hormone (somatotropin), a pituitary peptide hormone that stimulates growth, cell reproduction, and IGF-1 production."),
    makeMarker("Insulin-Like Growth Factor 1", "IGF-1", "Medium", "Homo sapiens, Canis lupus familiaris, Bos taurus, Sus scrofa, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "IGF-1 variants affect insulin-like growth factor levels that mediate growth hormone effects, influencing body size, muscle mass, and insulin sensitivity. Annual serum IGF-1 measurement and metabolic screening including fasting glucose are recommended; relevant to body condition and reproductive management in livestock.", "Encodes insulin-like growth factor 1 (alternative notation). Same gene as IGF1; this notation is commonly used in veterinary and livestock genomics literature."),
    makeMarker("Insulin-Like Growth Factor 1", "IGF1", "Medium", "Homo sapiens, Canis lupus familiaris, Bos taurus, Sus scrofa, Mus musculus, Equus caballus, Danio rerio, Rattus norvegicus", "IGF1 variants are major determinants of body size and metabolic rate across species, influencing growth velocity, muscle accretion, and lifespan. Annual serum IGF1 monitoring and body condition assessment are recommended; relevant to performance management in livestock and prediction of adult size in companion animals.", "Encodes insulin-like growth factor 1, a major mediator of growth hormone effects that promotes cell growth, differentiation, and survival through the IGF1R signaling pathway."),
    makeMarker("Insulin-Like Growth Factor 1 Receptor", "IGF1R", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Bos taurus, Danio rerio, Rattus norvegicus", "IGF1R variants alter insulin-like growth factor receptor signaling, affecting growth rate, insulin sensitivity, and cellular survival pathways. Growth monitoring and annual metabolic screening including fasting glucose and insulin are recommended; IGF1R status also influences cellular susceptibility to IGF1R-targeted cancer therapies.", "Encodes the IGF-1 receptor, a receptor tyrosine kinase that mediates IGF-1 and IGF-2 signaling to promote growth, proliferation, and survival."),
    makeMarker("Immunoglobulin Superfamily Member 1", "IGSF1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "IGSF1 variants cause X-linked central hypothyroidism and macroorchidism through impaired pituitary TRH signaling. Evaluate thyroid function (TSH, free T4) and testicular development in affected males; TSH-guided thyroid hormone supplementation is required and must account for the centrally low TSH baseline.", "Encodes a membrane glycoprotein of the immunoglobulin superfamily expressed in the pituitary and testis, involved in regulating thyroid-stimulating hormone and testosterone secretion."),
    makeMarker("Melanocortin 2 Receptor", "MC2R", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Bos taurus, Mus musculus, Danio rerio, Rattus norvegicus", "MC2R variants impair ACTH receptor signaling in the adrenal cortex, causing familial glucocorticoid deficiency with hypoglycemia and hyperpigmentation despite normal mineralocorticoid function. Annual ACTH stimulation testing and fasting glucose monitoring are recommended; perioperative steroid coverage protocols are essential.", "Encodes the ACTH receptor (melanocortin-2 receptor), expressed primarily in the adrenal cortex where it mediates ACTH-stimulated cortisol production."),
    makeMarker("Nuclear Receptor Subfamily 3 Group C Member 2 (Mineralocorticoid Receptor)", "NR3C2 (MR)", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "NR3C2 variants reduce mineralocorticoid receptor function, predisposing to pseudohypoaldosteronism with salt wasting, hyperkalemia, and hypotension — particularly dangerous in neonates. Annual serum electrolyte monitoring (sodium, potassium) and blood pressure assessment are recommended; dietary sodium supplementation may be required.", "Encodes the mineralocorticoid receptor that binds aldosterone and cortisol, regulating sodium and potassium balance in the kidney. Also expressed in hippocampus where it modulates stress responses."),
    makeMarker("Proopiomelanocortin", "POMC", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Equus caballus, Danio rerio, Rattus norvegicus", "POMC variants disrupt multi-peptide precursor processing, predisposing to central adrenal insufficiency, severe hyperphagia-driven obesity, and altered coat/skin pigmentation. Annual cortisol testing, body weight monitoring, and adrenal reserve assessment are recommended; ACTH and alpha-MSH insufficiency each require separate management.", "Encodes a polypeptide precursor that is cleaved into multiple bioactive peptides including ACTH, alpha-MSH, beta-endorphin, and beta-lipotropin. Central regulator of the stress response, appetite, and"),
    makeMarker("Parathyroid Hormone", "PTH", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Gallus gallus, Mus musculus, Danio rerio, Rattus norvegicus", "PTH variants alter parathyroid hormone production and calcium-phosphorus homeostasis regulation. Annual serum calcium, phosphorus, and PTH measurement is recommended; monitor for signs of hypercalcemia (polyuria, weakness) or hypocalcemia (tetany, seizures) in affected individuals.", "Encodes parathyroid hormone, the principal regulator of calcium and phosphorus homeostasis. PTH mobilizes calcium from bone, enhances renal calcium reabsorption, and stimulates renal 1,25-dihydroxyvit"),
    makeMarker("Vitamin D Receptor", "VDR", "Medium", "Homo sapiens, Gallus gallus, Bos taurus, Mus musculus, Canis lupus familiaris, Danio rerio, Rattus norvegicus", "VDR variants reduce cellular responsiveness to active vitamin D, predisposing to rickets, immune dysregulation, and altered calcium metabolism even with adequate vitamin D levels. Annual serum calcium, phosphorus, and vitamin D metabolite monitoring is recommended; higher-dose vitamin D supplementation may be required to overcome receptor insensitivity.", "Encodes the nuclear receptor for 1,25-dihydroxyvitamin D3 (calcitriol), mediating the genomic actions of vitamin D on calcium homeostasis, bone metabolism, immune function, and cell differentiation."),
  ]},
  { id: "epigenetics", name: "Epigenetics", color: "#6366F1", markers: [
    makeMarker("Necdin", "NDN", "Low", "Homo sapiens, Mus musculus, Caenorhabditis elegans, Danio rerio, Drosophila melanogaster, Rattus norvegicus, Saccharomyces cerevisiae", "NDN is a maternally imprinted, paternally expressed gene in the Prader-Willi critical region; paternal deletion contributes to hypothalamic dysfunction and hyperphagia. Informational; monitor for hyperphagia, obesity, and metabolic anomalies in offspring carrying deletion of the paternal 15q11/chromosome 7 region in relevant species.", "Encodes necdin, a maternally imprinted, paternally expressed gene in the Prader-Willi syndrome critical region that functions as a growth suppressor in postmitotic neurons."),
    makeMarker("DNA Methyltransferase 3 Alpha", "DNMT3A", "Low", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio, Xenopus tropicalis, Xenopus laevis", "DNMT3A somatic mutations are among the most common drivers of hematopoietic malignancies and clonal hematopoiesis of indeterminate potential. Germline variants are informational; annual complete blood count monitoring is advisable to detect evolving cytopenias that may signal clonal hematopoietic expansion.", "De novo DNA methyltransferase establishing new CpG methylation patterns during development; essential for genomic imprinting"),
    makeMarker("Tet Methylcytosine Dioxygenase 2", "TET2", "Low", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio, Xenopus tropicalis, Xenopus laevis, Drosophila melanogaster", "TET2 somatic loss-of-function is a common driver of clonal hematopoiesis and myeloid malignancies. Germline reference variants are informational; annual complete blood count is advisable with attention to progressive cytopenias or monocytosis that may signal clonal TET2-mutant expansion.", "Enzyme catalyzing oxidation of 5-methylcytosine to 5-hydroxymethylcytosine; key mediator of active DNA demethylation"),
  ]},
  { id: "hematology", name: "Hematology", color: "#B91C1C", markers: [
    makeMarker("Ankyrin 1", "ANK1", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "ANK1 variants cause hereditary spherocytosis — chronic compensated hemolytic anemia with spherocytic erythrocytes, intermittent jaundice, splenomegaly, and pigment gallstone risk. Annual CBC with reticulocyte count and serum bilirubin monitoring are essential; splenectomy is indicated in severe cases with transfusion dependence.", "Encodes ankyrin-1, a structural protein that links the red blood cell membrane skeleton to integral membrane proteins (band 3, Rh complex). Essential for erythrocyte shape and deformability."),
    makeMarker("Solute Carrier Family 11 Member 2 (Divalent Metal Transporter 1)", "DMT1 (SLC11A2)", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Gallus gallus, Danio rerio", "DMT1 variants impair intestinal and endosomal iron transport, causing microcytic hypochromic anemia with paradoxical hepatic iron overload. Annual CBC with iron studies (serum iron, ferritin, transferrin saturation) and liver function tests are recommended; both anemia management and iron overload prevention must be balanced.", "Encodes the primary intestinal iron transporter that mediates uptake of ferrous iron (Fe2+) from the gut lumen into enterocytes. Also transports iron from endosomes to cytoplasm after transferrin rece"),
    makeMarker("Coagulation Factor XII", "F12", "High", "Homo sapiens, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "F12 variants cause Hageman factor deficiency — severely prolonged aPTT on coagulation testing but typically without clinical bleeding tendency. Identification before surgical procedures is essential to avoid unnecessary blood product administration; distinguish carefully from other factor deficiencies that do cause bleeding.", "Encodes Hageman factor, a serine protease involved in the initiation of the intrinsic coagulation pathway and the kallikrein-kinin system."),
    makeMarker("Coagulation Factor VIII", "F8", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "F8 loss-of-function variants cause Hemophilia A — factor VIII deficiency producing severe spontaneous bleeding into joints, muscles, and body cavities. Factor VIII activity assay and carrier identification are essential before any surgical procedure; bleeding precautions, factor VIII replacement therapy, and DDAVP protocols must be established for affected individuals.", "Encodes coagulation factor VIII, a cofactor for factor IXa in the intrinsic coagulation cascade. Deficiency causes hemophilia A."),
    makeMarker("Coagulation Factor IX", "F9", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "F9 variants cause Hemophilia B (Christmas disease) — factor IX deficiency with severe spontaneous hemorrhage into joints and soft tissues. Factor IX activity measurement and carrier genotyping are mandatory; surgical bleeding management protocols including factor IX concentrate must be in place for affected animals.", "Encodes coagulation factor IX (Christmas factor), a vitamin K-dependent serine protease essential for blood coagulation. Deficiency causes hemophilia B."),
    makeMarker("Pyruvate Kinase L/R", "PKLR", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "PKLR variants cause pyruvate kinase deficiency — chronic hemolytic anemia in dogs and cats, with secondary myelofibrosis and osteosclerosis in severe canine cases. Annual CBC, reticulocyte count, and bilirubin monitoring are recommended; bone marrow transplantation is curative in severe canine PKLR deficiency.", "Encodes the liver and red blood cell isoforms of pyruvate kinase, a glycolytic enzyme catalyzing the conversion of phosphoenolpyruvate to pyruvate. The R isoform is the sole glycolytic pathway in matu"),
    makeMarker("Solute Carrier Family 40 Member 1 (Ferroportin)", "SLC40A1", "High", "Homo sapiens, Mus musculus, Danio rerio, Canis lupus familiaris, Rattus norvegicus", "SLC40A1 variants cause hereditary hemochromatosis type 4 — progressive hepatic, cardiac, and endocrine iron overload from failure of hepcidin-regulated iron export. Annual serum ferritin, transferrin saturation, and liver enzyme monitoring are essential; iron-restricted diet and therapeutic phlebotomy are the primary management strategies.", "Encodes ferroportin, the only known cellular iron exporter in mammals. Expressed on enterocytes, macrophages, and hepatocytes, it is essential for iron release into plasma and is regulated by hepcidin"),
    makeMarker("Solute Carrier Family 4 Member 1 (Band 3/Anion Exchanger 1)", "SLC4A1", "High", "Homo sapiens, Bos taurus, Mus musculus, Danio rerio, Rattus norvegicus", "SLC4A1 variants cause hereditary spherocytosis or Southeast Asian ovalocytosis depending on mutation type, compromising erythrocyte deformability and structural integrity. Annual CBC with morphological evaluation and reticulocyte count are recommended; hydration and folic acid supplementation management are important.", "Encodes Band 3 protein, the major integral membrane protein of erythrocytes mediating chloride-bicarbonate exchange. Also important for CO2 transport and erythrocyte structural integrity."),
    makeMarker("Transferrin", "TF", "High", "Homo sapiens, Bos taurus, Equus caballus, Gallus gallus, Mus musculus, Danio rerio, Rattus norvegicus", "TF variants affect systemic iron transport and distribution; severe deficiency causes hypochromic anemia with paradoxical iron overload in non-hematopoietic tissues. Annual CBC with iron studies (serum iron, ferritin, transferrin saturation) and hepatic enzyme panel are recommended to monitor both anemia and iron deposition.", "Encodes serum transferrin, the primary iron transport protein in blood that binds ferric iron and delivers it to cells via transferrin receptor-mediated endocytosis. Essential for systemic iron distri"),
    makeMarker("Von Willebrand Factor", "VWF", "High", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Danio rerio, Rattus norvegicus", "VWF variants are the most common inherited bleeding disorder in dogs (von Willebrand disease types I–III). Buccal mucosal bleeding time and VWF:Ag quantitation are recommended before any surgical procedure; VWF genotyping before breeding is strongly advised in affected breeds (Doberman Pinscher, German Shepherd, Scottish Terrier).", "Encodes von Willebrand factor, a large multimeric glycoprotein essential for platelet adhesion to damaged endothelium and as a carrier protein for coagulation factor VIII in plasma."),
  ]},
  { id: "hepatic", name: "Hepatic", color: "#059669", markers: [
    makeMarker("ATPase Copper Transporting Beta", "ATP7B", "Medium", "Homo sapiens, Canis lupus familiaris, Rattus norvegicus, Mus musculus, Caenorhabditis elegans, Danio rerio, Drosophila melanogaster, Saccharomyces cerevisiae", "ATP7B loss-of-function variants cause Wilson disease — progressive hepatic copper accumulation producing hepatitis, cirrhosis, and neurological signs from copper deposition in the brain. Annual liver enzymes, serum ceruloplasmin, and 24-hour urinary copper assessment are recommended; copper-restricted diet and chelation therapy (D-penicillamine, zinc) are indicated.", "Encodes a copper-transporting ATPase expressed primarily in the liver that incorporates copper into ceruloplasmin and mediates biliary copper excretion. Essential for copper homeostasis."),
    makeMarker("Bile Acid-CoA:Amino Acid N-Acyltransferase", "BAAT", "Medium", "Homo sapiens, Felis catus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "BAAT variants alter bile acid conjugation patterns (glycine vs. taurine), affecting fat digestion efficiency and bile salt solubility. Annual liver function testing and assessment of fat-soluble vitamin absorption are recommended; species-specific dietary fat and taurine management is particularly important in cats and dogs.", "Encodes the enzyme that conjugates bile acids with glycine or taurine in the liver, forming bile salts essential for fat digestion and absorption. Species differ in conjugation patterns."),
    makeMarker("Copper Metabolism Domain Containing 1", "COMMD1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "COMMD1 variants cause canine copper toxicosis (Bedlington Terrier hepatitis equivalent) — progressive hepatic copper accumulation leading to cirrhosis and liver failure. Annual liver enzyme and hepatic copper quantitation (biopsy if warranted) are recommended; copper-restricted diet and chelation therapy (ammonium tetrathiomolybdate, zinc acetate) are the primary prevention strategies.", "Encodes COMMD1 (formerly MURR1), a protein that regulates copper homeostasis by promoting biliary copper excretion and interacting with ATP7B. Also involved in NF-kB signaling and sodium channel traff"),
    makeMarker("Cytochrome P450 Family 7 Subfamily A Member 1", "CYP7A1", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Felis catus, Canis lupus familiaris, Danio rerio", "CYP7A1 variants reduce bile acid synthesis from cholesterol, predisposing to hypercholesterolemia and cholesterol gallstone formation. Annual fasting lipid profile and hepatic enzyme monitoring are recommended; dietary fat restriction and choleretic support (ursodeoxycholic acid) may be indicated in symptomatic individuals.", "Encodes cholesterol 7-alpha-hydroxylase, the rate-limiting enzyme in the classic bile acid synthesis pathway. Controls the conversion of cholesterol to bile acids in the liver."),
  ]},
  { id: "immune", name: "Immune", color: "#3B82F6", markers: [
    makeMarker("Bovine/Feline Immunodeficiency Virus Integration Site 21", "BFIV21", "High", "Bos taurus, Felis catus, Mus musculus, Rattus norvegicus", "BFIV21 variants are associated with susceptibility to retroviral integration and immune evasion in bovine and feline hosts. Annual immune profiling (CBC, lymphocyte subsets) is recommended for carriers in high-exposure settings; relevant to managing FIV-positive catteries and bovine retroviral disease surveillance.", "Gene locus associated with bovine and feline immunodeficiency virus integration site; relevant to retroviral susceptibility and immune evasion mechanisms in bovine and feline hosts."),
    makeMarker("Blood Group Antigen B (MHC Class I)", "BG1", "Medium", "Gallus gallus, Homo sapiens, Mus musculus, Rattus norvegicus", "BG1 MHC class I variants influence immune response breadth and susceptibility to Marek's disease virus in poultry. Haplotype-aware flock management and vaccination protocol selection are recommended; BG1 genotyping informs Marek's disease resistance breeding strategies.", "Encodes a MHC class I-like antigen (blood group antigen B) in chickens; influences immune responses and disease resistance, particularly to Marek's disease virus."),
    makeMarker("CD134 (OX40)", "CD134", "Medium", "Felis catus, Canis lupus familiaris, Homo sapiens, Mus musculus, Rattus norvegicus", "CD134 variants alter OX40 co-stimulatory receptor signaling in T cells, influencing T cell survival and immune memory formation. Relevant to feline immunodeficiency virus receptor tropism; monitor for signs of immune dysregulation and inform vaccination timing in seropositive animals.", "Encodes OX40, a co-stimulatory receptor on activated T cells that promotes T cell survival and memory. In cats, CD134 also functions as a receptor for feline immunodeficiency virus (FIV)."),
    makeMarker("Cytidine Monophospho-N-Acetylneuraminic Acid Hydroxylase", "CMAH", "Medium", "Canis lupus familiaris, Sus scrofa, Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "CMAH variants affect sialic acid cell-surface expression patterns, modifying susceptibility to certain pathogens and influencing xenotransplantation compatibility. Relevant to porcine-to-canine transplant biology; in breeding animals, assess for associated inflammation or immune activation phenotypes.", "Encodes the enzyme that converts CMP-N-acetylneuraminic acid (Neu5Ac) to CMP-N-glycolylneuraminic acid (Neu5Gc). Regulates sialic acid composition on cell surfaces, affecting pathogen interactions."),
    makeMarker("Cytotoxic T-Lymphocyte Associated Protein 4", "CTLA4", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Rattus norvegicus, Danio rerio", "CTLA4 variants impair T cell checkpoint inhibition, predisposing to immune-mediated polyendocrinopathy, thyroiditis, and inflammatory bowel disease. Annual thyroid function, glucose, and inflammatory marker monitoring are recommended; CTLA4 genotype is relevant to immune checkpoint therapy risks in oncology patients.", "Encodes CTLA-4, an inhibitory immune checkpoint receptor on T cells that competes with CD28 for B7 ligands and dampens T cell activation to prevent autoimmunity."),
    makeMarker("C-X-C Motif Chemokine Receptor 4", "CXCR4", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "CXCR4 gain-of-function variants cause WHIM syndrome (warts, hypogammaglobulinemia, infections, myelokathexis) with neutropenia and B cell lymphopenia. Annual CBC with differential, immunoglobulin quantitation, and B cell subset analysis are recommended; prophylactic antimicrobials may be required.", "Encodes a chemokine receptor that mediates hematopoietic stem cell homing to bone marrow and lymphocyte trafficking. Also a co-receptor for HIV-1 entry."),
    makeMarker("Dog Leukocyte Antigen 88 (MHC Class I)", "DLA-88", "Medium", "Canis lupus familiaris, Mus musculus, Rattus norvegicus", "DLA-88 haplotype determines canine MHC class I antigen presentation specificity, directly influencing susceptibility to infectious diseases and the outcome of bone marrow and organ transplantation. DLA typing is essential before hematopoietic stem cell transplantation; relevant to selecting compatible donors in regenerative veterinary medicine.", "Encodes the primary MHC class I molecule in dogs, responsible for presenting intracellular peptides to CD8+ cytotoxic T cells. Polymorphism determines immune response breadth."),
    makeMarker("Dog Leukocyte Antigen DQB1 (MHC Class II)", "DLA-DQB1", "Medium", "Canis lupus familiaris, Mus musculus, Rattus norvegicus", "DLA-DQB1 haplotypes are strongly associated with breed-specific autoimmune diseases including immune-mediated hemolytic anemia, inflammatory bowel disease, and hypothyroidism. Annual thyroid function testing and CBC screening are recommended in susceptible breeds; DLA-DQB1 typing assists in estimating autoimmune disease risk.", "Encodes the DQB1 beta chain of MHC class II molecules in dogs, presenting extracellular antigens to CD4+ helper T cells. Polymorphism is associated with autoimmune disease susceptibility."),
    makeMarker("Dog Leukocyte Antigen DRB1 (MHC Class II)", "DLA-DRB1", "Medium", "Canis lupus familiaris, Mus musculus, Rattus norvegicus", "DLA-DRB1 variants are associated with susceptibility to immune-mediated diseases including rheumatoid arthritis equivalents, lupus-like syndromes, and Addison's disease in dogs. Annual adrenal and immunological function assessment is recommended in susceptible breeds; DLA-DRB1 genotyping enhances disease risk profiling.", "Encodes the DRB1 beta chain of canine MHC class II (DLA-DR), the primary molecule for presenting extracellular pathogens to CD4+ helper T lymphocytes."),
    makeMarker("Equine Leukocyte Antigen DRA (MHC Class II)", "ELA-DRA", "Medium", "Equus caballus, Mus musculus, Rattus norvegicus", "ELA-DRA variants influence equine MHC class II antigen presentation, affecting susceptibility to recurrent airway obstruction (heaves), equine infectious anemia, and immune-mediated conditions. Annual respiratory and immune health evaluation is recommended; ELA typing informs equine transplantation and vaccination strategy planning.", "Encodes the alpha chain of equine MHC class II (DRA), involved in presenting extracellular antigens to CD4+ T cells and mediating adaptive immunity in horses."),
    makeMarker("Feline Leukocyte Antigen DRB (MHC Class II)", "FLA-DRB", "Medium", "Felis catus, Mus musculus, Rattus norvegicus", "FLA-DRB haplotypes influence feline susceptibility to immune-mediated diseases and feline infectious peritonitis (FIP) outcomes. Annual health screening including CBC and serum protein electrophoresis is recommended in cats with susceptible haplotypes; FIP prevention strategies should be optimized based on FLA typing.", "Encodes the beta chain of feline MHC class II (DR), essential for adaptive immune responses in cats by presenting antigens to CD4+ T helper cells."),
    makeMarker("Feline Leukocyte Antigen E (MHC Class I)", "FLA-E", "Medium", "Felis catus, Mus musculus, Rattus norvegicus", "FLA-E variants affect MHC class I-mediated cytotoxic immunity in cats, influencing resistance to retroviruses (FeLV, FIV) and susceptibility to immune-mediated pathology. Annual FeLV/FIV status monitoring and lymphocyte subset analysis are recommended; relevant to blood and organ transplantation compatibility in feline patients.", "Encodes an MHC class I molecule in cats, responsible for presenting intracellular peptides to CD8+ cytotoxic T cells and mediating antiviral immunity."),
    makeMarker("Forkhead Box N1 (Nude Gene)", "FOXN1", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio, Felis catus", "FOXN1 loss-of-function causes nude/SCID syndrome — complete thymic aplasia with absent T cell development, severe combined immunodeficiency, and alopecia. Strict barrier nursing, prophylactic antimicrobials, and immunoglobulin replacement are essential; hematopoietic stem cell transplantation is the only curative option.", "Encodes a transcription factor essential for thymic epithelial cell development and differentiation. Homozygous loss causes the 'nude' phenotype with thymic aplasia, T cell deficiency, and hairlessness."),
    makeMarker("Interferon Alpha", "IFNA", "Medium", "Homo sapiens, Felis catus, Canis lupus familiaris, Bos taurus, Mus musculus, Danio rerio, Rattus norvegicus", "IFNA variants alter type I interferon antiviral signaling, modifying innate immune responsiveness to viral pathogens and susceptibility to systemic lupus erythematosus-like interferonopathies. Annual viral serology and ANA/anti-dsDNA antibody screening are recommended in genetically susceptible individuals.", "Encodes interferon-alpha, a type I interferon cytokine produced by plasmacytoid dendritic cells and other innate immune cells in response to viral infections."),
    makeMarker("Interleukin 1 Beta", "IL-1β", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Sus scrofa, Rattus norvegicus, Danio rerio", "IL-1β variants alter pro-inflammatory cytokine production, predisposing to heightened systemic inflammatory responses, periodontal disease severity, and autoinflammatory syndromes. Annual inflammatory marker monitoring (CRP, SAA) and dental health assessment are recommended; IL-1β genotype is relevant to NSAID and biologic therapy planning.", "Encodes interleukin-1 beta, a key pro-inflammatory cytokine produced by macrophages and monocytes that mediates acute phase responses, fever, and tissue damage."),
    makeMarker("Interleukin 6 (alternate entry)", "IL-6", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Sus scrofa, Bos taurus, Danio rerio, Rattus norvegicus", "IL-6 variants modify systemic inflammatory signaling with pleiotropic effects on acute phase response intensity, bone metabolism, and metabolic syndrome risk. Annual CRP, SAA, and metabolic panel monitoring are recommended; IL-6 pathway inhibitors (tocilizumab equivalents) are increasingly available in veterinary oncology and immune-mediated disease management.", "Encodes interleukin-6, a pleiotropic cytokine mediating acute phase responses, inflammation, hematopoiesis, and metabolic regulation. A major driver of the cytokine storm in sepsis."),
    makeMarker("Interleukin 8 (CXCL8)", "IL-8", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Sus scrofa, Bos taurus, Danio rerio, Rattus norvegicus", "IL-8 (CXCL8) variants alter neutrophil chemotaxis intensity, influencing severity of local inflammatory responses, wound healing rates, and bacterial infection outcomes. Annual CBC with differential and inflammatory biomarker assessment are recommended; relevant to managing chronic wound healing and skin infection susceptibility.", "Encodes CXCL8, a chemokine that recruits and activates neutrophils at sites of inflammation and infection. A key mediator of the acute inflammatory response."),
    makeMarker("Interleukin 12 Subunit Beta", "IL12B", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Bos taurus, Danio rerio, Rattus norvegicus", "IL12B variants impair IL-12/IL-23-mediated Th1/Th17 immune polarization, predisposing to mycobacterial and Salmonella infections and susceptibility to intracellular pathogens. Annual CBC, routine microbiological surveillance, and skin testing for mycobacterial exposure are recommended in affected individuals.", "Encodes the p40 subunit shared by interleukins IL-12 and IL-23, cytokines that drive Th1 and Th17 immune responses and mediate resistance to intracellular pathogens."),
    makeMarker("Interleukin 17A", "IL17A", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Bos taurus, Danio rerio, Rattus norvegicus", "IL17A high-expression variants increase neutrophilic inflammation, predisposing to inflammatory skin disease, psoriasiform conditions, and inflammatory bowel disease. Annual dermatological and gastrointestinal examination are recommended; IL-17A pathway inhibitors are emerging in veterinary dermatology.", "Encodes interleukin-17A, a pro-inflammatory cytokine produced by Th17 cells that activates neutrophil recruitment and promotes inflammation in skin, gut, and joints."),
    makeMarker("Interleukin 4 Receptor Subunit Alpha", "IL4RA", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "IL4RA gain-of-function variants are a major driver of atopic dermatitis and allergic disease severity in dogs and humans. Annual skin examination for pruritus, alopecia, and otitis is recommended; dupilumab/lokivetmab (anti-IL-4Rα) is now a frontline targeted therapy for atopic dermatitis in carrier individuals.", "Encodes the alpha chain of the IL-4 receptor, a key component of both IL-4 and IL-13 receptor complexes that drive Th2 immune responses and IgE production underlying allergic diseases."),
    makeMarker("Interleukin 6", "IL6", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Sus scrofa, Bos taurus, Danio rerio, Rattus norvegicus", "IL6 promoter variants that increase basal transcription are associated with chronic inflammatory conditions, systemic inflammatory response syndrome, and cancer cachexia. Annual serum CRP and albumin monitoring are recommended; IL-6 pathway status informs prognosis and management of inflammatory conditions.", "Encodes interleukin-6; see also IL-6 entry. Duplicate entry reflecting alternate gene notation used across species databases."),
    makeMarker("Major Histocompatibility Complex (generic locus)", "MHC", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Equus caballus, Bos taurus, Gallus gallus, Danio rerio, Mus musculus", "MHC haplotype diversity is the primary determinant of immune response breadth, transplantation compatibility, and susceptibility to immune-mediated diseases across all vertebrate species. MHC typing is essential before transplantation, blood transfusion in sensitized patients, and for breeding program diversity assessment in managed or endangered populations.", "Generic locus reference for the Major Histocompatibility Complex, the most polymorphic gene region in vertebrates. Encodes cell surface glycoproteins (class I and II) that present antigens to T lymphocytes."),
    makeMarker("Protein Kinase DNA-Activated Catalytic Subunit", "PRKDC", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "PRKDC loss-of-function causes severe combined immunodeficiency (SCID) — absent T and B lymphocytes with profound susceptibility to all infections. Strict barrier nursing and prophylactic antimicrobial therapy are essential from birth; hematopoietic stem cell transplantation is the only curative intervention.", "Encodes the catalytic subunit of DNA-dependent protein kinase (DNA-PKcs), essential for V(D)J recombination during lymphocyte development and DNA double-strand break repair."),
    makeMarker("Transferrin (Ovotransferrin in birds)", "TF (Ovotransferrin)", "Medium", "Gallus gallus, Anas platyrhynchos, Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "Ovotransferrin (conalbumin) variants affect iron sequestration-based innate antimicrobial defense in avian species. Annual assessment of egg quality parameters and hatchability is recommended in affected flocks; relevant to biosecurity protocols where iron sequestration is a key antimicrobial mechanism.", "Encodes ovotransferrin (conalbumin) in birds, a transferrin homolog with iron-binding antimicrobial properties in egg white, and a component of innate immunity in avian species."),
    makeMarker("Toll-Like Receptor 3", "TLR3", "Medium", "Homo sapiens, Canis lupus familiaris, Bos taurus, Gallus gallus, Mus musculus, Danio rerio, Rattus norvegicus", "TLR3 variants impair double-stranded RNA innate immune sensing, predisposing to viral encephalitis and herpesvirus susceptibility. Annual neurological examination and serum viral screening are recommended; prophylactic antiviral protocols and vaccination optimization are important for carrier individuals in high-risk environments.", "Encodes Toll-like receptor 3, a pattern recognition receptor that senses double-stranded RNA (viral replication intermediate) and activates antiviral innate immune responses."),
    makeMarker("Toll-Like Receptor 7", "TLR7", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Sus scrofa, Bos taurus, Danio rerio, Rattus norvegicus", "TLR7 gain-of-function variants cause lupus-like systemic autoimmunity through excessive sensing of self-RNA. Annual ANA, anti-dsDNA, and complete blood count monitoring are recommended; TLR7 variants are relevant to biologics targeting the TLR7/TLR9 pathway in autoimmune disease management.", "Encodes Toll-like receptor 7, a pattern recognition receptor in endosomes that senses single-stranded viral RNA and activates type I interferon production."),
    makeMarker("Tumor Necrosis Factor", "TNF", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Sus scrofa, Bos taurus, Danio rerio, Rattus norvegicus", "TNF promoter high-expression variants potentiate systemic inflammatory responses, contributing to sepsis susceptibility, inflammatory bowel disease, and immune-mediated polyarthritis. Annual inflammatory biomarker assessment (CRP, SAA) and joint mobility assessment are recommended; TNF-inhibitor biologics are available in veterinary medicine for refractory cases.", "Encodes tumor necrosis factor-alpha, a key pro-inflammatory cytokine produced by macrophages and T cells that mediates inflammation, apoptosis, and immune cell activation."),
    makeMarker("Toll-Like Receptor 4", "TLR4", "Medium", "Homo sapiens, Canis lupus familiaris, Bos taurus, Sus scrofa, Gallus gallus, Mus musculus, Danio rerio, Rattus norvegicus", "TLR4 variants alter lipopolysaccharide sensing and endotoxin-driven inflammatory signaling, modifying mastitis susceptibility in dairy cattle, septic shock outcomes, and inflammatory bowel disease risk. Annual evaluation for signs of recurring bacterial infections and inflammatory disease is recommended; TLR4 status informs probiotic and antibiotic prophylaxis strategy selection.", "Encodes Toll-like receptor 4, a pattern recognition receptor that senses lipopolysaccharide (LPS) from gram-negative bacteria and activates NF-kB-driven inflammatory responses."),
    makeMarker("MHC Class I B (Avian)", "MHC-B", "Medium", "Gallus gallus, Meleagris gallopavo, Mus musculus, Rattus norvegicus", "MHC-B haplotypes in poultry are among the strongest genetic determinants of Marek's disease virus resistance. B21 haplotype confers strong resistance; B19 confers susceptibility. MHC-B genotyping is recommended for selection in Marek's disease-endemic flocks; vaccination efficacy may vary by haplotype.", "Encodes the chicken MHC class I B locus; one of the strongest genetic determinants of Marek's disease virus resistance and susceptibility in poultry."),
    makeMarker("Interferon Gamma", "IFNG", "Medium", "Homo sapiens, Canis lupus familiaris, Bos taurus, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "IFNG variants reduce Th1-mediated macrophage activation and intracellular pathogen killing capacity, predisposing to mycobacterial, Leishmania, and other intracellular infections. Annual Leishmania serology (in endemic regions), Johne's disease testing in cattle, and tuberculosis surveillance are recommended for carrier animals.", "Encodes interferon-gamma, the sole type II interferon, produced by NK cells and T cells. Critical for macrophage activation, Th1 immune polarization, and resistance to intracellular pathogens."),
    makeMarker("CRISPR-Associated Protein 9 (immune defense gene analog)", "CRISPR-CAS9", "Low", "Streptococcus pyogenes, Staphylococcus aureus, Homo sapiens (therapeutic use), Mus musculus, Danio rerio", "CRISPR-Cas9 is informational in this panel context — representing bacterial immune defense against bacteriophage. Its primary current relevance is as a therapeutic gene-editing tool; CRISPR-based therapies are entering clinical and veterinary trial phases for monogenic inherited conditions.", "Bacterial adaptive immune defense system using guide RNA-directed Cas9 nuclease to cleave foreign DNA; the Cas9 endonuclease has been repurposed as the most widely used gene-editing tool in molecular biology."),
    makeMarker("Recombination Activating Gene 1", "RAG1", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "RAG1 loss-of-function causes Omenn syndrome or T-B-NK+ SCID — complete failure of V(D)J recombination with absent T and B cells and life-threatening immunodeficiency. Strict barrier isolation, prophylactic antimicrobials, immunoglobulin replacement, and expedited hematopoietic stem cell transplantation referral are required from birth.", "Encodes RAG1, a component of the RAG recombinase essential for V(D)J recombination in developing T and B lymphocytes. Required for immunoglobulin and T cell receptor gene assembly."),
    makeMarker("MX Dynamin Like GTPase 1 (Interferon-Induced)", "MX1", "Medium", "Homo sapiens, Mus musculus, Sus scrofa, Gallus gallus, Danio rerio, Rattus norvegicus", "MX1 variants alter interferon-induced antiviral GTPase activity, modifying innate resistance to influenza, rhabdoviruses, and other RNA viruses. Vaccination efficacy against influenza-like viruses may be reduced in low-activity MX1 carriers; relevant to poultry biosecurity and influenza risk management in susceptible species.", "Encodes MX1, an interferon-stimulated GTPase with broad antiviral activity particularly against influenza virus and other negative-strand RNA viruses."),
    makeMarker("Down Syndrome Cell Adhesion Molecule", "DSCAM", "Medium", "Drosophila melanogaster, Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "DSCAM variants affect axon guidance and pattern recognition receptor diversity in innate immunity, particularly relevant to arthropod immune diversity against parasites. In mammals, monitor for neurological and immune developmental anomalies; copy number changes in the chromosome 21 region are associated with Down syndrome immune phenotypes.", "Encodes Down syndrome cell adhesion molecule, a member of the immunoglobulin superfamily with roles in neuronal wiring and, in invertebrates, as a highly diverse immune recognition receptor."),
  ]},
  { id: "longevity", name: "Longevity", color: "#7C3AED", markers: [
    makeMarker("Reactive Oxygen Species Modulator 1", "ROMO1", "Low", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio, Caenorhabditis elegans", "ROMO1 variants modulate mitochondrial reactive oxygen species production, influencing oxidative stress burden and cellular aging rate. Informational; antioxidant-rich diet and regular evaluation of metabolic and organ function are reasonable supportive measures for aging individuals carrying high-ROS alleles.", "Encodes a mitochondrial inner membrane protein that modulates reactive oxygen species production; regulates mitochondrial morphology and contributes to cellular oxidative stress."),
    makeMarker("Telomerase Reverse Transcriptase", "TERT", "Low", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "TERT variants alter telomerase activity, influencing both cancer susceptibility and replicative lifespan across tissues. Informational; annual CBC and cancer screening are advisable for aging individuals; relevant to understanding longevity breed differences and linking telomere length to disease risk in companion animals.", "Encodes the catalytic reverse transcriptase subunit of telomerase, an enzyme that maintains telomere length and enables continued cell division in stem cells and cancer cells."),
    makeMarker("Sirtuin 1 (NAD-Dependent Deacetylase)", "SIRT1", "Low", "Homo sapiens, Mus musculus, Caenorhabditis elegans, Danio rerio, Rattus norvegicus", "SIRT1 variants affect NAD+-dependent deacetylase activity regulating metabolic adaptation, stress resilience, and genome maintenance. Caloric moderation and regular exercise are expected to be most beneficial for low-activity SIRT1 carriers; metabolic health monitoring (glucose, lipids, liver enzymes) is advisable.", "Encodes Sirtuin-1, a NAD+-dependent protein deacetylase that regulates metabolism, stress responses, genome stability, and aging through deacetylation of key substrates including p53, FOXO, and PGC-1α."),
    makeMarker("Dauer Formation (C. elegans) / IGF1R Homolog", "DAF-2", "Low", "Caenorhabditis elegans, Drosophila melanogaster, Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "DAF-2 (IGF-1R homolog) reduced-function variants extend lifespan through FOXO/DAF-16 transcription factor activation of stress resistance and autophagy programs. Informational; caloric restriction and reduced-glycemic diets are expected to recapitulate partial DAF-2 pathway inhibition benefits; metabolic monitoring is advisable.", "C. elegans insulin/IGF-1 receptor homolog; reduced DAF-2 signaling dramatically extends lifespan through activation of the FOXO transcription factor DAF-16."),
  ]},
  { id: "metabolism", name: "Metabolism", color: "#D97706", markers: [
    makeMarker("Acetyl-CoA Carboxylase Alpha", "ACACA", "Medium", "Homo sapiens, Canis lupus familiaris, Bos taurus, Sus scrofa, Mus musculus, Danio rerio, Rattus norvegicus", "ACACA variants alter the rate-limiting step of de novo fatty acid synthesis, predisposing to dyslipidemia, hepatic steatosis, and obesity. Annual fasting lipid profile and hepatic enzyme monitoring are recommended; dietary fat management and energy intake restriction are primary interventions.", "Encodes acetyl-CoA carboxylase alpha, the rate-limiting enzyme in fatty acid biosynthesis that carboxylates acetyl-CoA to malonyl-CoA."),
    makeMarker("Aminocarboxymuconate Semialdehyde Decarboxylase", "ACMSD", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "ACMSD variants alter tryptophan catabolism flux through the kynurenine pathway vs. NAD+ synthesis, influencing neuroinflammatory tone and metabolic NAD+ availability. Informational; tryptophan-adequate diet and periodic liver and kidney function monitoring are advisable.", "Encodes the enzyme that decarboxylates aminocarboxymuconate semialdehyde in tryptophan catabolism, diverting metabolic flux away from NAD+ synthesis."),
    makeMarker("Adiponectin", "ADIPOQ", "Medium", "Homo sapiens, Canis lupus familiaris, Equus caballus, Mus musculus, Rattus norvegicus, Danio rerio", "ADIPOQ low-expression variants reduce insulin-sensitizing adiponectin signaling, predisposing to insulin resistance, obesity, and equine metabolic syndrome. Annual fasting insulin, glucose, and body condition score assessment are recommended; dietary management and controlled exercise are primary interventions.", "Encodes adiponectin, an adipokine secreted by adipose tissue that promotes insulin sensitivity, fatty acid oxidation, and anti-inflammatory signaling."),
    makeMarker("Alstrom Syndrome Protein 1", "ALMS1", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "ALMS1 biallelic variants cause Alström syndrome — cone-rod dystrophy, sensorineural hearing loss, dilated cardiomyopathy, and obesity-associated insulin resistance. Ophthalmic ERG testing, audiometry, echocardiography, and metabolic screening are all recommended in affected individuals; multisystem longitudinal monitoring is essential.", "Encodes the Alström syndrome protein, a centrosomal and ciliary protein. Loss causes a multisystem ciliopathy affecting eyes, ears, heart, liver, and metabolic function."),
    makeMarker("Argininosuccinate Synthase 1", "ASS1", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "ASS1 loss-of-function causes citrullinemia type I — toxic ammonia and citrulline accumulation causing hyperammonemic encephalopathy. Ammonia and amino acid monitoring are essential; low-protein diet with arginine supplementation and ammonia-scavenging therapy are required from diagnosis.", "Encodes argininosuccinate synthase, the third enzyme of the urea cycle that condenses citrulline and aspartate to form argininosuccinate. Deficiency causes citrullinemia."),
    makeMarker("ATPase Copper Transporting Alpha", "ATP7A", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "ATP7A loss-of-function causes Menkes disease — severe copper deficiency with kinky hair, neurodegeneration, and connective tissue failure from impaired copper efflux from intestinal cells. Serum copper, ceruloplasmin, and neurological assessment are essential; copper-histidinate infusions initiated early may slow progression.", "Encodes a copper-transporting P-type ATPase required for intestinal copper absorption and trans-placental copper transfer. Deficiency causes Menkes disease."),
    makeMarker("Agouti-Related Protein", "AgRP", "Medium", "Canis lupus familiaris, Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "AgRP high-expression variants increase orexigenic neuropeptide Y/AgRP neuron activity, predisposing to hyperphagia, obesity, and metabolic syndrome. Annual body condition score, fasting glucose, and lipid panel assessment are recommended; caloric restriction and structured feeding schedules are the primary management approach.", "Encodes agouti-related protein, an endogenous inverse agonist at melanocortin receptors (MC3R and MC4R) produced by hypothalamic neurons. A potent orexigenic factor that promotes food intake."),
    makeMarker("Cystathionine Beta-Synthase", "CBS", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "CBS loss-of-function causes homocystinuria — elevated homocysteine with lens ectopia, skeletal overgrowth, intellectual disability, and thromboembolic risk. Annual serum homocysteine, folic acid, and B12 monitoring are recommended; pyridoxine (B6) responsiveness should be tested; methionine-restricted diet with B6/B12/folate supplementation is essential.", "Encodes cystathionine beta-synthase, an enzyme in the transsulfuration pathway that converts homocysteine and serine to cystathionine. Deficiency causes homocystinuria."),
    makeMarker("CD36 Molecule (Fatty Acid Translocase)", "CD36", "Medium", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Danio rerio, Rattus norvegicus", "CD36 variants affect long-chain fatty acid uptake into cardiomyocytes and other tissues, influencing susceptibility to hypertrophic cardiomyopathy, insulin resistance, and platelet hyperreactivity. Annual fasting lipid profile, echocardiography, and insulin sensitivity evaluation are recommended in carrier animals.", "Encodes CD36, a multifunctional membrane glycoprotein that mediates fatty acid transport, oxidized LDL uptake by macrophages, thrombospondin signaling, and platelet adhesion."),
    makeMarker("Cysteine Dioxygenase Type 1", "CDO1", "Medium", "Homo sapiens, Felis catus, Mus musculus, Rattus norvegicus, Danio rerio", "CDO1 variants affect cysteine catabolism rate, with particular relevance to taurine biosynthesis in cats — a species unable to synthesize sufficient taurine independently. Annual taurine measurement and dietary taurine supplementation are essential in cats; dilated cardiomyopathy screening should be performed in cats with confirmed taurine deficiency.", "Encodes cysteine dioxygenase type 1, a key enzyme in cysteine catabolism producing hypotaurine and eventually taurine. Essential for taurine synthesis, particularly important in cats."),
    makeMarker("CCAAT/Enhancer Binding Protein Alpha", "CEBPA", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "CEBPA variants impair neutrophil and hepatocyte differentiation, causing acute myeloid leukemia in humans and dogs. Annual CBC with differential and liver function tests are recommended for germline carrier animals; cytogenetic evaluation is required if evolving cytopenias or blast cells are detected.", "Encodes C/EBP alpha, a bZIP transcription factor essential for granulocyte differentiation, liver function, and adipogenesis. Mutations are among the most common drivers of acute myeloid leukemia."),
    makeMarker("Cytochrome C Oxidase Subunit I (Mitochondrial)", "COI", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "COI variants affect the rate-limiting complex IV step of mitochondrial oxidative phosphorylation, impairing ATP production in high-energy tissues. Annual serum lactate, complete blood count, and liver and kidney function monitoring are recommended; mitochondrial supplement protocols (CoQ10, B vitamins) may be supportive.", "Encodes cytochrome c oxidase subunit I, the catalytic core of mitochondrial Complex IV (cytochrome c oxidase), the final enzyme of the mitochondrial electron transport chain."),
    makeMarker("Cysteine Sulfinic Acid Decarboxylase", "CSAD", "Medium", "Homo sapiens, Felis catus, Mus musculus, Rattus norvegicus, Danio rerio", "CSAD variants reduce taurine biosynthesis capacity, with dietary taurine deficiency causing dilated cardiomyopathy and reproductive failure in cats and dogs. Annual taurine level measurement, echocardiography, and dietary taurine adequacy assessment are recommended; taurine supplementation is indicated when levels are subnormal.", "Encodes the enzyme that decarboxylates cysteine sulfinic acid to hypotaurine in the taurine biosynthesis pathway. Important for taurine production in species with limited dietary sources."),
    makeMarker("Elongation Of Very Long Chain Fatty Acids 2", "ELOVL2", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "ELOVL2 variants impair very long-chain polyunsaturated fatty acid (VLC-PUFA) elongation needed for retinal and spermatogenic function. Annual ophthalmic examination and electroretinography are recommended; semen quality analysis is advisable in breeding males; dietary omega-3 supplementation (EPA/DHA) may be beneficial.", "Encodes a fatty acid elongase catalyzing the elongation of C20-C22 polyunsaturated fatty acids to very long-chain PUFA (C24-C26). Essential for retinal and testicular function."),
    makeMarker("Elongation Of Very Long Chain Fatty Acids 5", "ELOVL5", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "ELOVL5 variants impair elongation of omega-6 and omega-3 fatty acids toward arachidonic acid and EPA/DHA respectively, predisposing to essential fatty acid deficiency, inflammatory skin disease, and hepatic steatosis. Annual skin assessment, liver enzymes, and dietary EFA adequacy evaluation are recommended.", "Encodes a fatty acid elongase that extends C18 and C20 polyunsaturated fatty acids, important for maintaining the balance of omega-6 and omega-3 fatty acids in tissues."),
    makeMarker("Fatty Acid Binding Protein 4 (Adipocyte)", "FABP4", "Medium", "Homo sapiens, Canis lupus familiaris, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "FABP4 variants alter intracellular fatty acid trafficking in adipocytes and macrophages, influencing insulin resistance, atherosclerosis risk, and adipose inflammation. Annual fasting glucose, insulin, lipid panel, and body condition score monitoring are recommended; relevant to metabolic syndrome management in equine and canine patients.", "Encodes fatty acid binding protein 4 (FABP4/aP2), an intracellular lipid chaperone expressed in adipocytes and macrophages that regulates fatty acid metabolism and insulin signaling."),
    makeMarker("Fatty Acid Desaturase 1", "FADS1", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "FADS1 reduced-activity variants impair delta-5 desaturation of DGLA to arachidonic acid and EPA to DHA, reducing membrane PUFA composition and anti-inflammatory eicosanoid availability. Annual assessment of dietary EFA adequacy and inflammatory disease burden is recommended; direct arachidonic acid and EPA/DHA supplementation may bypass the desaturation bottleneck.", "Encodes fatty acid desaturase 1 (delta-5 desaturase), which catalyzes the final desaturation step in long-chain PUFA biosynthesis, converting DGLA to arachidonic acid and EPA to EPA."),
    makeMarker("Fatty Acid Desaturase 2", "FADS2", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "FADS2 reduced-activity variants impair delta-6 desaturation — the first and rate-limiting step converting linoleic acid (LA) and alpha-linolenic acid (ALA) to longer-chain PUFAs. Cats with limited FADS2 activity cannot synthesize arachidonic acid from LA, requiring dietary arachidonate; annual EFA status and skin health assessment are recommended.", "Encodes fatty acid desaturase 2 (delta-6 desaturase), the rate-limiting enzyme initiating PUFA elongation from essential fatty acids LA and ALA. Cats have limited delta-6 desaturase activity."),
    makeMarker("Fatty Acid Synthase", "FASN", "Medium", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Bos taurus, Mus musculus, Danio rerio, Rattus norvegicus", "FASN overexpression variants drive de novo lipogenesis and are associated with hepatic steatosis, obesity, and cancer cell metabolic reprogramming. Annual liver enzyme and lipid panel assessment are recommended; FASN inhibitors are in development for metabolic and oncological applications.", "Encodes fatty acid synthase, a multifunctional enzyme that synthesizes palmitate from acetyl-CoA and malonyl-CoA. A key enzyme in de novo lipogenesis."),
    makeMarker("Fibroblast Growth Factor 21", "FGF21", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "FGF21 variants alter hepatokine signaling that regulates lipid oxidation, glucose uptake, and energy expenditure, predisposing to dyslipidemia and metabolic syndrome. Annual fasting glucose, insulin, and lipid panel monitoring are recommended; FGF21 analogue therapies are in development for metabolic disease.", "Encodes fibroblast growth factor 21, a hepatokine and adipokine that regulates fatty acid oxidation, glucose uptake, and energy metabolism. A key metabolic hormone with therapeutic potential."),
    makeMarker("Ferritin Heavy Chain 1", "FTH1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "FTH1 variants affect iron storage and reactive oxygen species detoxification capacity in ferritin. Annual serum ferritin, CBC, and liver enzyme monitoring are recommended; hyperferritinemia should prompt evaluation for hereditary hyperferritinemia-cataract syndrome (autosomal dominant IRE mutation) vs. inflammatory causes.", "Encodes ferritin heavy chain, the catalytic subunit of ferritin that oxidizes Fe2+ to Fe3+ for safe iron storage. Essential for cellular iron homeostasis and protection against oxidative damage."),
    makeMarker("Glycogen Branching Enzyme", "GBE1", "High", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "GBE1 loss-of-function causes glycogen storage disease type IV (Andersen disease) — progressive hepatic cirrhosis and neuromuscular weakness from accumulation of unbranched glycogen. Annual liver function tests, muscle enzyme assays (CK), and echocardiography are recommended; liver transplantation is the only definitive therapy.", "Encodes glycogen branching enzyme, which creates branch points in the glycogen molecule by transferring glucosyl units to a new location on the polysaccharide chain."),
    makeMarker("GTP Cyclohydrolase 1", "GCH1", "Medium", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "GCH1 loss-of-function variants reduce BH4 (tetrahydrobiopterin) synthesis, impairing nitric oxide production, catecholamine biosynthesis, and pain regulation. Neurological assessment and urine neurotransmitter metabolite testing are recommended; BH4 (sapropterin) supplementation may be indicated for confirmed deficiency.", "Encodes GTP cyclohydrolase 1, the rate-limiting enzyme in tetrahydrobiopterin (BH4) biosynthesis. BH4 is an essential cofactor for aromatic amino acid hydroxylases, nitric oxide synthases, and pain."),
    makeMarker("Glucokinase", "GCK", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "GCK variants cause MODY type 2 (maturity-onset diabetes of the young) — mild stable fasting hyperglycemia from impaired pancreatic glucose sensing. Annual fasting glucose monitoring is recommended; GCK-MODY typically does not require pharmacological treatment, distinguishing it from type 2 diabetes requiring active management.", "Encodes glucokinase (hexokinase IV), the primary glucose sensor in pancreatic beta cells that triggers insulin secretion when blood glucose rises. Also regulates hepatic glycogen synthesis."),
    makeMarker("Glucokinase Regulator", "GCKR", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "GCKR variants affect glucokinase regulatory protein function, altering hepatic glucose uptake and triglyceride synthesis trade-offs. Annual fasting triglycerides and glucose monitoring are recommended; carriers may show elevated triglycerides despite normal glucose — a phenotype warranting dietary fat and carbohydrate management.", "Encodes the glucokinase regulatory protein, which inhibits hepatic glucokinase when fasting and releases it for glucose uptake after meals. Variants affect the balance between glucose and lipid metabolism."),
    makeMarker("Ghrelin And Obestatin Prepropeptide", "GHRL", "Medium", "Homo sapiens, Canis lupus familiaris, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "GHRL high-expression variants increase the primary hunger hormone ghrelin, predisposing to hyperphagia, obesity, and metabolic syndrome. Annual body condition score monitoring and fasting ghrelin measurement are recommended; structured meal timing (frequent small meals) may partially suppress ghrelin elevations.", "Encodes ghrelin, the primary hunger hormone produced by gastric X/A cells that stimulates appetite, promotes fat storage, and regulates energy balance via hypothalamic GHS-R signaling."),
    makeMarker("Growth Hormone Secretagogue Receptor", "GHSR", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "GHSR variants alter ghrelin receptor sensitivity and downstream orexigenic signaling, influencing appetite regulation and growth hormone pulse amplitude. Annual body weight monitoring, fasting ghrelin levels, and GH-axis assessment are recommended; GHSR antagonists are in development for obesity management.", "Encodes the growth hormone secretagogue receptor (ghrelin receptor), a constitutively active GPCR that mediates ghrelin's orexigenic effects and regulates growth hormone secretion."),
    makeMarker("Galactosidase Beta 1", "GLB1", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "GLB1 loss-of-function causes GM1 gangliosidosis — progressive neurodegeneration from ganglioside accumulation in lysosomes, with cerebellar ataxia and intellectual decline. Annual neurological examination including gait analysis, electrophysiology, and CSF evaluation are recommended; genetic carrier testing before breeding is strongly advised.", "Encodes lysosomal acid beta-galactosidase, which degrades GM1 ganglioside and other substrates. Deficiency causes GM1 gangliosidosis, a progressive lysosomal storage disorder."),
    makeMarker("Glucagon-Like Peptide 1 Receptor", "GLP1R", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "GLP1R variants affect incretin receptor responsiveness to GLP-1, influencing post-prandial insulin secretion efficiency and satiety signaling. Annual fasting and post-prandial glucose monitoring are recommended; GLP1R genotype may predict responsiveness to GLP-1 receptor agonist therapies (semaglutide, liraglutide class).", "Encodes the glucagon-like peptide-1 receptor, expressed in pancreatic beta cells, brain, and gut, mediating the insulinotropic and anorectic effects of GLP-1. Target of major diabetes and obesity drugs."),
    makeMarker("Glucose Transporter 1 (SLC2A1)", "GLUT1", "High", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "GLUT1 haploinsufficiency causes GLUT1 deficiency syndrome — impaired glucose entry into the CNS producing epilepsy, intellectual disability, and movement disorders. Annual neurological evaluation and CSF glucose measurement are recommended; ketogenic diet is the primary therapeutic intervention and must be initiated early.", "Encodes glucose transporter 1 (GLUT1/SLC2A1), the primary glucose transporter at the blood-brain barrier and in erythrocytes, mediating basal glucose transport into the central nervous system."),
    makeMarker("Glucose Transporter 12 (SLC2A12)", "GLUT12", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "GLUT12 variants affect insulin-responsive glucose transport in skeletal muscle and adipose tissue, contributing to insulin resistance in metabolic syndrome. Annual fasting insulin, glucose, and body condition assessment are recommended; exercise and dietary intervention are the primary management strategies.", "Encodes glucose transporter 12 (GLUT12/SLC2A12), an insulin-responsive glucose transporter expressed in skeletal muscle, adipose tissue, and small intestine."),
    makeMarker("Glucose Transporter 2 (SLC2A2)", "GLUT2", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "GLUT2 variants impair pancreatic beta cell glucose sensing and hepatic glucose uptake, causing Fanconi-Bickel glycogen storage disease in severe cases. Annual fasting glucose, urinalysis (glucosuria), and liver enzyme assessment are recommended; dietary glucose management and monitoring of hepatic glycogen accumulation are important.", "Encodes glucose transporter 2 (GLUT2/SLC2A2), a low-affinity, high-capacity glucose transporter in pancreatic beta cells and hepatocytes that acts as a glucose sensor."),
    makeMarker("Glucose Transporter 4 (SLC2A4)", "GLUT4", "Medium", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Danio rerio, Rattus norvegicus", "GLUT4 reduced-expression variants impair insulin-stimulated glucose uptake in skeletal muscle and adipose tissue, predisposing to insulin resistance and type 2 diabetes mellitus. Annual fasting insulin, glucose, body condition score monitoring, and exercise assessment are recommended; regular aerobic exercise upregulates GLUT4 expression.", "Encodes glucose transporter 4 (GLUT4/SLC2A4), the primary insulin-responsive glucose transporter in skeletal muscle and adipose tissue. Translocation to the cell surface is stimulated by insulin."),
    makeMarker("Glucuronidase Beta", "GUSB", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "GUSB loss-of-function causes mucopolysaccharidosis type VII (Sly disease) — progressive GAG accumulation in lysosomes producing skeletal dysplasia, intellectual disability, and multi-organ dysfunction. Annual skeletal radiographs, urine GAG measurement, and echocardiography are recommended; enzyme replacement therapy is available for human patients.", "Encodes lysosomal beta-glucuronidase, which degrades glycosaminoglycans (GAGs). Deficiency causes MPS type VII, a lysosomal storage disorder."),
    makeMarker("Glycogen Synthase 1 (Muscle)", "GYS1", "High", "Homo sapiens, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "GYS1 gain-of-function variants cause muscle glycogen storage disease (glycogen branching enzyme-related polysaccharide storage myopathy in horses). Annual serum CK, muscle biopsy in affected individuals, and exercise intolerance assessment are recommended; low-starch, high-fat diets are the primary management strategy in equine cases.", "Encodes the muscle isoform of glycogen synthase, the enzyme responsible for extending glycogen chains by adding UDP-glucose units. Regulated by insulin and exercise."),
    makeMarker("Hepcidin Antimicrobial Peptide", "HAMP", "Medium", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus, Canis lupus familiaris", "HAMP variants alter hepcidin production, the master regulator of systemic iron homeostasis, causing hereditary hemochromatosis (low hepcidin) or iron-refractory iron deficiency anemia (high hepcidin). Annual serum ferritin, transferrin saturation, and CBC monitoring are recommended; distinguishing high vs. low hepcidin-associated conditions directs treatment.", "Encodes hepcidin, the master regulatory hormone of systemic iron homeostasis that binds ferroportin to inhibit iron absorption and recycling."),
    makeMarker("Iduronidase Alpha-L", "IDUA", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "IDUA loss-of-function causes mucopolysaccharidosis type I (Hurler, Hurler-Scheie, or Scheie syndromes) — progressive GAG accumulation producing skeletal dysplasia, corneal clouding, cardiac valve disease, and intellectual disability. Annual ophthalmological, cardiac, and skeletal assessment are essential; enzyme replacement therapy (laronidase) and hematopoietic stem cell transplantation are established treatments.", "Encodes alpha-L-iduronidase, a lysosomal enzyme that degrades heparan sulfate and dermatan sulfate glycosaminoglycans. Deficiency causes MPS type I."),
    makeMarker("Insulin Receptor", "INSR", "High", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Danio rerio, Rattus norvegicus", "INSR loss-of-function variants cause severe insulin resistance syndromes (Rabson-Mendenhall syndrome, Donohue syndrome) with extreme hyperinsulinemia and growth abnormalities. Annual fasting glucose, insulin, and IGF-1 monitoring are essential; metabolic management is challenging and requires specialist endocrine consultation.", "Encodes the insulin receptor, a receptor tyrosine kinase that mediates insulin's metabolic effects on glucose uptake, glycogen synthesis, protein synthesis, and lipogenesis."),
    makeMarker("Ketohexokinase (Fructokinase)", "KHK", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "KHK variants impair hepatic fructose catabolism, causing either benign fructosuria (loss-of-function) or increased susceptibility to fructose-induced metabolic dysfunction. Annual fasting uric acid and liver function testing are recommended; dietary fructose restriction is advisable for individuals with high-activity KHK variants.", "Encodes ketohexokinase (fructokinase), the primary enzyme initiating hepatic fructose metabolism by phosphorylating fructose to fructose-1-phosphate."),
    makeMarker("Leptin Receptor", "LEPR", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "LEPR loss-of-function variants impair hypothalamic leptin satiety signaling, causing severe early-onset hyperphagia and morbid obesity. Annual body condition score, fasting leptin and glucose, and metabolic panel monitoring are recommended; leptin receptor deficiency requires aggressive dietary management and may respond to melanocortin agonist therapy.", "Encodes the leptin receptor, a cytokine receptor in the hypothalamus that mediates leptin's anorectic and neuroendocrine effects on energy balance."),
    makeMarker("Lipoprotein Lipase", "LPL", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "LPL loss-of-function variants cause familial lipoprotein lipase deficiency with severe hypertriglyceridemia (type I hyperlipoproteinemia), recurrent pancreatitis, and eruptive xanthomas. Annual fasting triglycerides and lipase monitoring are essential; extremely low-fat diet is mandatory and fat-soluble vitamin supplementation is required.", "Encodes lipoprotein lipase, an enzyme on capillary endothelial surfaces that hydrolyzes triglycerides in VLDL and chylomicrons, releasing fatty acids for tissue uptake."),
    makeMarker("Metallothionein", "MT", "Low", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "MT variants affect cysteine-rich metal-binding protein capacity for zinc, copper, and cadmium detoxification, influencing metal homeostasis and oxidative stress responses. In copper-accumulating breeds (Bedlington Terriers, Labrador Retrievers), MT expression contributes to copper detoxification capacity; annual liver copper and zinc monitoring is recommended.", "Encodes metallothionein, a cysteine-rich protein that binds heavy metals (zinc, copper, cadmium) for detoxification and metal homeostasis. Also functions in antioxidant defense."),
    makeMarker("Niemann-Pick Disease, Type C1", "NPC1", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "NPC1 loss-of-function causes Niemann-Pick disease type C — progressive cholesterol and sphingolipid accumulation in late endosomes/lysosomes producing cerebellar ataxia, vertical supranuclear gaze palsy, and dementia. Annual neurological assessment and liver function tests are recommended; miglustat treatment may slow neurological progression.", "Encodes NPC1, an endosomal/lysosomal membrane protein that mediates intracellular cholesterol transport. Deficiency causes Niemann-Pick disease type C, a neurovisceral lipid storage disorder."),
    makeMarker("Nuclear Receptor Subfamily 4 Group A Member 3", "NR4A3", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "NR4A3 variants affect nuclear receptor regulation of lipid metabolism and mitochondrial biogenesis in muscle and adipose tissue. Annual metabolic panel and liver function tests are recommended; relevant to understanding insulin resistance and energy expenditure variation in managed species.", "Encodes the NOR1 nuclear receptor, an orphan nuclear receptor expressed in skeletal muscle and adipose tissue that regulates lipid metabolism, mitochondrial function, and energy expenditure."),
    makeMarker("N-Terminal Asparagine Amidohydrolase 1", "NTAN1", "Low", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio, Saccharomyces cerevisiae", "NTAN1 variants affect the N-end rule protein degradation pathway and are informational at population level. Periodic assessment of general systemic health is sufficient; no specific clinical intervention is currently warranted for this marker alone.", "Encodes N-terminal asparagine amidohydrolase, a component of the N-end rule protein degradation pathway that deamidates N-terminal asparagine residues to aspartate."),
    makeMarker("Ornithine Decarboxylase Antizyme 1", "OAZ1", "Low", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio, Saccharomyces cerevisiae", "OAZ1 variants affect polyamine homeostasis regulation through ornithine decarboxylase antizyme feedback control. Informational; monitoring for unusual cancer susceptibility or growth phenotypes may be reasonable given the role of polyamines in cell proliferation.", "Encodes ornithine decarboxylase antizyme 1, a regulatory protein that inhibits ODC and promotes its proteasomal degradation to maintain polyamine homeostasis."),
    makeMarker("Ornithine Transcarbamylase", "OTC", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "OTC deficiency is the most common urea cycle disorder — presenting with hyperammonemic encephalopathy, particularly in neonates and after protein loads. Urgent ammonia management, protein-restricted diet, arginine and citrulline supplementation, and ammonia-scavenging drugs are required; neonatal OTC testing is indicated in offspring of known carrier dams.", "Encodes ornithine transcarbamylase, the second enzyme of the urea cycle, located in mitochondria, that condenses carbamoyl phosphate and ornithine to form citrulline."),
    makeMarker("Phenylalanine Hydroxylase", "PAH", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio, Felis catus", "PAH loss-of-function causes phenylketonuria (PKU) — phenylalanine accumulation producing severe intellectual disability without dietary intervention. Neonatal phenylalanine screening and lifelong phenylalanine-restricted diet are essential; BH4 (sapropterin) responsiveness should be tested in confirmed cases to guide management.", "Encodes phenylalanine hydroxylase, the hepatic enzyme that converts phenylalanine to tyrosine using tetrahydrobiopterin (BH4) as a cofactor. Deficiency causes phenylketonuria (PKU)."),
    makeMarker("Phosphoenolpyruvate Carboxykinase 1", "PCK1", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "PCK1 variants affect the rate-limiting step of gluconeogenesis and glyceroneogenesis in the liver, influencing fasting glucose maintenance and fat redistribution. Annual fasting glucose and liver function panel assessment are recommended; dietary carbohydrate timing and protein management are key intervention strategies.", "Encodes the cytosolic form of phosphoenolpyruvate carboxykinase, the rate-limiting enzyme in gluconeogenesis that converts oxaloacetate to phosphoenolpyruvate."),
    makeMarker("Pyruvate Dehydrogenase Kinase 4", "PDK4", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "PDK4 high-expression variants suppress pyruvate dehydrogenase complex activity, impairing carbohydrate utilization and promoting metabolic inflexibility in muscle and heart. Annual metabolic screening including fasting glucose and serum lactate, plus cardiac evaluation, are recommended in affected individuals.", "Encodes pyruvate dehydrogenase kinase 4, which phosphorylates and inactivates the pyruvate dehydrogenase complex to regulate the entry of pyruvate into the TCA cycle."),
    makeMarker("Phospholipid Transfer Protein", "PLTP", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "PLTP variants alter HDL remodeling and phospholipid transfer between lipoproteins, influencing cardiovascular disease risk. Annual fasting lipid profile including HDL-C, LDL-C, and triglycerides is recommended; dietary fat composition and statin therapy selection may be informed by PLTP status.", "Encodes phospholipid transfer protein, which transfers phospholipids between lipoproteins and from cell membranes to HDL, participating in reverse cholesterol transport."),
    makeMarker("Peroxisome Proliferator-Activated Receptor Gamma", "PPARG", "Medium", "Homo sapiens, Canis lupus familiaris, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "PPARG variants alter nuclear receptor-driven adipogenesis, insulin sensitivity, and anti-inflammatory lipid signaling. Annual insulin sensitivity, body condition score, and metabolic panel monitoring are recommended; PPARG activation by thiazolidinediones (glitazones) may be indicated in confirmed insulin-resistant individuals.", "Encodes peroxisome proliferator-activated receptor gamma (PPARγ), a nuclear receptor that promotes adipocyte differentiation, insulin sensitivity, and fatty acid storage. The molecular target of thiazolidinedione insulin sensitizers."),
    makeMarker("PPARG Coactivator 1 Alpha", "PPARGC1A", "Medium", "Homo sapiens, Canis lupus familiaris, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "PPARGC1A variants impair mitochondrial biogenesis and oxidative metabolism, predisposing to muscle fatigue, metabolic syndrome, and reduced aerobic capacity. Annual CBC, serum CK, resting metabolic assessment, and body condition monitoring are recommended; regular aerobic exercise stimulates PPARGC1A expression and partially compensates reduced baseline activity.", "Encodes PGC-1α, a master regulator of mitochondrial biogenesis, fatty acid oxidation, and energy metabolism. Coactivates numerous transcription factors controlling oxidative metabolism."),
    makeMarker("Stearoyl-CoA Desaturase", "SCD", "Medium", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Bos taurus, Mus musculus, Danio rerio, Rattus norvegicus", "SCD variants alter delta-9 fatty acid desaturation (converting saturated to monounsaturated fatty acids), influencing membrane fluidity, lipid composition, and metabolic disease risk. Annual fasting lipid panel and liver enzyme assessment are recommended; SCD activity is reflected in palmitoleate/palmitate and oleate/stearate ratios.", "Encodes stearoyl-CoA desaturase, the rate-limiting enzyme in monounsaturated fatty acid synthesis that converts saturated fatty acids (palmitate, stearate) to monounsaturated forms."),
    makeMarker("Solute Carrier Family 2 Member 2 (GLUT2)", "SLC2A2", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "SLC2A2 variants impair pancreatic glucose sensing and hepatic glucose uptake — see also GLUT2. Annual fasting glucose, urinalysis for glucosuria, and liver enzyme panel assessment are recommended; dietary glucose management is the primary intervention.", "Encodes GLUT2, the low-affinity glucose transporter in pancreatic beta cells and hepatocytes (alternate gene symbol notation for GLUT2)."),
    makeMarker("Solute Carrier Family 2 Member 4 (GLUT4)", "SLC2A4", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "SLC2A4 variants impair insulin-dependent glucose uptake in skeletal muscle and adipose tissue — see also GLUT4. Annual fasting insulin, glucose, and body condition assessment are recommended; aerobic exercise is the most potent inducer of GLUT4 membrane translocation and expression.", "Encodes GLUT4, the insulin-regulated glucose transporter in skeletal muscle and adipose tissue (alternate gene symbol notation for GLUT4)."),
    makeMarker("Sterol Regulatory Element Binding Transcription Factor 1", "SREBF1", "Medium", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Danio rerio, Rattus norvegicus", "SREBF1 high-expression variants drive hepatic de novo lipogenesis and cholesterol synthesis, predisposing to hepatic steatosis, dyslipidemia, and metabolic syndrome. Annual fasting lipid profile and liver enzyme assessment are recommended; dietary carbohydrate restriction reduces SREBF1 activation.", "Encodes SREBP-1c, a master transcription factor that activates lipogenic genes in response to insulin and high carbohydrate intake, promoting de novo fatty acid and triglyceride synthesis."),
    makeMarker("Tryptophan 2,3-Dioxygenase", "TDO2", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "TDO2 variants affect the rate-limiting hepatic step of tryptophan catabolism into the kynurenine pathway, influencing serotonin availability and NAD+ synthesis. Annual liver function tests and tryptophan/kynurenine ratio assessment are informative; relevant to behavioral conditions linked to kynurenine pathway dysregulation.", "Encodes tryptophan 2,3-dioxygenase, the hepatic enzyme that initiates tryptophan catabolism via the kynurenine pathway, affecting tryptophan availability for serotonin synthesis."),
    makeMarker("Leptin", "LEP", "Medium", "Homo sapiens, Canis lupus familiaris, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "LEP loss-of-function causes profound early-onset obesity, hyperphagia, and hypogonadotropic hypogonadism through absent satiety signaling. Annual body condition score, fasting glucose, insulin, and leptin measurement are recommended; recombinant leptin therapy is available and produces dramatic weight loss in confirmed leptin-deficient individuals.", "Encodes leptin, an adipokine produced in proportion to fat mass that signals energy sufficiency to the hypothalamus, suppressing appetite and stimulating energy expenditure."),
    makeMarker("Melanocortin 4 Receptor", "MC4R", "Medium", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Danio rerio, Rattus norvegicus", "MC4R loss-of-function is the most common monogenic cause of human and canine obesity, causing hyperphagia through impaired hypothalamic energy balance regulation. Annual body condition score and metabolic assessment (glucose, insulin, lipids) are recommended; melanocortin agonist therapy (setmelanotide) may be indicated in severe MC4R-deficient cases.", "Encodes melanocortin-4 receptor, a GPCR expressed in the hypothalamus that mediates the anorexigenic effects of alpha-MSH (from POMC) to regulate energy balance. The most common monogenic obesity gene."),
    makeMarker("Fat Mass and Obesity Associated", "FTO", "Medium", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Danio rerio, Rattus norvegicus", "FTO risk alleles increase fat mass and obesity susceptibility through altered m6A RNA demethylase activity affecting hypothalamic appetite regulation. Annual body condition score and metabolic panel monitoring are recommended; dietary management and physical activity are the primary interventions; risk is modifiable by environment.", "Encodes an m6A RNA demethylase expressed in the hypothalamus; the first genome-wide significant obesity locus discovered. Mechanism involves post-transcriptional regulation of energy balance-related mRNAs."),
    makeMarker("Insulin", "INS", "High", "Homo sapiens, Sus scrofa, Canis lupus familiaris, Felis catus, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "INS variants that reduce insulin production or processing capacity predispose to diabetes mellitus type 1 (autoimmune) and neonatal diabetes. Annual fasting glucose, insulin, and C-peptide measurements are recommended; early insulin therapy prevents diabetic complications in affected individuals.", "Encodes insulin, the primary anabolic hormone produced by pancreatic beta cells that regulates glucose, lipid, and protein metabolism."),
  ]},
  { id: "musculoskeletal", name: "Musculoskeletal", color: "#78716C", markers: [
    makeMarker("Bone Gamma-Carboxyglutamate Protein (Osteocalcin)", "BGLAP", "Medium", "Homo sapiens, Canis lupus familiaris, Equus caballus, Bos taurus, Mus musculus, Danio rerio, Rattus norvegicus", "BGLAP variants affect osteocalcin production, which has dual roles in bone matrix mineralization and endocrine regulation of insulin sensitivity. Annual bone density assessment and serum osteocalcin with glucose/insulin monitoring are recommended; relevant to fracture risk management and metabolic bone disease.", "Encodes osteocalcin (bone Gla protein), a vitamin K-dependent protein secreted by osteoblasts that regulates bone mineralization and functions as a hormone regulating energy metabolism and reproduction."),
    makeMarker("Creatine Kinase, M-Type", "CKM", "Medium", "Homo sapiens, Equus caballus, Canis lupus familiaris, Sus scrofa, Mus musculus, Danio rerio, Rattus norvegicus", "CKM variants alter muscle-specific creatine kinase function, affecting high-energy phosphate buffering during intense exercise. Annual serum CK monitoring and exercise tolerance assessment are recommended; individuals with high-activity alleles may have elevated basal CK — establish individual baselines before interpreting post-exertion CK elevations.", "Encodes the M isoform of creatine kinase, which catalyzes the reversible conversion of creatine and ATP to phosphocreatine and ADP, buffering ATP levels in muscle during high-intensity exercise."),
    makeMarker("Collagen Type VI Alpha 1 Chain", "COL6A1", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "COL6A1 variants cause Ullrich congenital muscular dystrophy or Bethlem myopathy — connective tissue myopathy with proximal muscle weakness and distal joint contractures. Annual serum CK, muscle biopsy evaluation, pulmonary function testing, and orthopaedic joint assessment are recommended; physiotherapy and respiratory support are essential.", "Encodes the alpha-1 chain of type VI collagen, a major component of the extracellular matrix surrounding muscle fibers and providing structural support to connective tissue."),
    makeMarker("Myostatin", "MSTN", "Low", "Bos taurus, Canis lupus familiaris, Sus scrofa, Homo sapiens, Mus musculus, Ovis aries, Danio rerio, Rattus norvegicus", "MSTN loss-of-function variants produce the 'double-muscling' phenotype — dramatically increased muscle mass from reduced TGF-beta myogenesis inhibition. Breeding animals with homozygous MSTN deletions may experience dystocia (calf size); cardiac screening is recommended as cardiac muscle may also be affected; regular musculoskeletal evaluation is advisable.", "Encodes myostatin (GDF-8), a TGF-beta family member that acts as a negative regulator of skeletal muscle mass. Loss-of-function causes dramatic muscle hypertrophy (double-muscling) in cattle and other species."),
    makeMarker("Phosphorylase, Glycogen, Muscle", "PYGM", "High", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "PYGM loss-of-function causes muscle glycogen storage disease type V (McArdle disease) — exercise intolerance, painful cramps, myoglobinuria, and rhabdomyolysis during sustained exertion. Annual serum CK, renal function, and exercise tolerance evaluation are recommended; avoid intense sustained exercise; aerobic training at low intensity improves tolerance.", "Encodes the muscle isoform of glycogen phosphorylase (myophosphorylase), which cleaves glycogen to glucose-1-phosphate for glycolysis in muscle. Deficiency causes McArdle disease."),
    makeMarker("Ryanodine Receptor 1", "RYR1", "High", "Homo sapiens, Sus scrofa, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "RYR1 variants are the primary cause of malignant hyperthermia susceptibility — a life-threatening hypermetabolic crisis triggered by volatile anesthetic agents (halothane, isoflurane) and depolarizing muscle relaxants. Any anesthesia protocol for known RYR1 carriers must exclude all triggering agents and use only TIVA (total intravenous anesthesia); emergency dantrolene must be immediately available.", "Encodes ryanodine receptor 1, the calcium release channel of the sarcoplasmic reticulum in skeletal muscle. Mutations cause malignant hyperthermia susceptibility and central core disease."),
    makeMarker("Sodium Voltage-Gated Channel Alpha Subunit 4 (Skeletal Muscle Nav1.4)", "SCN4A", "High", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "SCN4A variants cause non-dystrophic myotonias and periodic paralyses — episodic muscle stiffness, weakness, or paralysis from skeletal muscle sodium channel dysfunction. Annual EMG, serum electrolytes, and exercise tolerance assessment are recommended; sodium channel blockers (mexiletine) are effective for myotonia management.", "Encodes the alpha subunit of the skeletal muscle voltage-gated sodium channel Nav1.4, essential for muscle action potential generation. Mutations cause various non-dystrophic myotonias and periodic paralysis."),
  ]},
  { id: "neuroscience", name: "Neuroscience", color: "#2563EB", markers: [
    makeMarker("Adhesion G Protein-Coupled Receptor L2", "ADGRL2", "Medium", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "ADGRL2 variants affect latrophilin-2 trans-synaptic adhesion molecule function in excitatory synapse formation and circuit development. Monitor for developmental neurological and behavioral anomalies; relevant to assessment of attention, social behavior, and cognitive development in affected offspring.", "Encodes latrophilin-2 (LPHN2), a cell adhesion GPCR expressed at synapses that mediates trans-synaptic adhesion and plays roles in synapse formation and neural circuit development."),
    makeMarker("Activity Regulated Cytoskeleton Associated Protein", "ARC", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "ARC variants affect immediate-early gene-driven synaptic scaling and long-term memory consolidation. Monitor for learning and memory deficits and altered fear memory extinction in affected individuals; relevant to breeding selection for working ability and learning aptitude.", "Encodes ARC (activity-regulated cytoskeleton-associated protein), an immediate-early gene product essential for long-term synaptic plasticity, AMPA receptor endocytosis, and memory consolidation."),
    makeMarker("Acid Sensing Ion Channel Subunit 2", "ASIC2", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "ASIC2 variants alter acid-sensing ion channel subunit composition in sensory neurons, modifying pain perception, mechanosensory thresholds, and neurological responses to ischemia. Assessment of pain sensitivity, nociceptive behavior, and neurological function is advisable; relevant to pain management protocols.", "Encodes acid-sensing ion channel 2 (ASIC2), a proton-gated sodium channel expressed in central and peripheral neurons that modulates pain, mechanosensory responses, and synaptic plasticity."),
    makeMarker("Ataxin 1", "ATXN1", "High", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "ATXN1 CAG repeat expansions cause spinocerebellar ataxia type 1 — progressive cerebellar and brainstem degeneration with gait ataxia, dysarthria, and dysphagia. Annual neurological examination with gait and vestibular assessment are recommended; repeat length directly correlates with disease severity and age at onset.", "Encodes ataxin-1, a transcriptional regulator whose polyglutamine expansion (CAG repeat expansion) causes spinocerebellar ataxia type 1 (SCA1)."),
    makeMarker("Calcium Voltage-Gated Channel Subunit Alpha1 D", "CACNA1D", "High", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "CACNA1D gain-of-function variants cause PASNA syndrome — primary aldosteronism, seizures, and neurological abnormalities from calcium channel overactivation. Annual aldosterone/renin ratio, blood pressure, serum electrolytes, and neurological assessment are recommended; avoid drugs exacerbating L-type calcium channel activity.", "Encodes the Cav1.3 L-type calcium channel, expressed in neurons, cochlear hair cells, and adrenal cortex. Mutations cause PASNA syndrome with primary aldosteronism and neurological effects."),
    makeMarker("Cocaine And Amphetamine Regulated Transcript", "CART", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "CART variants alter neuropeptide signaling regulating energy balance, reward, and stress responses in the hypothalamus and limbic system. Annual body weight, behavioral temperament, and stress reactivity assessment are recommended; CART variants may influence feeding behavior and response to stress-modulating medications.", "Encodes CART peptide, a neuropeptide expressed in hypothalamic and limbic neurons that regulates energy balance, stress responses, and reward processing."),
    makeMarker("Cell Adhesion Molecule L1 Like", "CHL1", "Medium", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "CHL1 variants impair L1-like cell adhesion molecule-mediated axon guidance and cortical neuron migration, contributing to autism spectrum disorders and intellectual disability phenotypes. Developmental neurological milestones, social behavior, and cognitive assessment are recommended in carrier offspring.", "Encodes close homolog of L1 (CHL1), a neural cell adhesion molecule mediating axon guidance, cortical neuron migration, and synaptic differentiation."),
    makeMarker("CLN5, Intracellular Trafficking Protein", "CLN5", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "CLN5 loss-of-function causes neuronal ceroid lipofuscinosis type 5 (Finnish variant late-infantile NCL) — progressive vision loss, seizures, and neurodegeneration. Annual ERG, ophthalmological examination, EEG, and neurological assessment are essential; genetic carrier testing before breeding is strongly recommended in Border Collies and other susceptible breeds.", "Encodes CLN5, a lysosomal membrane protein involved in protein trafficking. Deficiency causes a form of neuronal ceroid lipofuscinosis (NCL)."),
    makeMarker("CAMP Responsive Element Binding Protein 1", "CREB1", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "CREB1 variants affect cAMP-responsive transcription factor activity in synaptic plasticity and memory consolidation circuits. Monitor for learning, memory, and anxiety-related behavioral phenotypes; relevant to performance and training assessment in working animal breeds.", "Encodes CREB1, a transcription factor activated by cAMP and calcium signaling that drives expression of plasticity-related genes essential for long-term memory formation."),
    makeMarker("Catenin Alpha 2", "CTNNA2", "Medium", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "CTNNA2 variants affect alpha-N-catenin synaptic scaffolding, associated with lissencephaly and cortical dysplasia. Neuroimaging (MRI) and developmental neurological assessment are recommended in offspring of carrier parents; monitor for seizure activity and developmental regression.", "Encodes alpha-N-catenin, a synaptic scaffolding protein linking cadherin-based adhesion to the actin cytoskeleton. Important for dendritic spine morphology and synaptic plasticity."),
    makeMarker("Cathepsin D", "CTSD", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "CTSD loss-of-function causes neuronal ceroid lipofuscinosis type 10 — congenital or early-onset lysosomal storage neurodegeneration with severe seizures and early death. Annual ERG, EEG, and neurological assessment are essential; genetic carrier testing is mandatory before breeding in susceptible breeds.", "Encodes lysosomal cathepsin D, an aspartic protease essential for lysosomal protein degradation. Deficiency causes neuronal ceroid lipofuscinosis type 10 (CLN10/CTSD-NCL)."),
    makeMarker("Dopamine Beta-Hydroxylase", "DBH", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "DBH variants alter norepinephrine and epinephrine biosynthesis, influencing sympathetic nervous system tone, attention, and behavioral reactivity. Annual blood pressure, heart rate variability, and behavioral temperament assessment are recommended; relevant to selection of adrenergic medications in affected animals.", "Encodes dopamine beta-hydroxylase, the enzyme that converts dopamine to norepinephrine in catecholaminergic neurons and adrenal chromaffin cells."),
    makeMarker("Early Growth Response 1", "EGR1", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "EGR1 variants affect immediate-early transcription factor-driven synaptic consolidation and memory encoding. Monitor for learning and long-term memory deficits; relevant to performance assessment in working breeds and training-outcome prediction.", "Encodes EGR1, an immediate-early zinc finger transcription factor activated by synaptic activity that drives gene expression required for long-term potentiation and memory consolidation."),
    makeMarker("GABA Type A Receptor Associated Protein", "GABARAP", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "GABARAP variants affect GABA-A receptor trafficking to synapses, influencing inhibitory synaptic strength and susceptibility to anxiety and seizures. Annual neurological assessment including EEG evaluation is recommended; GABARAP status may affect responsiveness to benzodiazepine and GABA-modulatory medications.", "Encodes GABARAP, a ubiquitin-like protein involved in trafficking GABA-A receptors to the plasma membrane and in autophagosome formation."),
    makeMarker("Glutamate Ionotropic Receptor AMPA Type Subunit 1", "GRIA1", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "GRIA1 variants affect GluA1 AMPA receptor subunit composition at excitatory synapses, influencing synaptic plasticity, spatial memory, and anxiety phenotypes. Monitor for cognitive, anxiety, and social behavioral phenotypes; relevant to working animal assessment and management of fear or aggression-related behaviors.", "Encodes GluA1, the major AMPA-type glutamate receptor subunit important for long-term potentiation, spatial learning, and synaptic plasticity."),
    makeMarker("Glutamate Ionotropic Receptor NMDA Type Subunit 2B", "GRIN2B", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "GRIN2B variants alter GluN2B NMDA receptor subunit function, causing intellectual disability, autism spectrum disorder phenotypes, and seizures. Developmental cognitive and behavioral milestones should be assessed in carrier offspring; NMDA receptor-modulating treatments may require genotype-informed dosing.", "Encodes GluN2B, the NR2B subunit of NMDA glutamate receptors. A critical determinant of synaptic plasticity thresholds and a target of learning and memory modulation."),
    makeMarker("Glutamate Metabotropic Receptor 7", "GRM7", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "GRM7 variants affect presynaptic metabotropic glutamate autoreceptor feedback inhibition, associated with anxiety disorders, epilepsy, and altered pain processing. Annual neurological and behavioral assessment are recommended; GRM7 genotype may influence responsiveness to glutamatergic modulators used in neuropathic pain and anxiety management.", "Encodes metabotropic glutamate receptor 7 (mGluR7), a presynaptic autoreceptor that inhibits glutamate release at high concentrations, regulating synaptic excitability."),
    makeMarker("Hexosaminidase Subunit Beta", "HEXB", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "HEXB loss-of-function causes GM2 gangliosidosis (Sandhoff disease in humans, equivalent storage disease in cats and dogs) — progressive lysosomal ganglioside accumulation producing neurological deterioration. Annual neurological examination, gait assessment, and ERG are essential; genetic carrier testing is mandatory before breeding in susceptible breeds.", "Encodes the beta subunit of hexosaminidase, forming both hexosaminidase A (alpha-beta) and B (beta-beta) isoenzymes. Deficiency causes Sandhoff disease from accumulated GM2 ganglioside."),
    makeMarker("Heterogeneous Nuclear Ribonucleoprotein H1", "HNRNPH1", "Medium", "Mus musculus, Homo sapiens, Rattus norvegicus, Danio rerio", "HNRNPH1 variants affect RNA splicing regulation in the CNS, particularly relevant to drug-induced dopaminergic reward circuits. Monitor for behavioral and neurological phenotypes including sensitization to stimulants; relevant to working animal drug testing protocols and predicting abnormal behavioral responses to stimulants.", "Encodes heterogeneous nuclear ribonucleoprotein H1, an RNA-binding protein that regulates alternative splicing. In mice, a missense variant dramatically reduces amphetamine sensitivity."),
    makeMarker("WWC1 (KIBRA, Kidney And Brain Protein)", "KIBRA", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "KIBRA variants affect synaptic scaffolding protein-mediated memory performance, with a well-replicated association between T allele and improved episodic memory. Relevant to cognitive assessment in aging animals; informational for monitoring age-related cognitive decline in carrier populations.", "Encodes KIBRA (WWC1), a scaffolding protein at the postsynaptic density that regulates AMPA receptor trafficking and is associated with human episodic memory performance."),
    makeMarker("NDRG Family Member 1", "NDRG1", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "NDRG1 loss-of-function causes Charcot-Marie-Tooth disease type 4D — progressive hereditary motor and sensory neuropathy with significant disability. Annual neurological examination, gait analysis, electromyography, and nerve conduction studies are recommended; genetic carrier testing is strongly advised in susceptible dog breeds (Greyhounds).", "Encodes NDRG1, a protein expressed in myelinating Schwann cells essential for myelin maintenance. Deficiency causes a demyelinating peripheral neuropathy."),
    makeMarker("N-Methyl-D-Aspartate Receptor", "NMDAR", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "NMDAR autoantibody-associated encephalitis or variant-driven dysfunction causes a spectrum of neuropsychiatric and seizure disorders. Annual neurological assessment including EEG and, if indicated, NMDAR autoantibody measurement are recommended; NMDAR genotype may influence anesthetic protocol selection (ketamine sensitivity).", "Generic NMDA receptor complex reference; NMDA receptors mediate excitatory glutamatergic neurotransmission, synaptic plasticity, and learning. Targets of numerous neuropsychiatric medications."),
    makeMarker("Opioid Receptor Mu 1", "OPRM1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "OPRM1 variants alter mu-opioid receptor binding affinity, with direct consequences for analgesic efficacy and opioid dose requirements. Pre-procedural OPRM1 genotyping is recommended to guide opioid dose selection; A118G variant carriers may require higher opioid doses for equivalent analgesia.", "Encodes the mu-opioid receptor, the primary target of endorphins and opioid analgesics. Mediates analgesia, reward, and respiratory depression."),
    makeMarker("Receptor For Activated C Kinase 1", "RACK1", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio, Saccharomyces cerevisiae", "RACK1 variants affect ribosomal scaffolding protein function that coordinates synaptic translation of plasticity-related proteins. Monitor for cognitive and neurological phenotypes; informational for understanding interindividual variation in synaptic protein synthesis and neural plasticity.", "Encodes RACK1 (receptor for activated C kinase 1), a scaffolding protein on the ribosome that coordinates signaling and translation regulation at synapses."),
    makeMarker("Solute Carrier Family 1 Member 1 (EAAT3)", "SLC1A1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "SLC1A1 variants affect neuronal glutamate/aspartate transporter function, associated with obsessive-compulsive disorder and repetitive behavior phenotypes. Monitor for compulsive or repetitive behaviors and anxiety; relevant to behavioral management protocols in affected individuals.", "Encodes EAAT3, a neuronal glutamate transporter that regulates glutamate uptake in postsynaptic neurons and is involved in cysteine transport for GSH synthesis."),
    makeMarker("Solute Carrier Family 6 Member 1 (GAT-1, GABA Transporter 1)", "SLC6A1", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "SLC6A1 loss-of-function variants cause myoclonic-atonic epilepsy with intellectual disability — reduced GABA reuptake impairing inhibitory control. Annual EEG monitoring and developmental neurological assessment are recommended; valproate and levetiracetam are often effective, while specific antiepileptics must be selected carefully based on mechanism.", "Encodes the GABA transporter GAT-1, responsible for the reuptake of GABA from the synapse into presynaptic terminals and astrocytes, terminating inhibitory signaling."),
    makeMarker("SLIT-ROBO Rho GTPase Activating Protein 3", "SRGAP3", "Medium", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "SRGAP3 variants affect Rho GTPase-activating protein function in axon guidance and dendritic spine morphogenesis, contributing to intellectual disability phenotypes. Developmental neurological milestones and cognitive assessment are recommended in carrier offspring; relevant to behavioral neuroscience breeding research.", "Encodes SRGAP3, a Rho GTPase-activating protein that regulates neuronal morphology and axon guidance through inhibition of Rac1 in dendritic spines."),
    makeMarker("Synaptic Ras GTPase Activating Protein 1", "SYNGAP1", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "SYNGAP1 haploinsufficiency is a common cause of intellectual disability, autism spectrum disorder, and epilepsy. Annual developmental cognitive assessment, EEG monitoring, and behavioral evaluation are recommended; SYNGAP1 status may guide selection of NMDA receptor-modulating therapies.", "Encodes SynGAP1, a Ras/Rap GTPase-activating protein at the postsynaptic density that regulates AMPA receptor trafficking and synaptic strength. Haploinsufficiency causes intellectual disability."),
    makeMarker("Trace Amine Associated Receptor 1", "TAAR1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "TAAR1 variants affect intracellular GPCR-mediated modulation of dopaminergic and serotonergic neurotransmission, influencing psychiatric vulnerability and drug sensitivity. Annual behavioral temperament assessment is recommended; TAAR1 genotype may inform responsiveness to novel TAAR1 agonist antipsychotic medications.", "Encodes trace amine-associated receptor 1, an intracellular GPCR that modulates dopamine and serotonin neurotransmission. A therapeutic target for psychiatric disorders."),
    makeMarker("Tachykinin Precursor 1 (Substance P)", "TAC1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "TAC1 variants affect substance P and neurokinin A neuropeptide signaling in pain transmission and stress response circuits. Annual pain sensitivity assessment and behavioral stress response evaluation are recommended; NK1 receptor antagonists may be considered in individuals with chronic pain or severe anxiety phenotypes.", "Encodes tachykinin precursor 1, which is processed into substance P and neurokinin A. These neuropeptides mediate pain transmission, stress responses, and neuroinflammation."),
    makeMarker("Tyrosine Hydroxylase", "TH", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "TH variants affect the rate-limiting enzyme of catecholamine biosynthesis, with severe loss causing dopamine/norepinephrine deficiency disorder (L-DOPA-responsive dystonia and parkinsonism). Annual neurological examination including motor assessment are recommended; L-DOPA or dopamine precursor supplementation is indicated for confirmed deficiency states.", "Encodes tyrosine hydroxylase, the rate-limiting enzyme in catecholamine biosynthesis that converts tyrosine to L-DOPA. Essential for dopamine, norepinephrine, and epinephrine production."),
    makeMarker("Vesicle Associated Membrane Protein 2 (Synaptobrevin-2)", "VAMP2", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "VAMP2 variants impair synaptic vesicle fusion SNARE complex function, causing severe neurodevelopmental disorder with intellectual disability and hyperkinetic movements. Annual neurological assessment, developmental milestone evaluation, and EEG monitoring are recommended; genetic counseling and testing of at-risk offspring are advisable.", "Encodes synaptobrevin-2 (VAMP2), the vesicular SNARE protein essential for synaptic vesicle fusion and neurotransmitter release at all chemical synapses."),
    makeMarker("Vasoactive Intestinal Peptide", "VIP", "Medium", "Homo sapiens, Gallus gallus, Mus musculus, Rattus norvegicus, Danio rerio", "VIP variants affect neuropeptide-driven circadian pacemaker synchronization and immune modulation in the CNS. Monitor for circadian rhythm disruption, behavioral irregularities, and immune-mediated neurological conditions; relevant to welfare management under artificial lighting conditions.", "Encodes vasoactive intestinal peptide, a neuropeptide with wide expression in the CNS and periphery that regulates circadian rhythms, immune function, and smooth muscle tone."),
    makeMarker("Brain-Derived Neurotrophic Factor", "BDNF", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "BDNF Val66Met variant reduces activity-dependent BDNF secretion, impacting hippocampal neuroplasticity, fear memory extinction, and resilience to chronic stress. Annual behavioral temperament and cognitive assessment are recommended; exercise and enrichment enhance BDNF expression and may partially compensate for reduced secretion variants.", "Encodes brain-derived neurotrophic factor, the most widely expressed neurotrophin in the adult brain. Promotes neuronal survival, differentiation, synaptic plasticity, and learning."),
    makeMarker("Catechol-O-Methyltransferase", "COMT", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "COMT Val158Met variant alters prefrontal dopamine and norepinephrine catabolism rate, with low-activity (Met) carriers showing increased baseline prefrontal dopamine and stress vulnerability under extreme conditions. Annual behavioral temperament assessment is recommended; COMT genotype may inform selection of dopaminergic and adrenergic medications.", "Encodes catechol-O-methyltransferase, an enzyme that inactivates catecholamine neurotransmitters (dopamine, norepinephrine, epinephrine) by methylation. A major dopamine-regulating enzyme in the prefrontal cortex."),
    makeMarker("Disrupted In Schizophrenia 1", "DISC1", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "DISC1 variants impair scaffold protein function at the centrosome and synaptic density, predisposing to neurodevelopmental and psychiatric phenotypes. Annual behavioral temperament and developmental neurological assessment are recommended; DISC1 status may inform risk profiling for complex psychiatric trait breeding evaluations.", "Encodes disrupted in schizophrenia 1 (DISC1), a scaffolding protein at the centrosome and postsynaptic density involved in neurodevelopment, neuronal migration, and synaptic function."),
    makeMarker("Apolipoprotein E", "APOE", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "APOE ε4 allele is the strongest genetic risk factor for late-onset Alzheimer's disease and canine cognitive dysfunction syndrome, and impairs amyloid-beta clearance. Annual cognitive function assessment (cognitive dysfunction scale in dogs) is recommended from 8 years of age; antioxidant-rich diet and cognitive enrichment are strongly advisable for ε4 carriers.", "Encodes apolipoprotein E, a lipid transport protein with critical roles in neuronal lipid homeostasis, amyloid-beta clearance, and synaptic plasticity. APOE ε4 is the major genetic risk factor for Alzheimer's disease."),
    makeMarker("Neurexin 1", "NRXN1", "High", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "NRXN1 deletions are among the highest-confidence genetic risk factors for autism spectrum disorder, schizophrenia, and intellectual disability through loss of trans-synaptic adhesion complex assembly. Annual developmental cognitive and social behavioral assessment are recommended in carrier offspring; genetic counseling is advisable before breeding carrier-to-carrier pairs.", "Encodes neurexin-1, a presynaptic cell adhesion molecule that organizes the synapse by binding postsynaptic neuroligins and LRRTMs. Deletions are a major risk factor for autism and schizophrenia."),
  ]},
  { id: "nutrition", name: "Nutrition", color: "#65A30D", markers: [
    makeMarker("Amylase 1A (Salivary)", "AMY1A", "Low", "Homo sapiens, Sus scrofa, Canis lupus familiaris, Mus musculus, Rattus norvegicus", "AMY1A copy number variation determines salivary amylase output and starch digestion initiation efficiency. High copy number correlates with more efficient starch pre-digestion; informational for dietary starch composition recommendations in performance and working animals.", "Encodes salivary amylase 1A, an alpha-amylase that initiates starch digestion in the oral cavity. Copy number variation in humans and dogs is associated with dietary starch adaptation."),
    makeMarker("Amylase 2A (Pancreatic)", "AMY2A", "Low", "Homo sapiens, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "AMY2A variants affect pancreatic amylase secretion and starch digestion efficiency in the small intestine. Informational; dietary starch complexity and carbohydrate-to-protein ratio may need adjustment based on amylase activity level; relevant to managing exocrine pancreatic insufficiency.", "Encodes pancreatic amylase 2A, one of the major digestive enzymes secreted by the exocrine pancreas for starch and glycogen hydrolysis in the intestinal lumen."),
    makeMarker("Amylase 2B (Pancreatic)", "AMY2B", "Low", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Rattus norvegicus", "AMY2B high copy number in dogs represents a genomic adaptation to starch-rich diets during domestication, conferring enhanced pancreatic amylase capacity. Informational; provides context for dietary starch tolerance differences among breeds; exocrine pancreatic function testing is advisable if clinical signs of maldigestion develop.", "Encodes pancreatic amylase 2B; copy number amplification in dogs is a key adaptation to starch-rich human cohabitation diets, increasing intestinal starch digestion capacity."),
    makeMarker("Sodium-Dependent Neutral Amino Acid Transporter (B0AT1)", "B0AT1 (SLC6A19)", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "B0AT1 variants impair intestinal neutral amino acid absorption, causing Hartnup disorder — pellagra-like rash, cerebellar ataxia, and psychiatric symptoms from tryptophan malabsorption. Dietary protein intake assessment and nicotinamide (niacin) supplementation are recommended to compensate for reduced tryptophan absorption.", "Encodes the B0AT1 neutral amino acid transporter (SLC6A19), the primary intestinal transporter for neutral amino acids including tryptophan. Deficiency causes Hartnup disorder."),
    makeMarker("Beta-Carotene 15,15'-Monooxygenase 1", "BCMO1", "Low", "Homo sapiens, Felis catus, Canis lupus familiaris, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "BCMO1 low-activity variants reduce beta-carotene cleavage to preformed vitamin A (retinal), causing subclinical vitamin A deficiency despite adequate beta-carotene intake. Annual serum retinol measurement is recommended; dietary vitamin A supplementation should target the pre-formed retinol form rather than carotenoid precursors alone.", "Encodes beta-carotene 15,15'-monooxygenase 1, the enzyme that cleaves dietary beta-carotene to produce vitamin A (retinol). Cats have limited BCMO1 activity, requiring pre-formed vitamin A in their diet."),
    makeMarker("Beta-Carotene Oxygenase 1", "BCO1", "Low", "Homo sapiens, Felis catus, Gallus gallus, Mus musculus, Rattus norvegicus, Danio rerio", "BCO1 variants affect provitamin A carotenoid conversion efficiency, influencing vitamin A status particularly in species or populations relying heavily on plant-based vitamin A precursors. Annual serum retinol monitoring and adjustment of dietary carotenoid or pre-formed vitamin A supplementation are recommended.", "Encodes beta-carotene oxygenase 1 (BCO1), the primary enzyme converting dietary provitamin A carotenoids (beta-carotene, alpha-carotene) into retinal for vitamin A synthesis."),
    makeMarker("Calbindin 1, 28kDa (Vitamin D-Dependent Calcium Binding Protein D28k)", "CALB1(D28K)", "Low", "Homo sapiens, Gallus gallus, Mus musculus, Rattus norvegicus, Danio rerio", "CALB1 D28K variants affect calcium buffering and intracellular calcium transport in the intestinal mucosa and cerebellum, influencing calcium absorption efficiency. Annual serum calcium, phosphorus, and vitamin D metabolite assessment are recommended; calcium and vitamin D supplementation dosing should account for transport protein efficiency.", "Encodes calbindin-D28k, a vitamin D-dependent calcium-binding protein expressed in intestinal epithelium, neurons, and kidneys that mediates transcellular calcium transport and neuronal calcium buffering."),
    makeMarker("Calbindin 2 / Calretinin (Vitamin D-Dependent Calcium Binding Protein D9K)", "CALB1(D9K)", "Low", "Homo sapiens, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "CALB1 D9K variants affect vitamin D-dependent intestinal calcium absorption, with lower efficiency predisposing to hypocalcemia in species with high calcium turnover. Annual serum calcium, phosphorus, and PTH monitoring are recommended; dietary calcium and vitamin D intake should be optimized to compensate for reduced transport efficiency.", "Encodes calbindin-D9k (S100G), a vitamin D-inducible calcium-binding protein in intestinal epithelium that facilitates calcium absorption, particularly important during periods of high calcium demand."),
    makeMarker("Cholecystokinin", "CCK", "Low", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "CCK variants affect the intestinal satiety hormone mediating digestive enzyme release and post-meal fullness signaling. Annual gastrointestinal digestive function assessment and body condition monitoring are recommended; CCK-related satiety differences may contribute to interindividual variation in post-meal food intake regulation.", "Encodes cholecystokinin, an intestinal and brain peptide hormone released in response to dietary fat and protein that stimulates gallbladder contraction, pancreatic enzyme secretion, and satiety signaling."),
    makeMarker("Chymotrypsin-Like Elastase 2A", "CELA2A", "Medium", "Homo sapiens, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "CELA2A variants affect chymotrypsin-like elastase-mediated protein digestion in the small intestine. Annual assessment of protein digestibility and fecal elastase levels may be warranted if clinical signs of protein maldigestion (hypoalbuminemia, weight loss) are detected; exocrine pancreatic function testing should be performed.", "Encodes chymotrypsin-like elastase 2A, a pancreatic serine protease secreted into the duodenum that digests dietary proteins and elastin."),
    makeMarker("Cubilin", "CUBN", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "CUBN variants impair cubilin-intrinsic factor complex-mediated vitamin B12 absorption, causing Imerslund-Gräsbeck syndrome with megaloblastic anemia and proteinuria. Annual serum B12, methylmalonic acid, homocysteine, and CBC with differential are recommended; parenteral B12 supplementation bypasses the intestinal absorption defect.", "Encodes cubilin, a multiligand endocytic receptor expressed in intestinal and renal tubular epithelium that mediates absorption of vitamin B12-intrinsic factor complex and other ligands."),
    makeMarker("Excitatory Amino Acid Transporter 3", "EAAT3 (SLC1A1)", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "EAAT3 variants affect intestinal and renal cysteine and glutamate transport, influencing glutathione synthesis capacity and amino acid absorption efficiency. Annual amino acid profile and glutathione status assessment are recommended; cysteine-enriched diet may support antioxidant capacity in low-activity EAAT3 carriers.", "Encodes the EAAT3 excitatory amino acid transporter; expressed in intestinal epithelium and kidneys for cysteine and glutamate reabsorption, and in neurons as a glutamate transporter."),
    makeMarker("Group-Specific Component (Vitamin D Binding Protein)", "GC", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "GC variants affect vitamin D binding protein structure and half-life, influencing total 25-hydroxyvitamin D transport capacity and tissue bioavailability. Annual total and free 25-hydroxyvitamin D measurement is recommended; interpret serum vitamin D levels in context of GC genotype — low GC-binding alleles may show lower total D despite adequate free D.", "Encodes the vitamin D binding protein (GC-globulin), the primary plasma transporter of vitamin D metabolites. Affects bioavailability of vitamin D to tissues."),
    makeMarker("Large Neutral Amino Acid Transporter 1 (System L)", "LAT1 (SLC7A5)", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "LAT1 variants affect blood-brain barrier and intestinal transport of large neutral amino acids (Phe, Trp, Leu, Val), influencing neurotransmitter precursor availability. Annual serum amino acid profile is recommended; relevant to management of phenylketonuria, LNAA therapy, and neurotransmitter precursor supplementation.", "Encodes LAT1, a sodium-independent transporter for large neutral amino acids that mediates their uptake across the blood-brain barrier and intestinal epithelium."),
    makeMarker("Lactase", "LCT", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Sus scrofa, Mus musculus, Bos taurus, Rattus norvegicus", "LCT low-persistence variants cause adult-onset lactase decline, producing lactose intolerance with bloating, diarrhea, and gas after dairy ingestion. Dietary lactose restriction or lactase enzyme supplementation is recommended; dairy products should be avoided or replaced with lactose-free alternatives in confirmed carriers.", "Encodes lactase-phlorizin hydrolase (LPH), the intestinal brush border enzyme that cleaves lactose into glucose and galactose. Adult persistence of lactase is due to variants upstream of LCT."),
    makeMarker("Maltase-Glucoamylase", "MGAM", "Low", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "MGAM variants affect intestinal brush border maltose and starch oligosaccharide digestion capacity. Informational; clinically significant maldigestion is uncommon given other starch-digesting enzymes; assess for post-prandial gastrointestinal symptoms in high-starch diets when MGAM activity is very low.", "Encodes maltase-glucoamylase, an intestinal brush border enzyme that cleaves maltose and short oligosaccharides to glucose for absorption."),
    makeMarker("Mucin 2 (Intestinal)", "MUC2", "Low", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "MUC2 variants affect intestinal mucus layer structure and thickness, influencing barrier function, microbiome composition, and susceptibility to inflammatory bowel disease. Annual gastrointestinal health assessment including fecal microbiome profiling is recommended; MUC2 status is relevant to dietary fiber and probiotic management strategies.", "Encodes mucin 2 (MUC2), the main secreted mucin forming the intestinal mucus gel layer that protects the epithelium and shapes the luminal microbiome."),
    makeMarker("Peptide Transporter 1 (H+/Peptide Cotransporter)", "PEPT1 (SLC15A1)", "Low", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "PEPT1 variants affect di- and tripeptide intestinal absorption efficiency, influencing total protein assimilation rate. Informational; relevant to optimizing protein source and hydrolyzate supplementation in animals with suboptimal protein utilization or recovery after gastrointestinal injury.", "Encodes the intestinal H+/peptide cotransporter PEPT1 (SLC15A1), responsible for the efficient absorption of small peptides from the intestinal lumen."),
    makeMarker("Plasma Glutamate Carboxypeptidase", "PGCP", "Low", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "PGCP variants affect folate and glutamate carboxypeptidase activity in the intestinal epithelium, influencing folate absorption from polyglutamated dietary sources. Annual serum folate and homocysteine monitoring are recommended; dietary supplementation with monoglutamate forms of folate (folic acid) bypasses the PGCP cleavage requirement.", "Encodes plasma glutamate carboxypeptidase (PGCP), an enzyme that cleaves polyglutamated folate to monoglutamated forms for intestinal absorption."),
    makeMarker("Pancreatic Lipase Related Protein 1", "PLB1", "Low", "Homo sapiens, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "PLB1 variants affect pancreatic phospholipid and galactolipid digestion, influencing fat-soluble nutrient absorption efficiency. Annual assessment of fat-soluble vitamin status (A, D, E, K) and fecal fat is recommended if clinical signs of fat malabsorption are present.", "Encodes phospholipase B1, a pancreatic enzyme that digests phospholipids, lysophospholipids, and galactolipids in the intestinal lumen."),
    makeMarker("Pancreatic Lipase", "PNLIP", "Medium", "Homo sapiens, Sus scrofa, Canis lupus familiaris, Felis catus, Mus musculus, Rattus norvegicus, Danio rerio", "PNLIP variants affect primary pancreatic triglyceride lipase output, influencing dietary fat digestion efficiency and fat-soluble vitamin absorption. Annual fecal fat assessment and fat-soluble vitamin (A, D, E, K) monitoring are recommended; PNLIP status is relevant to management of exocrine pancreatic insufficiency.", "Encodes pancreatic lipase (PNLIP), the primary enzyme for dietary triglyceride digestion in the small intestine, requiring colipase as a cofactor."),
    makeMarker("Serine Protease 1 (Cationic Trypsinogen)", "PRSS1", "High", "Homo sapiens, Sus scrofa, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "PRSS1 gain-of-function variants cause hereditary pancreatitis through premature intrapancreatic trypsin activation. Annual serum amylase, lipase, and abdominal ultrasound monitoring are recommended; low-fat diet and alcohol avoidance (where applicable) are essential; prophylactic ERCP or pancreatectomy may be considered in severe recurrent cases.", "Encodes cationic trypsinogen (PRSS1), the most abundant pancreatic protease precursor. Gain-of-function mutations cause autoactivation within the pancreas, leading to hereditary pancreatitis."),
    makeMarker("Retinol Binding Protein 4 (Plasma RBP)", "RBP4", "Medium", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "RBP4 high-expression variants impair insulin signaling in adipose tissue and are associated with insulin resistance and type 2 diabetes. Annual fasting insulin, glucose, and serum RBP4 measurement are recommended; vitamin A status and carbohydrate intake management are important secondary considerations.", "Encodes retinol binding protein 4 (RBP4), the primary plasma transporter of vitamin A (retinol) from liver to peripheral tissues. Also an adipokine that reduces insulin sensitivity when overexpressed."),
    makeMarker("Selenoprotein P", "SELENOP", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "SELENOP variants affect the primary plasma selenium transport protein, influencing selenium delivery to peripheral tissues, thyroid function, and antioxidant capacity. Annual serum selenium and selenoprotein status monitoring are recommended; dietary selenium supplementation should be carefully dosed — both deficiency and toxicity are clinically significant.", "Encodes selenoprotein P (SELENOP), the main plasma selenium transport protein that carries selenium to peripheral tissues. Also has antioxidant peroxidase activity."),
    makeMarker("Selenoprotein P (alternative entry)", "SELENOP(SelP)", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "SELENOP (SelP) variants mirror the SELENOP entry — affecting selenocysteine-containing plasma transport of selenium and local GPX activity. Annual serum selenium and thyroid function (TSH, T4) monitoring are recommended; selenium is essential for DIO2-mediated T3 production.", "Alternate notation for SELENOP; the full-length SELENOP protein contains multiple selenocysteine residues acting as selenium storage and delivery molecules."),
    makeMarker("Sodium-Glucose Linked Transporter 1 (SGLT1)", "SGLT1 (SLC5A1)", "High", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "SGLT1 loss-of-function causes glucose-galactose malabsorption — life-threatening osmotic diarrhea in neonates ingesting lactose-containing milk. Prompt elimination of lactose and glucose/galactose from the diet is required; fructose-based formula is well tolerated; genetic testing of siblings of affected neonates is strongly recommended.", "Encodes sodium-glucose linked transporter 1 (SGLT1/SLC5A1), the high-affinity intestinal and renal epithelial transporter for glucose and galactose. Essential for post-prandial monosaccharide absorption."),
    makeMarker("Sucrase-Isomaltase", "SI", "Medium", "Homo sapiens, Sus scrofa, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "SI variants cause congenital sucrase-isomaltase deficiency — sucrose and starch oligosaccharide intolerance with diarrhea and flatulence after dietary sucrose ingestion. Annual gastrointestinal symptom assessment and dietary sucrose restriction are recommended; sucrase enzyme supplementation (sacrosidase) is available for affected individuals.", "Encodes the intestinal brush border sucrase-isomaltase complex, which cleaves sucrose into glucose and fructose, and cleaves isomaltose oligosaccharides."),
    makeMarker("Sucrase-Isomaltase (complex isoform notation)", "SI(complex)", "Medium", "Homo sapiens, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "SI complex isoform variants affect different functional domains of the sucrase-isomaltase bifunctional enzyme; see SI entry. Clinical management is identical: dietary sucrose restriction and enzyme supplementation for symptomatic individuals.", "Alternate notation reflecting the bifunctional sucrase/isomaltase enzyme complex; both activities are encoded by the single SI gene processed into two functional subunits."),
    makeMarker("Solute Carrier Family 19 Member 3 (Thiamine Transporter 2)", "SLC19A3", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "SLC19A3 loss-of-function causes thiamine transporter deficiency syndrome 2 — biotin-thiamine-responsive basal ganglia disease with encephalopathy. High-dose thiamine and biotin supplementation must be initiated promptly; annual neurological assessment and MRI monitoring are recommended; supplementation should be maintained lifelong to prevent encephalopathic crises.", "Encodes thiamine transporter 2 (THTR2/SLC19A3), a membrane protein mediating cellular thiamine uptake. Deficiency causes biotin-thiamine-responsive basal ganglia disease."),
    makeMarker("Solute Carrier Family 38 Member 2 (SNAT2)", "SLC38A2", "Low", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "SLC38A2 variants affect amino acid transporter-mediated glutamine, alanine, and asparagine uptake in intestinal and hepatic cells, influencing protein assimilation efficiency. Informational; protein quality and quantity monitoring are recommended for animals with suboptimal protein utilization.", "Encodes SNAT2 (SLC38A2), a sodium-coupled neutral amino acid transporter (System A) mediating uptake of glutamine, alanine, and asparagine into cells."),
    makeMarker("Solute Carrier Family 39 Member 4 (ZIP4, Zinc Transporter)", "SLC39A4", "High", "Homo sapiens, Canis lupus familiaris, Sus scrofa, Mus musculus, Rattus norvegicus, Danio rerio", "SLC39A4 loss-of-function causes acrodermatitis enteropathica — severe zinc malabsorption with dermatitis, diarrhea, and alopecia. Annual serum zinc measurement and supplementation titration are required; oral zinc supplementation (zinc gluconate, zinc sulfate) reverses clinical signs when initiated promptly.", "Encodes ZIP4 (SLC39A4), the primary intestinal zinc importer. Deficiency causes acrodermatitis enteropathica, a severe zinc malabsorption syndrome."),
    makeMarker("Solute Carrier Family 3 Member 2 / SLC7A5 (LAT1 Heavy Chain)", "SLC3A2/SLC7A5", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "SLC3A2/SLC7A5 complex variants affect heterodimeric large neutral amino acid transporter assembly, influencing blood-brain barrier amino acid transport. Annual serum amino acid profile is recommended; relevant to managing LNAA supplementation strategies in aminoacidopathies and understanding amino acid competition at the blood-brain barrier.", "Encodes the heavy chain (SLC3A2/4F2hc) of the LAT1 heterodimer; partners with SLC7A5 (LAT1 light chain) to form the functional large neutral amino acid transporter at the blood-brain barrier."),
    makeMarker("Transient Receptor Potential Cation Channel Subfamily V Member 6 (TRPV6)", "TRPV6", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio, Gallus gallus", "TRPV6 variants affect the vitamin D-regulated apical calcium entry channel in intestinal epithelium, influencing active transcellular calcium absorption efficiency. Annual serum calcium, PTH, and bone density assessment are recommended; calcium supplementation requirements may be elevated in low-activity TRPV6 carriers, particularly during growth and pregnancy.", "Encodes TRPV6, the apical calcium entry channel in intestinal epithelial cells that mediates vitamin D-stimulated active calcium absorption."),
    makeMarker("Tocopherol Transfer Protein Alpha (TTPA)", "TTPA", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "TTPA loss-of-function variants cause familial isolated vitamin E deficiency — progressive spinocerebellar ataxia and peripheral neuropathy from impaired hepatic alpha-tocopherol retention. Annual serum vitamin E, neurological examination, and EMG/nerve conduction testing are recommended; high-dose vitamin E supplementation is the primary treatment.", "Encodes alpha-tocopherol transfer protein (TTPA), a liver protein that selectively retains alpha-tocopherol (vitamin E) for secretion into VLDL, maintaining systemic vitamin E levels."),
  ]},
  { id: "pharmacogenomics", name: "Pharmacogenomics", color: "#7E22CE", markers: [
    makeMarker("ATP Binding Cassette Subfamily B Member 1 (P-glycoprotein, MDR1)", "ABCB1", "High", "Homo sapiens, Canis lupus familiaris, Equus caballus, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "ABCB1 (MDR1) loss-of-function variants in Collies and related herding breeds cause ivermectin and multi-drug toxicity — potentially lethal CNS toxicity from drugs normally excluded from the brain by P-glycoprotein. MDR1 genotyping is mandatory before prescribing ivermectin, selamectin, loperamide, vincristine, doxorubicin, or acepromazine; dose reductions of 25–50% are required for MDR1-mutant carriers with most affected drugs.", "Encodes P-glycoprotein (MDR1), an ABC efflux transporter at the blood-brain barrier, intestinal epithelium, and liver that pumps drugs and toxins out of cells to limit accumulation."),
    makeMarker("Cytochrome P450 Family 1 Subfamily A (Generic)", "CYP1A", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "CYP1A family variants affect aromatic and polycyclic hydrocarbon metabolism, influencing toxin bioactivation and drug clearance across species. Dietary aromatic compound (charcoal-grilled foods, certain plant toxins) exposure management is advisable in low-activity carriers; CYP1A status informs dose selection for CYP1A-metabolized drugs (theophylline, enrofloxacin).", "Generic locus reference for the CYP1A subfamily; includes CYP1A1 (aromatic hydrocarbon hydroxylation) and CYP1A2 (drug metabolism). Major drug-metabolizing cytochrome P450 enzymes."),
    makeMarker("Cytochrome P450 Family 1 Subfamily A Member 2", "CYP1A2", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "CYP1A2 poor metabolizer variants cause elevated plasma concentrations of clomipramine, theophylline, caffeine, and enrofloxacin, risking dose-dependent toxicity. CYP1A2 genotyping is recommended before initiating therapy with CYP1A2-metabolized drugs in dogs; starting doses should be reduced by 30–50% in confirmed poor metabolizers.", "Encodes cytochrome P450 1A2, a major hepatic drug-metabolizing enzyme that oxidizes numerous drugs, dietary chemicals, and environmental toxins."),
    makeMarker("Cytochrome P450 Family 2 Subfamily D Member 15", "CYP2D15", "Medium", "Canis lupus familiaris, Felis catus, Homo sapiens, Mus musculus, Rattus norvegicus", "CYP2D15 poor metabolizer variants in dogs reduce hepatic metabolism of codeine, tramadol, metoprolol, and several other drugs, increasing toxicity risk. CYP2D15 genotyping is recommended before initiating therapy with CYP2D metabolized drugs; dose reductions are required in poor metabolizer carriers and drug-drug interaction risk is elevated.", "Encodes the canine CYP2D15 cytochrome P450, the primary canine ortholog of human CYP2D6 that metabolizes tramadol, codeine, and numerous other drugs."),
    makeMarker("N-Acetyltransferase 2", "NAT2", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "NAT2 slow acetylator variants cause delayed hepatic N-acetylation of sulfonamides, isoniazid, and hydralazine, increasing toxicity risk (drug-induced lupus, peripheral neuropathy). Pre-treatment NAT2 genotyping is advisable for sulfonamide and isoniazid regimens; dose reductions or treatment interval extensions are required for confirmed slow acetylators.", "Encodes N-acetyltransferase 2, a phase II drug-metabolizing enzyme that N-acetylates aromatic amines, hydrazines, and sulfonamides."),
    makeMarker("UDP Glucuronosyltransferase Family 1 Member A6", "UGT1A6", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Rattus norvegicus, Danio rerio", "UGT1A6 variants alter glucuronidation of aspirin, paracetamol (acetaminophen), and serotonin metabolites. Cats with severely limited UGT1A6 activity must never receive paracetamol or aspirin — feline UGT1A6 incapacity makes these drugs life-threateningly toxic; drug-specific dosing protocols must account for species UGT1A6 capacity.", "Encodes UDP-glucuronosyltransferase 1A6, a phase II conjugation enzyme that glucuronidates phenols, serotonin, and NSAIDs including aspirin and paracetamol."),
  ]},
  { id: "pigmentation", name: "Pigmentation", color: "#D946EF", markers: [
    makeMarker("Endothelin 3", "EDN3", "Medium", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "EDN3 loss-of-function variants cause Waardenburg syndrome type 4 (Waardenburg-Shah syndrome) — pigmentation defects (white forelock, heterochromia), congenital sensorineural deafness, and Hirschsprung disease from impaired neural crest melanocyte and enteric neuron migration. Ophthalmological, hearing, and gastrointestinal functional assessment are essential in affected individuals.", "Encodes endothelin-3, a signaling peptide critical for neural crest cell migration and differentiation into melanocytes and enteric neurons."),
    makeMarker("Endothelin Receptor Type B", "EDNRB", "Medium", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "EDNRB variants cause Waardenburg syndrome type 4B and lethal white foal syndrome in horses — pigmentation defects combined with Hirschsprung aganglionic megacolon. Audiological testing, enteric function assessment, and abdominal imaging are essential; breeding two EDNRB carrier horses must be avoided as 25% of offspring will be homozygous lethal white foals.", "Encodes endothelin receptor type B, required for neural crest cell migration and survival during formation of melanocytes and enteric nervous system ganglia."),
    makeMarker("Myosin VA", "MYO5A", "High", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "MYO5A loss-of-function causes Griscelli syndrome type 1 — silver-gray hypopigmentation combined with severe neurological dysfunction from impaired organelle transport in melanocytes and neurons. Annual neurological assessment, immunological evaluation, and ophthalmological examination are recommended; hematopoietic stem cell transplantation is indicated for the hemophagocytic lymphohistiocytosis form.", "Encodes myosin Va, an actin-based molecular motor essential for melanosome transport to dendritic tips in melanocytes and for organelle transport in neurons."),
    makeMarker("Syntaxin 17", "STX17", "Medium", "Canis lupus familiaris, Mus musculus, Homo sapiens, Rattus norvegicus, Danio rerio", "STX17 variants are responsible for the merle coat color pattern in dogs — characterized by irregular patches of diluted pigment — and are associated with auditory and ocular defects in homozygous merle individuals. Breeding merle-to-merle pairs must be avoided; offspring risk 25% double-merle homozygosity, which causes microphthalmia, blindness, and deafness. Annual hearing (BAER) and ophthalmological testing are recommended.", "Encodes syntaxin 17, a SNARE protein involved in autophagosome-lysosome fusion. A SINE insertion in the STX17 promoter causes the merle pigmentation pattern in dogs."),
    makeMarker("Melanocortin 1 Receptor", "MC1R", "Low", "Homo sapiens, Canis lupus familiaris, Felis catus, Equus caballus, Gallus gallus, Mus musculus, Danio rerio, Rattus norvegicus", "MC1R variants determine the eumelanin (black/brown) vs. phaeomelanin (yellow/red) pigmentation balance, with secondary associations between loss-of-function alleles and increased UV sensitivity and photocarcinogenesis risk. Annual skin examination for suspected UV-induced lesions is recommended in lightly pigmented MC1R loss-of-function carriers; sun protection is advisable.", "Encodes melanocortin-1 receptor, the primary genetic determinant of coat and skin color. Determines the ratio of eumelanin (black/brown) to phaeomelanin (yellow/red) production in melanocytes."),
    makeMarker("Agouti Signaling Protein", "ASIP", "Low", "Homo sapiens, Canis lupus familiaris, Felis catus, Equus caballus, Sus scrofa, Mus musculus, Danio rerio, Rattus norvegicus", "ASIP overexpression variants competitively antagonize MC1R, shifting melanin synthesis toward yellow/red phaeomelanin and contributing to yellow obesity in some rodent models. Annual body condition assessment is advisable in species where ASIP overexpression is linked to hyperphagia and metabolic dysregulation; primarily informational for coat color prediction in most domestic species.", "Encodes agouti signaling protein, an inverse agonist at MC1R and MC4R that shifts pigmentation toward phaeomelanin (yellow/red) and regulates energy balance."),
    makeMarker("KIT Proto-Oncogene, Receptor Tyrosine Kinase", "KIT", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "KIT variants cause white spotting phenotypes, deafness, and mast cell tumors depending on allele type. White-spotted and W locus carrier animals should have annual BAER hearing tests (cochlear melanocyte dependency) and annual skin and lymph node examinations for mast cell tumor development. KIT genotype guides targeted tyrosine kinase inhibitor (toceranib, masitinib) selection in mast cell tumor patients.", "Encodes the KIT receptor tyrosine kinase, expressed in melanoblasts, hematopoietic stem cells, and mast cells. The W (white spotting) locus in mice and many domestic species."),
    makeMarker("OCA2 Melanosomal Transmembrane Protein", "OCA2", "Medium", "Homo sapiens, Danio rerio, Mus musculus, Rattus norvegicus", "OCA2 loss-of-function variants cause oculocutaneous albinism type 2 — the most common form of albinism globally — with severely reduced melanin, photophobia, nystagmus, and reduced visual acuity from foveal hypoplasia. Annual ophthalmological examination, strict UV protection, and retinal assessment are recommended for affected individuals.", "Encodes OCA2, a melanosomal membrane protein essential for melanin synthesis. The major determinant of brown vs. blue eye color in humans; deficiency causes OCA type 2 albinism."),
  ]},
  { id: "renal", name: "Renal", color: "#0EA5E9", markers: [
    makeMarker("Collagen Type IV Alpha 5 Chain", "COL4A5", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "COL4A5 X-linked variants cause Alport syndrome — progressive glomerulonephritis from defective glomerular basement membrane type IV collagen, leading to renal failure, sensorineural hearing loss, and ocular abnormalities. Annual serum creatinine/SDMA, urinalysis for hematuria/proteinuria, BAER audiometry, and ophthalmological examination are essential; ACE inhibitor therapy should be initiated at first proteinuria detection.", "Encodes the alpha-5 chain of type IV collagen, a major component of the glomerular basement membrane. Mutations cause X-linked Alport syndrome."),
    makeMarker("Polycystin 1, Transient Receptor Potential Channel Interacting", "PKD1", "High", "Homo sapiens, Felis catus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "PKD1 variants cause the most common inherited kidney disease — autosomal dominant polycystic kidney disease (ADPKD) — with progressive cyst expansion and renal failure, hepatic cysts, and intracranial aneurysm risk. Annual renal ultrasound, blood pressure monitoring, and serum creatinine/SDMA are essential; blood pressure control slows cyst growth; carrier testing before breeding is strongly recommended in Persian cats.", "Encodes polycystin-1 (PC1), a large transmembrane protein that forms a complex with polycystin-2 in primary cilia, regulating tubular cell proliferation and differentiation."),
    makeMarker("Polycystin 2, Transient Receptor Potential Cation Channel", "PKD2", "High", "Homo sapiens, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "PKD2 variants cause autosomal dominant polycystic kidney disease type 2 — generally later onset and slower progression than PKD1 but still leading to renal failure. Annual renal ultrasound and blood pressure monitoring from middle age are recommended; PKD2 status informs genetic counseling regarding inheritance risk (50% per offspring) and age-of-onset expectations.", "Encodes polycystin-2 (PC2), a calcium-permeable TRP channel that heterodimerizes with polycystin-1 in primary cilia to regulate tubular cell signaling."),
    makeMarker("Solute Carrier Family 34 Member 1 (Sodium-Phosphate Cotransporter IIa)", "SLC34A1", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "SLC34A1 variants impair proximal tubular phosphate reabsorption, causing hypophosphatemia and nephrolithiasis. Annual serum phosphate, urinary phosphate fractional excretion, and renal ultrasound for nephrolithiasis are recommended; dietary phosphate restriction and neutral-phosphate supplementation are important management tools.", "Encodes NaPi-IIa, the primary proximal tubular sodium-phosphate cotransporter responsible for about 70% of renal phosphate reabsorption. Regulated by PTH and FGF23."),
  ]},
  { id: "reproduction", name: "Reproduction", color: "#DB2777", markers: [
    makeMarker("Androgen Receptor", "AR", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "AR variants cause androgen insensitivity syndrome (AIS) — XY individuals with testes and female external phenotype due to receptor loss-of-function, or male pattern baldness from high-sensitivity alleles. Annual reproductive and endocrine evaluation is recommended in ambiguous sex phenotype individuals; AR status informs testosterone and anabolic steroid responsiveness in performance animals.", "Encodes the androgen receptor, a nuclear receptor that mediates the biological effects of testosterone and DHT on male sexual differentiation, reproductive function, and anabolic processes."),
    makeMarker("Chromodomain Helicase DNA Binding Protein 1 (W/Z Chromosome)", "CHD1-W/Z", "Low", "Gallus gallus, Meleagris gallopavo, Coturnix japonica, Anas platyrhynchos, Homo sapiens, Mus musculus, Rattus norvegicus", "CHD1-W/Z sex-linked variants are used for genetic sex determination in birds (W-chromosome specific in females). Sex identification is essential for avian population management, reproductive pairing, and conservation programs where morphological sex determination is unreliable; CHD1 PCR-based sexing is the gold standard in avian practice.", "Encodes chromodomain helicase DNA binding protein 1; W-chromosome-specific copies (CHD1W) are used for genetic sex determination in birds, distinguishing females (ZW) from males (ZZ)."),
    makeMarker("Cytochrome P450 Family 19 Subfamily A Member 1 (Aromatase)", "CYP19A1", "Medium", "Homo sapiens, Equus caballus, Canis lupus familiaris, Bos taurus, Mus musculus, Danio rerio, Rattus norvegicus", "CYP19A1 variants alter estrogen biosynthesis from androgens in gonads, adipose, and brain, predisposing to infertility, osteopenia, and metabolic syndrome. Annual reproductive hormone panel (E2, testosterone, FSH, LH), bone density assessment, and metabolic screening are recommended; aromatase inhibitors may be indicated in estrogen-excess states.", "Encodes aromatase (CYP19A1), the enzyme that catalyzes the conversion of androgens (androstenedione, testosterone) to estrogens (estrone, estradiol). The rate-limiting step in estrogen biosynthesis."),
    makeMarker("Estrogen Receptor 1 (Nuclear)", "ESR1", "Medium", "Homo sapiens, Canis lupus familiaris, Equus caballus, Bos taurus, Mus musculus, Danio rerio, Rattus norvegicus", "ESR1 variants affect nuclear estrogen receptor alpha function, influencing bone mineral density, reproductive cyclicity, mammary development, and metabolic regulation. Annual reproductive health assessment, bone density evaluation, and mammary examination are recommended; ESR1 genotype informs estrogen therapy responsiveness in postmenopausal or ovariectomized individuals.", "Encodes estrogen receptor alpha (ERα), a nuclear receptor that mediates the genomic effects of estradiol on reproductive tissue, bone, cardiovascular system, and metabolism."),
    makeMarker("Estrogen Receptor 1 (ERα notation)", "ESR1(ERα)", "Medium", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Bos taurus, Danio rerio, Rattus norvegicus", "ESR1 (ERα) variants — same gene as ESR1 entry — influence estrogen-driven reproductive behaviors, gonadal hormone feedback, and bone homeostasis. Annual reproductive hormone assessment and bone density monitoring are recommended; this notation is commonly used in comparative endocrinology literature.", "Alternate notation for ESR1; emphasizes the ligand (ERα) rather than gene symbol context. Functionally identical to the ESR1 entry above."),
    makeMarker("Estrogen Receptor 2 (ERβ)", "ESR2", "Medium", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "ESR2 variants alter estrogen receptor beta signaling, influencing ovarian follicle development, uterine function, and gonadotropin feedback regulation. Annual reproductive cycle monitoring, ovarian ultrasound, and reproductive hormone panel are recommended; ESR2 variants are relevant to fertility management in breeding animals.", "Encodes estrogen receptor beta (ERβ), expressed in ovarian granulosa cells, lung, and nervous system, modulating granulosa cell differentiation and FSH responsiveness."),
    makeMarker("Prolactin", "PRL", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Bos taurus, Mus musculus, Danio rerio, Rattus norvegicus", "PRL variants affect prolactin production, influencing lactation quality, mammary gland development, maternal behavior, and immune modulation during gestation. Annual serum prolactin measurement and mammary gland assessment during lactation are recommended; hyperprolactinemia (pseudo-pregnancy in dogs) should be monitored and managed with dopamine agonists when clinically indicated.", "Encodes prolactin, a pituitary hormone essential for mammary gland development, initiation and maintenance of lactation, and maternal behavior."),
    makeMarker("Vitellogenin", "VTG", "Low", "Gallus gallus, Oncorhynchus mykiss, Danio rerio, Homo sapiens, Mus musculus, Rattus norvegicus", "VTG is produced only in egg-laying species and females under estrogen stimulation; its presence in male fish is a sentinel biomarker of estrogenic endocrine disruption. Informational in domestic mammals; in fish and avian species, VTG levels in plasma are used as a biomarker for environmental estrogen exposure monitoring.", "Encodes vitellogenin, a yolk precursor protein produced by liver in egg-laying species in response to estrogen; a key biomarker of estrogenic endocrine disruption in environmental monitoring."),
    makeMarker("Sex Determining Region Y", "SRY", "Low", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Bos taurus, Rattus norvegicus", "SRY variants or translocations to autosomes cause differences of sex development (DSD) — phenotypically female XY individuals (Swyer syndrome) or XX sex-reversed males. Genetic sex testing for SRY presence/absence is recommended in individuals with ambiguous external genitalia, infertility, or gonadal dysgenesis; tumor surveillance of dysgenetic gonads (gonadoblastoma risk) is essential.", "Encodes the sex-determining region Y protein (SRY), the testis-determining factor. Expression triggers Sertoli cell differentiation and male sexual development in XY embryos."),
    makeMarker("Doublesex And Mab-3 Related Transcription Factor 1", "DMRT1", "Medium", "Homo sapiens, Gallus gallus, Danio rerio, Caenorhabditis elegans, Drosophila melanogaster, Mus musculus, Rattus norvegicus", "DMRT1 variants affect Z-chromosome dosage-dependent sex determination in birds and testis maintenance in mammals. Monitor for gonadal dysgenesis, infertility, and germ cell tumor risk in individuals with DMRT1 haploinsufficiency; genetic sex verification and gonadal imaging are advisable.", "Encodes DMRT1, a transcription factor critical for gonadal sex determination in many vertebrates. In birds, DMRT1 Z-chromosome dosage determines sex; in mammals, it maintains testis identity."),
    makeMarker("VASA Helicase (Dead Box Polypeptide 4, DDX4)", "VASA", "Low", "Drosophila melanogaster, Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "VASA (DDX4) variants disrupt RNA helicase-dependent germ cell development and maintenance of primordial germ cell identity. Annual reproductive hormone panel and gonadal ultrasound are recommended in carrier animals presenting with fertility disorders; premature ovarian insufficiency and oligospermia are the primary clinical phenotypes.", "Encodes VASA (DDX4), an RNA helicase essential for germ cell development and maintenance in multiple species. A conserved marker of germline identity."),
    makeMarker("Stimulated By Retinoic Acid 8", "STRA8", "Low", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "STRA8 variants affect retinoic acid-driven initiation of meiosis in both male and female germ cells, with loss causing meiotic failure and infertility. Annual reproductive evaluation including semen analysis (males) and estrous cycle monitoring (females) are recommended; dietary vitamin A adequacy is important for maintaining meiotic initiation.", "Encodes STRA8, a retinoic acid-responsive transcription factor that initiates premeiotic DNA replication and is essential for the onset of meiosis in both sexes."),
  ]},
  { id: "sensory", name: "Sensory", color: "#0891B2", markers: [
    makeMarker("ADAM Metallopeptidase With Thrombospondin Type 1 Motif 10", "ADAMTS10", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "ADAMTS10 variants cause Weill-Marchesani syndrome — lens ectopia, microspherophakia, glaucoma, brachydactyly, and short stature from defective fibrillin microfibril matrix. Annual slit-lamp biomicroscopy, intraocular pressure measurement, and systemic skeletal assessment are essential; lens ectopia requires prompt ophthalmological intervention.", "Encodes ADAMTS10, a zinc metalloprotease involved in fibrillin-1 microfibril assembly in the lens zonule and extracellular matrix. Deficiency causes Weill-Marchesani syndrome."),
    makeMarker("Aryl Hydrocarbon Receptor Interacting Protein Like 1", "AIPL1", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "AIPL1 variants cause Leber congenital amaurosis type 4 — the most severe form, with complete blindness from birth due to photoreceptor loss. Annual ERG and ophthalmological assessment are recommended; this is a candidate for retinal gene therapy trials. Genetic carrier testing before breeding is mandatory in susceptible breeds.", "Encodes aryl hydrocarbon receptor interacting protein-like 1 (AIPL1), a chaperone essential for PDE6 phosphodiesterase stability in rod and cone photoreceptors."),
    makeMarker("Centrosomal Protein 290", "CEP290", "High", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "CEP290 variants cause multiple ciliopathies including Leber congenital amaurosis, Joubert syndrome, and Senior-Løken syndrome, with severity depending on allele type. Annual ERG, renal ultrasound (for nephronophthisis risk), and brain MRI are recommended in affected individuals; retinal gene therapy for CEP290-LCA is in clinical trials.", "Encodes centrosomal protein 290 (CEP290), a ciliary transition zone protein essential for photoreceptor cilia structure and function. Mutations cause various ciliopathies."),
    makeMarker("Cyclic Nucleotide Gated Channel Subunit Beta 3", "CNGB3", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "CNGB3 loss-of-function is the most common cause of complete achromatopsia in dogs and humans — rod monochromatism with severe photophobia, nystagmus, and absent color vision. Annual ERG and ophthalmological examination are essential; gene therapy (AAV-CNGB3) has shown restored cone function in canine models and is in human clinical trials.", "Encodes the beta-3 subunit of the cone photoreceptor cyclic nucleotide-gated channel, essential for cone phototransduction and the most commonly mutated gene in achromatopsia."),
    makeMarker("Cone-Rod Homeobox Transcription Factor", "CRX", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "CRX dominant or recessive variants cause Leber congenital amaurosis or cone-rod dystrophy — severe early-onset photoreceptor degeneration depending on allele type. Annual ERG and full ophthalmological assessment are essential; genetic carrier testing before breeding is strongly recommended in susceptible breeds.", "Encodes CRX, a paired-like homeodomain transcription factor that activates photoreceptor-specific gene expression. Essential for photoreceptor differentiation and maintenance."),
    makeMarker("Cryptochrome Circadian Regulator 4 (Light-Responsive)", "CRY4", "Low", "Gallus gallus, Sylvia borin (Garden Warbler), Mus musculus, Danio rerio, Rattus norvegicus", "CRY4 variants may affect the putative avian light-dependent magnetic compass mechanism in migratory birds. Informational; most relevant to research on magnetic navigation in migratory species and to managed population welfare under artificial lighting conditions.", "Encodes cryptochrome 4 (CRY4), a non-degradable flavoprotein proposed as the molecular basis for radical-pair magnetoreception in migratory birds' eyes."),
    makeMarker("Congenital Stationary Night Blindness (Locus)", "CSNB", "High", "Equus caballus, Canis lupus familiaris, Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "CSNB locus variants in Appaloosa horses (TRPM1) and other species cause stationary inability to see in low-light conditions without progressive degeneration. Annual ERG and veterinary ophthalmological assessment are recommended; affected horses must be managed with adequate lighting and should not be ridden in poorly lit environments. Genetic testing of Appaloosa breeding stock is strongly recommended.", "Locus reference for congenital stationary night blindness (CSNB); in Appaloosas caused by TRPM1 intronic insertion. Characterized by impaired rod signaling with stationary visual deficit."),
    makeMarker("Family With Sequence Similarity 174 Member A", "FAM174A", "Medium", "Canis lupus familiaris, Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "FAM174A variants are associated with inherited retinal degeneration in specific dog breeds. Annual ERG and ophthalmological assessment are recommended in affected breeds; genetic carrier testing assists breeding program selection to reduce prevalence of inherited retinal degeneration.", "Encodes a poorly characterized membrane protein; variants are associated with progressive retinal atrophy in dogs."),
    makeMarker("Guanine Nucleotide Binding Protein, Alpha Transducing 3 (Gustducin)", "GNAT3", "Low", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Danio rerio, Rattus norvegicus", "GNAT3 variants affect alpha-gustducin-mediated bitter and sweet taste transduction, influencing palatability assessment and dietary selectivity. Informational; relevant to understanding interindividual palatability differences and voluntary feed intake variation in managed animal populations.", "Encodes alpha-gustducin (GNAT3), a G protein alpha subunit expressed in taste receptor cells that couples taste receptors to downstream signaling for bitter and sweet taste transduction."),
    makeMarker("Olfactory Receptor Family 5 Subfamily A Member 1", "OR5A1", "Low", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus", "OR5A1 variants affect a specific olfactory receptor tuned to musks and certain steroid odorants, contributing to individual variation in olfactory acuity. Informational; relevant to breeding programs selecting for olfactory discrimination ability in tracking and detection dogs.", "Encodes OR5A1, an olfactory receptor expressed in olfactory sensory neurons that responds to musks and androstenone. One of approximately 1,000 olfactory receptor genes."),
    makeMarker("Progressive Rod-Cone Degeneration", "PRCD", "High", "Canis lupus familiaris, Felis catus, Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "PRCD loss-of-function is a major cause of progressive retinal atrophy (PRA) in over 20 dog breeds and cats — progressive rod then cone degeneration leading to complete blindness. Annual ERG and ophthalmological examination are recommended from 3 years of age; genetic carrier testing of breeding stock is mandatory for affected breeds (Poodle, Cocker Spaniel, Labrador Retriever).", "Encodes PRCD, a small photoreceptor disc protein essential for rod outer segment disc morphogenesis and maintenance. Deficiency causes progressive rod-cone degeneration (PRA in dogs)."),
    makeMarker("Retinal Pigment Epithelium 65 (RPE65)", "RPE65", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "RPE65 loss-of-function causes Leber congenital amaurosis type 2 — severe childhood-onset vision loss from vitamin A cycle blockade in the RPE. Annual ERG and vitamin A supplementation are recommended; voretigene neparvovec (AAV2-RPE65) gene therapy is FDA-approved for humans and was originally developed in Briard dogs with natural RPE65 mutations.", "Encodes RPE65, the retinal pigment epithelium-specific isomerohydrolase that catalyzes the rate-limiting step in the visual cycle, regenerating the 11-cis-retinal chromophore."),
    makeMarker("Short Wave Sensitive Opsin 1 (Blue/UV Cone Opsin)", "SWS1", "Low", "Gallus gallus, Mus musculus, Danio rerio, Homo sapiens, Rattus norvegicus", "SWS1 variants alter short-wavelength (blue or UV) cone photoreceptor spectral tuning, influencing color vision range and UV sensitivity. Informational in most managed species; relevant to understanding visual ecology, behavioral phototaxis, and UV-based communication in birds and fish.", "Encodes short-wave-sensitive opsin 1, the photopigment of UV/violet cone photoreceptors. In birds and many non-mammalian vertebrates, SWS1 can be tuned to UV rather than blue wavelengths."),
    makeMarker("Transient Receptor Potential Cation Channel Subfamily M Member 1 (TRPM1/Nyctalopin)", "TRPM1", "High", "Equus caballus, Canis lupus familiaris, Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "TRPM1 intronic SINE insertion is the cause of leopard complex spotting and CSNB in Appaloosa horses; biallelic TRPM1 variants cause congenital stationary night blindness. Annual BAER or ERG assessment and ophthalmological examination are recommended; homozygous LP (leopard complex) horses are night-blind and must not be ridden in low-light conditions.", "Encodes TRPM1, a TRP channel expressed in retinal ON-bipolar cells and melanocytes. Intronic insertion in Appaloosa horses disrupts expression in bipolar cells causing CSNB."),
    makeMarker("Long Wave Opsin 1 (Red-Sensitive Cone Opsin)", "OPSIN1LW", "Low", "Homo sapiens, Macaca mulatta, Gallus gallus, Mus musculus, Danio rerio, Rattus norvegicus", "OPSIN1LW variants alter long-wavelength cone photopigment spectral sensitivity, causing red-green color vision deficiency. Informational; relevant to training protocols in hunting and working dogs where red/green discrimination tasks are designed; most affected species navigate effectively with trichromacy or dichromacy.", "Encodes long-wave sensitive opsin 1 (OPN1LW/L-opsin), the red-sensitive cone photopigment. Variants cause red-green color blindness (deuteranomaly/protanomaly)."),
    makeMarker("Cryptochrome Circadian Regulator 1", "CRY1", "Low", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus, Xenopus tropicalis, Xenopus laevis, Drosophila melanogaster, Caenorhabditis elegans", "CRY1 variants are associated with delayed sleep phase disorder from a lengthened circadian period. Monitor for circadian rhythm misalignment and sleep disturbances; informational for managing captive animal welfare in controlled lighting environments.", "Encodes cryptochrome-1, a core negative feedback component of the circadian clock that inhibits CLOCK/BMAL1-mediated transcription. Also involved in light-dependent magnetic sensing."),
    makeMarker("Transient Receptor Potential Cation Channel Subfamily V Member 1 (Capsaicin Receptor)", "TRPV1", "Medium", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Rattus norvegicus, Danio rerio", "TRPV1 variants affect thermosensory and pain perception thresholds via the capsaicin receptor, influencing nociceptive response intensity and heat pain sensitivity. Annual pain sensitivity assessment is advisable; TRPV1 genotype informs selection of TRPV1 antagonist analgesics for neuropathic and inflammatory pain management.", "Encodes TRPV1, the heat and capsaicin-sensitive cation channel in pain-sensing nociceptors and thermosensory neurons. The molecular transducer of burning heat and chemical pain."),
    makeMarker("Prestin (SLC26A5, Outer Hair Cell Motor Protein)", "PRESTIN", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio, Gallus gallus", "PRESTIN variants impair outer hair cell electromotility and cochlear amplification, reducing high-frequency hearing sensitivity. Annual BAER audiometry is recommended in affected breeds; hearing threshold shifts in high-frequency ranges are the expected primary phenotype.", "Encodes prestin (SLC26A5), the outer hair cell motor protein responsible for electromotility that amplifies sound in the mammalian cochlea. Essential for high-frequency hearing sensitivity."),
    makeMarker("Glucocorticoid Receptor / Taste 2 Receptor (Bitter Taste)", "GR/TAS2R", "Low", "Homo sapiens, Canis lupus familiaris, Felis catus, Mus musculus, Rattus norvegicus, Danio rerio", "TAS2R (bitter taste receptor) variants alter bitter compound aversion thresholds, influencing voluntary consumption of bitter-tasting compounds including some medications. Informational; relevant to compliance with oral medication palatability, bitter compound aversion in feed refusal, and dietary selectivity in managed animals.", "Combined locus notation for bitter taste receptor (TAS2R) gene family members and co-located glucocorticoid receptor reference; TAS2R variants determine bitterness perception thresholds."),
  ]},
  { id: "stress", name: "Stress Response", color: "#B45309", markers: [
    makeMarker("Arginine Vasopressin Receptor 1B", "AVPR1B", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "AVPR1B variants affect pituitary vasopressin V1b receptor signaling in the HPA axis, influencing ACTH secretion amplitude in response to acute and chronic stressors. Annual cortisol assessment and behavioral stress reactivity evaluation are recommended; relevant to managing anxiety-related and stress-induced pathologies.", "Encodes the vasopressin V1b receptor in the anterior pituitary, stimulating ACTH release during stress to amplify the glucocorticoid stress response."),
    makeMarker("Corticotropin Releasing Hormone", "CRH", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "CRH high-expression variants potentiate HPA axis reactivity, predisposing to heightened chronic stress responses, anxiety disorders, and stress-induced gastrointestinal dysfunction. Annual cortisol profile, behavioral temperament, and gastrointestinal health assessment are recommended; environmental stress reduction protocols are important for high-CRH carrier individuals.", "Encodes corticotropin-releasing hormone (CRH), the primary hypothalamic neuropeptide triggering the stress response by stimulating pituitary ACTH and adrenal cortisol secretion."),
    makeMarker("Corticotropin Releasing Hormone Receptor 1", "CRHR1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "CRHR1 variants alter CRH receptor 1 sensitivity in the pituitary and limbic system, modifying HPA axis gain and anxiety vulnerability. Annual cortisol profiling and behavioral stress assessment are recommended; CRHR1 antagonist compounds are in development for anxiety and depression pharmacotherapy.", "Encodes CRH receptor type 1 (CRHR1), expressed in the anterior pituitary and brain, mediating CRH-stimulated ACTH release and central anxiety responses."),
    makeMarker("Corticotropin Releasing Hormone Receptor 2", "CRHR2", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "CRHR2 variants alter urocortin-mediated stress recovery signaling in limbic circuits, affecting anxiety resilience and stress response termination. Annual behavioral temperament and cortisol recovery assessment are recommended; CRHR2-specific agonists may support stress resilience in affected animals.", "Encodes CRH receptor type 2 (CRHR2), expressed in brain regions mediating stress recovery, appetite, and cardiovascular regulation. Preferentially binds urocortins."),
    makeMarker("Dual Specificity Phosphatase 1 (MKP-1)", "DUSP1", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "DUSP1 variants alter glucocorticoid-induced MAPK stress signaling deactivation, influencing inflammatory resolution efficiency and stress response duration. Annual inflammatory marker assessment and cortisol profiling are recommended; DUSP1 variants may modulate glucocorticoid responsiveness and anti-inflammatory treatment efficacy.", "Encodes DUSP1/MKP-1, a dual-specificity phosphatase induced by glucocorticoids that deactivates stress-activated MAPKs (p38, JNK), providing negative feedback to inflammatory and stress signaling."),
    makeMarker("FKBP Prolyl Isomerase 5 (FKBP51)", "FKBP5", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "FKBP5 high-expression variants reduce glucocorticoid receptor (GR) sensitivity through co-chaperone interference, prolonging HPA axis stress reactivity and predisposing to PTSD and depression. Annual behavioral temperament assessment and cortisol profiling are recommended; early life stress history substantially amplifies FKBP5 risk in genetically susceptible individuals.", "Encodes FKBP51, a glucocorticoid receptor co-chaperone that reduces GR sensitivity and prolongs HPA axis activation. A key mediator of stress-related psychiatric vulnerability."),
    makeMarker("Glutathione Peroxidase (Generic)", "GPX", "Low", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "GPX family variants reduce oxidative stress protection through impaired hydrogen peroxide detoxification. Annual oxidative stress biomarkers and antioxidant enzyme status assessment are advisable; dietary antioxidant supplementation (vitamin E, selenium) is recommended to support GPX enzyme activity in selenium-cofactor-dependent family members.", "Generic locus reference for the glutathione peroxidase family; GPX enzymes reduce hydrogen peroxide and lipid hydroperoxides using glutathione, protecting cells from oxidative damage."),
    makeMarker("Glutathione Peroxidase 1", "GPX1", "Low", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "GPX1 variants reduce cytosolic hydrogen peroxide detoxification capacity, predisposing to elevated oxidative damage in erythrocytes and other tissues. Annual CBC with Heinz body assessment and serum selenium monitoring are recommended; selenium-adequate diet is essential for optimal GPX1 selenoprotein function.", "Encodes glutathione peroxidase 1 (GPX1), the most abundant cytosolic selenoprotein that reduces hydrogen peroxide and lipid hydroperoxides, protecting against oxidative stress."),
    makeMarker("Heat Shock Protein 70", "HSP70", "Low", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "HSP70 variants affect molecular chaperone-mediated protein refolding capacity under thermal and oxidative stress, influencing heat tolerance and recovery from hyperthermia. Informational; heat management protocols and graded exercise exposure are advisable in breeds working in hot environments; relevant to exertional heatstroke risk assessment.", "Encodes HSP70, the major inducible heat shock chaperone that prevents protein aggregation, assists protein folding, and mediates stress tolerance across tissues."),
    makeMarker("Heat Shock Protein 90", "HSP90", "Low", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio, Saccharomyces cerevisiae", "HSP90 variants affect client protein (steroid receptors, kinases) chaperone activity, influencing buffering of genetic variation and stress resilience. Informational; HSP90 activity links genotype to phenotypic expression under stress conditions — animals in stressful environments may show greater phenotypic variance at HSP90-sensitive loci.", "Encodes HSP90, a chaperone that maintains the stability and function of client proteins including steroid hormone receptors, protein kinases, and transcription factors."),
    makeMarker("Heat Shock Protein Family B (Small) Member 1 (HSP27)", "HSPB1", "Low", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "HSPB1 variants cause Charcot-Marie-Tooth disease type 2 (axonal CMT) and distal hereditary motor neuropathy — progressive peripheral motor and sensory axonal neuropathy. Annual neurological examination, gait assessment, and EMG/nerve conduction studies are recommended in carrier individuals; physiotherapy and supportive management are the primary interventions.", "Encodes HSP27 (HSPB1), a small heat shock protein that stabilizes actin cytoskeleton, inhibits apoptosis, and is expressed in neurons. Mutations cause peripheral neuropathies."),
    makeMarker("Nuclear Receptor Subfamily 3 Group C Member 1 (Glucocorticoid Receptor)", "NR3C1 (GR)", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "NR3C1 variants alter glucocorticoid receptor sensitivity, producing either glucocorticoid resistance (with compensatory hypercortisolism and hypertension) or relative hypersensitivity. Annual cortisol profile, blood pressure, and ACTH stimulation testing are recommended; GR genotype directly informs glucocorticoid therapy dosing and HPA feedback sensitivity.", "Encodes the glucocorticoid receptor (GR/NR3C1), a nuclear receptor mediating the genomic and non-genomic effects of cortisol on metabolism, inflammation, and stress responses."),
    makeMarker("Superoxide Dismutase (Generic)", "SOD", "Low", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "SOD family variants impair superoxide radical dismutation, increasing oxidative damage burden across tissues. Informational; antioxidant-rich diet, controlled exercise, and regular oxidative stress biomarker monitoring are advisable for SOD low-activity carriers, particularly in aging individuals.", "Generic locus reference for superoxide dismutase family; SOD enzymes catalyze the dismutation of superoxide radicals to hydrogen peroxide and oxygen, providing primary antioxidant defense."),
    makeMarker("Superoxide Dismutase 1 (Cu/Zn-SOD)", "SOD1", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "SOD1 gain-of-toxic-function mutations cause familial ALS — progressive upper and lower motor neuron degeneration leading to paralysis and respiratory failure. Annual neurological examination including gait analysis and electromyography are recommended; genetic carrier testing before breeding is strongly recommended in susceptible dog breeds (Pembroke Welsh Corgi degenerative myelopathy).", "Encodes copper/zinc superoxide dismutase (SOD1), the cytosolic antioxidant enzyme that dismutates superoxide to hydrogen peroxide. Gain-of-function mutations cause familial ALS."),
    makeMarker("Superoxide Dismutase 2 (Mn-SOD)", "SOD2", "Medium", "Homo sapiens, Canis lupus familiaris, Mus musculus, Rattus norvegicus, Danio rerio", "SOD2 variants impair mitochondrial superoxide scavenging capacity, predisposing to mitochondrial oxidative damage, premature aging, and cancer susceptibility. Annual oxidative stress biomarker and organ function assessment are recommended; dietary antioxidant (CoQ10, vitamin E) supplementation may provide partial mitochondrial support.", "Encodes manganese superoxide dismutase (SOD2), the mitochondrial matrix antioxidant enzyme protecting against mitochondrial superoxide generated by the electron transport chain."),
    makeMarker("Thioredoxin Reductase 1", "TXNRD1", "Low", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "TXNRD1 selenoprotein variants reduce thioredoxin-dependent antioxidant recycling capacity and ribonucleotide reductase function, impairing cellular redox balance. Annual serum selenium monitoring and dietary selenium adequacy assessment are recommended; selenium-adequate diet is essential for optimal selenoprotein TXNRD1 function.", "Encodes thioredoxin reductase 1 (TXNRD1), a cytosolic selenoprotein that reduces thioredoxin using NADPH, maintaining the cellular thioredoxin antioxidant system."),
  ]},
  { id: "structural", name: "Structural / Body Form", color: "#6B7280", markers: [
    makeMarker("Collagen Type XI Alpha 2 Chain", "COL11A2", "High", "Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "COL11A2 variants cause Stickler syndrome type 3 — non-ocular Stickler syndrome with spondyloepiphyseal dysplasia, hearing loss, and craniofacial abnormalities. Annual audiometry (BAER), spinal radiography, and joint mobility assessment are recommended; COL11A2 haploinsufficiency also contributes to otospondylomegaepiphyseal dysplasia.", "Encodes the alpha-2 chain of type XI collagen, a fibrillar collagen important for cartilage matrix structure and regulation of type II collagen fibril diameter in cartilage and vitreous humor."),
    makeMarker("Collagen Type V Alpha 1 Chain", "COL5A1", "High", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "COL5A1 variants cause Ehlers-Danlos syndrome classical type — skin hyperextensibility, joint hypermobility, and susceptibility to tissue fragility and wound dehiscence. Annual joint stability and skin integrity assessment are recommended; low-impact exercise and trauma prevention are essential management strategies.", "Encodes the alpha-1 chain of type V collagen, a fibrillar collagen that regulates type I collagen fibril assembly in skin, tendons, and cornea."),
    makeMarker("Doublesex And Mab-3 Related Transcription Factor 3", "DMRT3", "Medium", "Equus caballus, Mus musculus, Homo sapiens, Danio rerio, Rattus norvegicus", "DMRT3 variants have major effects on equine gaited locomotion — the stop codon variant creates the pacing/ambling gait phenotype by modifying spinal interneuron circuit development. Gait phenotyping and locomotion assessment are recommended; DMRT3 genotyping predicts gaited ability in horses bred for harness or pleasure gaited disciplines.", "Encodes DMRT3, a transcription factor expressed in spinal interneurons during development. A DMRT3 stop codon variant modifies spinal interneuron circuitry enabling the pacing/ambling gait in horses."),
    makeMarker("Fibroblast Growth Factor 4 (FGF4 Retrogene)", "FGF4", "Low", "Canis lupus familiaris, Homo sapiens, Mus musculus, Danio rerio, Rattus norvegicus", "FGF4 retrogene insertion causes chondrodysplastic short-limb dwarfism (chondrodystrophy) in many dog breeds and is associated with intervertebral disc disease (IVDD) risk. Annual spinal assessment including neurological examination and X-ray/MRI of the thoracolumbar spine are recommended in chondrodystrophic breeds; minimizing jumping and spinal impact reduces IVDD risk.", "An FGF4 retrogene insertion on chromosome 18 in dogs causes chondrodysplasia (short-legged phenotype). Present in many small dog breeds (Dachshund, Corgi, Basset) and strongly associated with IVDD."),
    makeMarker("High Mobility Group AT-Hook 2", "HMGA2", "Low", "Homo sapiens, Canis lupus familiaris, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "HMGA2 variants are among the strongest determinants of body size variation in dogs and other species, influencing bone growth plate activity and final adult size. Informational for size prediction in developing animals; relevant to body condition monitoring and nutritional management for target adult size.", "Encodes HMGA2, an architectural transcription factor that modulates chromatin structure during development. Variants in this region are among the strongest effects on body size across dog breeds."),
    makeMarker("Ligand Dependent Nuclear Receptor Corepressor Like", "LCORL", "Low", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "LCORL variants near the LCORL/NCAPG locus are strongly associated with body size and stature in horses, cattle, and dogs. Informational for adult size prediction; relevant to nutritional management, weight-bearing exercise intensity planning, and breed standard assessment.", "LCORL/NCAPG locus variants are among the strongest GWAS signals for body size in multiple livestock and companion animal species, but functional mechanism remains under investigation."),
    makeMarker("Lamin A/C", "LMNA", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "LMNA variants cause a spectrum of laminopathies including dilated cardiomyopathy with conduction disease, Emery-Dreifuss muscular dystrophy, limb-girdle muscular dystrophy, and Hutchinson-Gilford progeria. Annual echocardiography, ECG with Holter monitoring, and serum CK assessment are recommended; implantable cardioverter-defibrillator placement is indicated early in LMNA cardiomyopathy carriers.", "Encodes lamins A and C, structural components of the nuclear lamina that maintain nuclear integrity, regulate gene expression, and anchor chromatin."),
    makeMarker("Methionine Sulfoxide Reductase B3", "MSRB3", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "MSRB3 variants cause sensorineural hearing loss (DFNB74) by impairing methionine sulfoxide repair in cochlear hair cells. Annual BAER audiometry is recommended; genetic carrier testing before breeding is strongly advised in susceptible dog breeds; early hearing loss detection enables welfare management and training adaptation.", "Encodes methionine sulfoxide reductase B3 (MSRB3), an enzyme that repairs oxidized methionine residues in proteins. Deficiency causes progressive hearing loss in dogs and humans."),
    makeMarker("Non-SMC Condensin I Complex Subunit G", "NCAPG", "Low", "Homo sapiens, Equus caballus, Bos taurus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "NCAPG locus variants are among the strongest genetic determinants of body size and prenatal growth rate in horses and cattle — see also LCORL. Informational for size prediction in livestock; birth weight and early growth rate monitoring are advisable, as this locus is also associated with dystocia risk in extreme-size allele combinations.", "Encodes a condensin complex subunit involved in chromosome condensation; variants near NCAPG/LCORL are strong QTLs for body size in horses, cattle, and dogs."),
    makeMarker("Procollagen-Lysine 2-Oxoglutarate 5-Dioxygenase 1", "PLOD1", "High", "Homo sapiens, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "PLOD1 loss-of-function causes kyphoscoliotic Ehlers-Danlos syndrome (kEDS) — neonatal hypotonia, progressive kyphoscoliosis, joint hypermobility, and fragile friable skin. Annual spinal radiography, joint mobility and skin integrity assessment are recommended; physical therapy and protective measures are the primary management; high-dose lysine and vitamin C supplementation may provide partial support.", "Encodes lysyl hydroxylase 1 (PLOD1), the enzyme that hydroxylates lysine residues in collagen for cross-link formation. Deficiency causes kyphoscoliotic EDS."),
    makeMarker("Peptidylprolyl Isomerase B (Cyclophilin B)", "PPIB", "High", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "PPIB variants impair prolyl cis-trans isomerase-assisted collagen folding in the ER, causing osteogenesis imperfecta type IX — severe bone fragility, blue sclerae, and progressive deformity. Annual bone radiography and density assessment are recommended; bisphosphonate therapy and protective management are essential; genetic carrier testing is strongly advised before breeding.", "Encodes cyclophilin B (CypB/PPIB), a peptidyl-prolyl isomerase in the endoplasmic reticulum that assists collagen folding and participates in the collagen-modifying complex."),
    makeMarker("Collagen Type I Alpha 1 Chain", "COL1A1", "High", "Homo sapiens, Equus caballus, Canis lupus familiaris, Mus musculus, Danio rerio, Rattus norvegicus", "COL1A1 variants cause osteogenesis imperfecta (brittle bone disease) — recurrent fractures at minimal trauma, blue sclerae, dentinogenesis imperfecta, and short stature depending on severity. Annual bone radiography, density assessment, and fracture monitoring are essential; bisphosphonate therapy reduces fracture risk; COL1A1 genotype predicts disease severity and response to treatment.", "Encodes the alpha-1 chain of type I collagen, the most abundant structural protein in bone, skin, tendon, and ligament. Dominant mutations cause osteogenesis imperfecta."),
    makeMarker("Paired Like Homeodomain 1", "PITX1", "Medium", "Homo sapiens, Mus musculus, Rattus norvegicus, Danio rerio", "PITX1 variants affect hindlimb-specific developmental patterning transcription factor activity, causing tibial hemimelia and other lower limb structural asymmetries. Radiographic assessment of hindlimb skeletal development is recommended in offspring of carrier parents; relevant to genetic screening in breeds with known hindlimb morphological phenotypes.", "Encodes paired-like homeodomain 1 (PITX1), a transcription factor that specifies hindlimb identity and controls hindlimb-specific gene expression during development."),
    makeMarker("RUNX Family Transcription Factor 2", "RUNX2", "Medium", "Homo sapiens, Canis lupus familiaris, Equus caballus, Mus musculus, Danio rerio, Rattus norvegicus", "RUNX2 variants cause cleidocranial dysplasia — hypoplastic clavicles, delayed fontanelle closure, supernumerary teeth, and short stature from impaired osteoblast differentiation. Annual dental radiography, skeletal survey, and growth assessment are recommended; dental management to prevent impaction of supernumerary teeth is important. RUNX2 sequence variation also correlates with breed-specific skull morphology in dogs.", "Encodes RUNX2, the master transcription factor driving osteoblast differentiation and bone formation. Haploinsufficiency causes cleidocranial dysplasia; copy number variation correlates with skull morphology."),
  ]},
];
